def _load_engine_options(path: str) -> dict:
    opts: dict = {}
    if not os.path.isfile(path):
        return opts
    try:
        with open(path, encoding="utf-8") as f:
            for raw in f:
                line = raw.strip()
                if not line or line.startswith("#"):
                    continue
                m = re.match(
                    r"option\s+name\s+(\S+)\s+type\s+\S+\s+default\s+(.*)",
                    line, re.IGNORECASE,
                )
                if m:
                    opts[m.group(1)] = m.group(2).strip()
    except Exception as _ie:
        _flog(f"[ignored] _load_engine_options: {_ie!r}")
    return opts

_engine_extra_opts: dict = _load_engine_options(_ENGINE_OPTIONS_PATH)

