def _dlponder_ema(prev, x, alpha=0.2):
    if x is None:
        return prev
    return float(x) if prev is None else (1.0 - alpha) * float(prev) + alpha * float(x)


def _dlponder_gain_core(nps_ema, opponent_s_ema, policy_nodes):
    if not nps_ema or not opponent_s_ema or not policy_nodes or policy_nodes <= 0:
        return None
    return (float(nps_ema) * float(opponent_s_ema)) / float(policy_nodes)


def _dlponder_forward_gate_core(opponent_s_ema, min_opp_s):
    if min_opp_s is None or float(min_opp_s) <= 0:
        return True
    if opponent_s_ema is None:
        return True
    return float(opponent_s_ema) >= float(min_opp_s)


def _dlponder_decide_core(gain, gain_min, samples, min_samples, prev_mode="prefetch"):
    if gain is None or samples < min_samples:
        return "ponder"
    if prev_mode == "ponder":
        return "ponder" if gain >= gain_min * 0.7 else "prefetch"
    return "ponder" if gain >= gain_min else "prefetch"


