def _dlponder_load_state(path=None):
    try:
        with open(path or _DLPONDER_STATE_PATH, encoding="utf-8") as f:
            d = json.load(f)
        for k in ("nps_ema", "opponent_s_ema", "samples", "mode",
                  "dlp_dispatched", "dlp_hits", "dlp_misses",
                  "mp_alt_dispatched", "mp_alt_hits",
                  "mpon_dispatched", "mpon_mate", "mpon_nomate_proof",
                  "mpon_hits", "mpon_misses"):
            if k in d:
                _DLPONDER_STATE[k] = d[k]
    except Exception as _ie:
        _flog(f"[ignored] _dlponder_load_state: {_ie!r}")


def _dlponder_save_state(path=None):
    try:
        _path = path or _DLPONDER_STATE_PATH
        _tmp = _path + ".tmp"
        with open(_tmp, "w", encoding="utf-8") as f:
            json.dump({k: _DLPONDER_STATE.get(k) for k in
                       ("nps_ema", "opponent_s_ema", "samples", "mode",
                        "dlp_dispatched", "dlp_hits", "dlp_misses",
                        "mp_alt_dispatched", "mp_alt_hits",
                        "mpon_dispatched", "mpon_mate", "mpon_nomate_proof",
                        "mpon_hits", "mpon_misses")}, f)
        os.replace(_tmp, _path)
    except Exception as _de:
        _flog(f"[ignored] _dlponder_save_state: {_de!r}")


def _prereq_dlponder_done() -> bool:
    if not os.path.exists(_DLPONDER_STATE_PATH):
        return False
    try:
        with open(_DLPONDER_STATE_PATH, encoding="utf-8") as _f:
            _st = json.load(_f)
        _nps = _st.get("nps_ema")
        return isinstance(_nps, (int, float)) and _nps > 0
    except Exception:
        return False


def _prereq_setup_done() -> bool:
    return os.path.exists(_SETUP_CONFIG_PATH)


def _args_has_skip(args) -> bool:
    return any(str(a).strip().lower() == "skip" for a in (args or []))


def _strip_skip(args):
    return [a for a in (args or []) if str(a).strip().lower() != "skip"]


def _ensure_prereqs(command: str, args) -> bool:
    for _bat_p in {nnue_1_PATH, nnue_2_PATH}:
        try:
            if not (_bat_p and os.path.splitext(_bat_p)[1].lower()
                    in (".bat", ".cmd") and os.path.isfile(_bat_p)):
                continue
            _bat_src = open(_bat_p, "r", encoding="utf-8",
                            errors="replace").read()
            if "wsl" in _bat_src.lower() and "%*" not in _bat_src:
                _msg = (f"{command}: engine.bat が %* を転送していません — "
                        f"WSL nnue の reap が構造的に不能で、調整系の restart の"
                        f"たびに Linux 側 nnue が leak します。次の .bat の wsl 行"
                        f"末尾に `%*` を追加してから再実行してください: {_bat_p}")
                _flog("[PREREQ][BAT-GATE] " + _msg)
                print("info string [setup] " + _msg, flush=True)
                if command != "game":
                    return False
        except Exception as _bge:
            _flog(f"[PREREQ][BAT-GATE] check failed (ignored): {_bge!r}")

    if _args_has_skip(args):
        _flog(f"[PREREQ] '{command} skip' — DLP/Setup 前提工程をスキップ")
        print(f"info string [setup] {command}: skip 指定のため前提工程 (DLP/Setup) を省略します",
              flush=True)
        return True

    try:
        if not _prereq_dlponder_done():
            _flog(f"[PREREQ] {command}: dlp_state.txt 不在 — DLP 較正を先に実行")
            print(f"info string [setup] {command}: DLP 未較正 — 較正を先に実行します",
                  flush=True)
            _dlponder_cli([])
            if not _prereq_dlponder_done():
                _flog("[PREREQ] DLP 較正後も dlp_state.txt が生成されていない — 中断")
                print("info string [setup] DLP 較正に失敗しました (dlp_state.txt が生成されていません)", flush=True)
                return False
        else:
            _flog(f"[PREREQ] {command}: DLP 済 (dlp_state.txt あり) — スキップ")

        if not _prereq_setup_done():
            _flog(f"[PREREQ] {command}: setup_config.txt 不在 — Setup を先に実行")
            print(f"info string [setup] {command}: セットアップ未実施 — 環境依存キーの調整を先に実行します",
                  flush=True)
            _spsa_cli(setup_mode=True)
            if not _prereq_setup_done():
                _flog("[PREREQ] Setup 後も setup_config.txt が生成されていない — 中断")
                print("info string [setup] セットアップに失敗しました (setup_config.txt が生成されていません)", flush=True)
                return False
        else:
            _flog(f"[PREREQ] {command}: Setup 済 (setup_config.txt あり) — スキップ")
    except Exception as _pe:
        _flog(f"[PREREQ] {command}: 前提工程で例外 — 中断: {_pe!r}")
        print(f"info string [setup] 前提工程で例外が発生しました: {_pe}", flush=True)
        return False

    return True


_dlponder_mode_cfg = str(_cfg.get("DL_Ponder_Mode", "auto")).strip().lower()
