def _build_nnue_opts(slot_prefix, cfg, fv_scale, extra_engine_opts,
                     *, hash_override=None, threads_override=None,
                     sp_default="false", resign_default=99999,
                     ponder_active=True):
    base = {
        "USI_Hash":            hash_override or str(cfg[f"{slot_prefix}_Hash"]),
        "Threads":             threads_override or str(cfg[f"{slot_prefix}_Threads"]),
        "MultiPV":             "1",
        "DrawValueBlack":      str(cfg[f"{slot_prefix}_DrawValueBlack"]),
        "DrawValueWhite":      str(cfg[f"{slot_prefix}_DrawValueWhite"]),
        **_NNUE_BOOK_OPTS,
        "FV_Scale":            fv_scale,
        "MinimumThinkingTime": str(cfg[f"{slot_prefix}_MinimumThinkingTime"]),
        "SlowMover":           str(cfg[f"{slot_prefix}_SlowMover"]),
        "USI_Ponder":          "true" if ponder_active else "false",
        "Stochastic_Ponder":   sp_default,
        "ResignValue":         str(cfg.get(f"{slot_prefix}_ResignValue", resign_default)),
        "EnteringKingRule":    str(cfg.get(f"{slot_prefix}_EnteringKingRule",
                                            cfg.get("EnteringKingRule", "CSA27"))),
    }
    reserved = frozenset(base)
    for ek, ev in extra_engine_opts.items():
        if ek not in reserved:
            base[ek] = ev
    return base


