def _resolve_ta(key: str, base: float) -> float:
    v = float(_cfg.get(key, -1.0))
    return base if v < 0.0 else max(0.0, min(_TA_CEIL, v))


def _time_aggression_dyn_ratio(dyn, base, lo=0.25, hi=1.5):
    if base <= 1e-6:
        return 1.0
    return max(lo, min(hi, dyn / base))

