_SBK_BOOK_CACHE: dict = {}

_SBK_PIECE_TYPE_TO_USI_CHAR = {
    1: "P", 2: "L", 3: "N", 4: "S", 5: "G", 6: "B", 7: "R", 8: "K",
}


def _sbk_read_varint(buf: bytes, pos: int):
    result = 0
    shift = 0
    while True:
        b = buf[pos]
        result |= (b & 0x7F) << shift
        pos += 1
        if not (b & 0x80):
            break
        shift += 7
    return result, pos


def _sbk_iter_fields(buf: bytes, start: int, end: int):
    pos = start
    while pos < end:
        tag, pos = _sbk_read_varint(buf, pos)
        field_no = tag >> 3
        wire_type = tag & 0x7
        if wire_type == 0:
            val, pos = _sbk_read_varint(buf, pos)
        elif wire_type == 1:
            val = buf[pos:pos + 8]
            pos += 8
        elif wire_type == 2:
            length, pos = _sbk_read_varint(buf, pos)
            val = buf[pos:pos + length]
            pos += length
        elif wire_type == 5:
            val = buf[pos:pos + 4]
            pos += 4
        else:
            raise ValueError(f"sbk: unsupported wire_type={wire_type} at pos={pos}")
        yield field_no, wire_type, val


def _sbk_move_int_to_usi(move_int: int):
    v = move_int & 0xFFFFFFFF
    from_dan = v & 0xF
    from_suji = (v >> 4) & 0xF
    to_dan = (v >> 8) & 0xF
    to_suji = (v >> 12) & 0xF
    promotion = (v >> 19) & 0x1
    piece = (v >> 24) & 0x1F

    suji_chars = "123456789"
    dan_chars = "abcdefghi"

    if from_dan == 0 and from_suji == 0:
        pt = piece & 0x07
        ch = _SBK_PIECE_TYPE_TO_USI_CHAR.get(pt)
        if ch is None or not (1 <= to_suji <= 9) or not (1 <= to_dan <= 9):
            return None
        return f"{ch}*{suji_chars[to_suji - 1]}{dan_chars[to_dan - 1]}"
    if not (1 <= from_suji <= 9 and 1 <= from_dan <= 9
            and 1 <= to_suji <= 9 and 1 <= to_dan <= 9):
        return None
    promo = "+" if promotion else ""
    return (f"{suji_chars[from_suji - 1]}{dan_chars[from_dan - 1]}"
            f"{suji_chars[to_suji - 1]}{dan_chars[to_dan - 1]}{promo}")


def _sbk_parse_move_bytes(buf: bytes):
    move_int = 0
    weight = 0
    next_id_raw = 0
    for fn, wt, val in _sbk_iter_fields(buf, 0, len(buf)):
        if fn == 1:
            move_int = val
        elif fn == 3:
            weight = val
        elif fn == 4:
            next_id_raw = val
    next_id = next_id_raw & 0xFFFFFFFF
    if next_id >= 0x80000000:
        next_id -= 0x100000000
    return move_int, weight, next_id


def _sbk_parse_state_bytes(buf: bytes):
    state_id = None
    position = None
    moves = []
    for fn, wt, val in _sbk_iter_fields(buf, 0, len(buf)):
        if fn == 1:
            state_id = val
        elif fn == 7:
            try:
                position = val.decode("utf-8")
            except Exception:
                position = None
        elif fn == 9:
            moves.append(val)
    return {"id": state_id, "position": position, "moves": moves}


def _sbk_parse_file(path: str):
    with open(path, "rb") as f:
        buf = f.read()
    pos = 0
    end = len(buf)
    author = None
    states = []
    while pos < end:
        tag, pos2 = _sbk_read_varint(buf, pos)
        field_no = tag >> 3
        wire_type = tag & 0x7
        pos = pos2
        if wire_type != 2:
            raise ValueError(f"sbk: unexpected top-level wire_type={wire_type}")
        length, pos = _sbk_read_varint(buf, pos)
        val = buf[pos:pos + length]
        pos += length
        if field_no == 1:
            author = val.decode("utf-8", errors="replace")
        elif field_no == 3:
            states.append(_sbk_parse_state_bytes(val))
    return author, states


def _sbk_build_position_dict(states: list) -> dict:
    n = len(states)
    if n > 0 and not states[0].get("position"):
        states[0]["position"] = (
            "lnsgkgsnl/1r5b1/ppppppppp/9/9/9/PPPPPPPPP/1B5R1/LNSGKGSNL b - 1")
    decoded_moves = []
    for st in states:
        dm = []
        for mv in st["moves"]:
            try:
                move_int, weight, next_id = _sbk_parse_move_bytes(mv)
            except Exception:
                continue
            usi = _sbk_move_int_to_usi(move_int)
            dm.append((usi, weight, next_id))
        decoded_moves.append(dm)

    roots = [i for i, st in enumerate(states) if st.get("position")]
    visited = [False] * n
    position_dict: dict = {}

    for root_id in roots:
        if visited[root_id]:
            continue
        try:
            root_board = ShogiBoard(sfen=states[root_id]["position"])
        except Exception:
            continue
        visited[root_id] = True
        stack = [(root_id, root_board)]
        while stack:
            sid, board = stack.pop()
            moves_here = decoded_moves[sid]
            if moves_here:
                key = _book_key_from_sfen(board.sfen())
                if key:
                    bucket = position_dict.setdefault(key, {})
                    for usi, weight, _next_id in moves_here:
                        if usi is None:
                            continue
                        if usi not in bucket or weight > bucket[usi]:
                            bucket[usi] = weight
            for usi, weight, next_id in moves_here:
                if usi is None or next_id == -1 or next_id is None:
                    continue
                if not (0 <= next_id < n) or visited[next_id]:
                    continue
                try:
                    nb = board.clone()
                    nb.apply_usi(usi)
                except Exception:
                    continue
                visited[next_id] = True
                stack.append((next_id, nb))

    return position_dict


def _sbk_cache_paths(sbk_path: str):
    base = os.path.basename(sbk_path)
    cache_dir = os.path.dirname(os.path.abspath(sbk_path))
    cache_path = os.path.join(cache_dir, base + ".pyfamate_cache.json")
    return cache_path


def _sbk_load_book(path: str):
    abspath = os.path.abspath(path)
    try:
        st = os.stat(abspath)
    except OSError as e:
        _flog(f"[bookloader-sbk] stat 失敗 path={abspath!r}: {e}")
        return None
    sig = (abspath, st.st_mtime_ns, st.st_size)

    cached = _SBK_BOOK_CACHE.get(abspath)
    if cached is not None and cached[0] == sig:
        return cached[1]

    cache_path = _sbk_cache_paths(abspath)
    if os.path.exists(cache_path):
        try:
            with open(cache_path, "r", encoding="utf-8") as cf:
                cache_obj = json.load(cf)
            if (cache_obj.get("mtime_ns") == st.st_mtime_ns
                    and cache_obj.get("size") == st.st_size):
                position_dict = cache_obj["positions"]
                _SBK_BOOK_CACHE[abspath] = (sig, position_dict)
                _flog(f"[bookloader-sbk] ディスクキャッシュから読込 path={abspath!r} "
                      f"positions={len(position_dict)}")
                return position_dict
            else:
                _flog(f"[bookloader-sbk] ディスクキャッシュが古い (mtime/size不一致) "
                      f"— 再パースします path={abspath!r}")
        except Exception as e:
            _flog(f"[bookloader-sbk] ディスクキャッシュ読込失敗 (再パースします): {e}")

    t0 = time.perf_counter()
    try:
        author, states = _sbk_parse_file(abspath)
        position_dict = _sbk_build_position_dict(states)
    except Exception as e:
        _flog(f"[bookloader-sbk] パース失敗 path={abspath!r}: {e}\n"
              + _safe_format_exc().strip())
        return None
    elapsed = time.perf_counter() - t0
    _flog(f"[bookloader-sbk] パース成功 path={abspath!r} author={author!r} "
          f"states={len(states)} positions={len(position_dict)} elapsed={elapsed:.2f}s")

    _SBK_BOOK_CACHE[abspath] = (sig, position_dict)
    try:
        with open(cache_path, "w", encoding="utf-8") as cf:
            json.dump({
                "mtime_ns": st.st_mtime_ns,
                "size": st.st_size,
                "source": os.path.basename(abspath),
                "positions": position_dict,
            }, cf, ensure_ascii=False)
        _flog(f"[bookloader-sbk] ディスクキャッシュ書込 path={cache_path!r}")
    except Exception as e:
        _flog(f"[bookloader-sbk] ディスクキャッシュ書込失敗 (無視して続行): {e}")

    return position_dict


def _book_file_is_sbk(filename: str) -> bool:
    return (filename or "").strip().lower().endswith(".sbk")



_DB_BOOK_CACHE: dict = {}

_YBB_MAGIC          = b"YANE-BINBOOK-V1\0"
_YBB_FLAG_MOVE_DEPTH = 1
_YBB_KNOWN_FLAGS    = _YBB_FLAG_MOVE_DEPTH
_YBB_HEADER_STRUCT     = _struct.Struct("<16sQQ")
_YBB_INDEX_STRUCT      = _struct.Struct("<32sQHH")
_YBB_MOVE_STRUCT       = _struct.Struct("<Hh")
_YBB_MOVE_DEPTH_STRUCT = _struct.Struct("<HhH")


def _book_file_is_db(filename: str) -> bool:
    return (filename or "").strip().lower().endswith(".db")


def _book_file_is_ybb(filename: str) -> bool:
    return (filename or "").strip().lower().endswith(".ybb")


def _book_file_is_dbybb(filename: str) -> bool:
    return _book_file_is_db(filename) or _book_file_is_ybb(filename)


def _db_parse_db_text(path: str) -> dict:
    position_dict: dict = {}
    with open(path, "r", encoding="utf-8", errors="ignore") as f:
        f.readline()
        cur_key = None
        for line in f:
            s = line.strip()
            if not s or s.startswith("#"):
                continue
            if s[:4] == "sfen":
                cur_key = _book_key_from_sfen(s)
                continue
            if cur_key is None:
                continue
            toks = s.split()
            if not toks:
                continue
            usi = toks[0]
            value = _book_parse_int(toks[2] if len(toks) > 2 else None, 0)
            count = _book_parse_int(toks[4] if len(toks) > 4 else None, 1)
            if count < 1:
                count = 1
            position_dict.setdefault(cur_key, []).append((usi, value, count))
    return position_dict


def _db_parse_ybb(path: str) -> dict:
    with open(path, "rb") as f:
        raw = f.read()
    if len(raw) < _YBB_HEADER_STRUCT.size:
        raise ValueError("ybb: header too short")
    magic, record_count, flags = _YBB_HEADER_STRUCT.unpack(
        raw[:_YBB_HEADER_STRUCT.size])
    if magic != _YBB_MAGIC:
        raise ValueError(f"ybb: invalid magic {magic!r}")
    if flags & ~_YBB_KNOWN_FLAGS:
        raise ValueError(f"ybb: unknown flags {flags}")
    move_struct = (_YBB_MOVE_DEPTH_STRUCT if (flags & _YBB_FLAG_MOVE_DEPTH)
                   else _YBB_MOVE_STRUCT)
    moves_base = _YBB_HEADER_STRUCT.size + record_count * _YBB_INDEX_STRUCT.size
    if len(raw) < moves_base:
        raise ValueError("ybb: index area truncated")

    position_dict: dict = {}
    idx_off = _YBB_HEADER_STRUCT.size
    for _ in range(record_count):
        packed_sfen, move_offset, _ply, move_count = _YBB_INDEX_STRUCT.unpack(
            raw[idx_off:idx_off + _YBB_INDEX_STRUCT.size])
        idx_off += _YBB_INDEX_STRUCT.size
        try:
            key = _book_key_from_sfen(_decode_packed_sfen(packed_sfen))
        except Exception:
            continue
        if not key:
            continue
        mbase = moves_base + move_offset
        moves = []
        for k in range(move_count):
            off = mbase + k * move_struct.size
            chunk = raw[off:off + move_struct.size]
            if len(chunk) != move_struct.size:
                break
            if flags & _YBB_FLAG_MOVE_DEPTH:
                move16, value, _depth = move_struct.unpack(chunk)
            else:
                move16, value = move_struct.unpack(chunk)
            usi = _move16_to_usi(move16 & 0xFFFF)
            if usi in ("none", "null", "resign", "win"):
                continue
            moves.append((usi, int(value), 1))
        if moves:
            position_dict[key] = moves
    return position_dict


def _db_cache_path(path: str) -> str:
    base = os.path.basename(path)
    cache_dir = os.path.dirname(os.path.abspath(path))
    return os.path.join(cache_dir, base + ".pyfamate_dbcache.json")


def _db_load_book(path: str):
    abspath = os.path.abspath(path)
    try:
        stt = os.stat(abspath)
    except OSError as e:
        _flog(f"[bookloader-db] stat 失敗 path={abspath!r}: {e}")
        return None
    sig = (abspath, stt.st_mtime_ns, stt.st_size)

    cached = _DB_BOOK_CACHE.get(abspath)
    if cached is not None and cached[0] == sig:
        return cached[1]

    cache_path = _db_cache_path(abspath)
    if os.path.exists(cache_path):
        try:
            with open(cache_path, "r", encoding="utf-8") as cf:
                cache_obj = json.load(cf)
            if (cache_obj.get("mtime_ns") == stt.st_mtime_ns
                    and cache_obj.get("size") == stt.st_size):
                pd = {k: [tuple(m) for m in v]
                      for k, v in cache_obj["positions"].items()}
                _DB_BOOK_CACHE[abspath] = (sig, pd)
                _flog(f"[bookloader-db] ディスクキャッシュから読込 path={abspath!r} "
                      f"positions={len(pd)}")
                return pd
            _flog(f"[bookloader-db] ディスクキャッシュが古い — 再パース path={abspath!r}")
        except Exception as e:
            _flog(f"[bookloader-db] ディスクキャッシュ読込失敗 (再パース): {e}")

    t0 = time.perf_counter()
    try:
        if _book_file_is_ybb(abspath):
            pd = _db_parse_ybb(abspath)
        else:
            pd = _db_parse_db_text(abspath)
    except Exception as e:
        _flog(f"[bookloader-db] パース失敗 path={abspath!r}: {e}\n"
              + _safe_format_exc().strip())
        return None
    elapsed = time.perf_counter() - t0
    _flog(f"[bookloader-db] パース成功 path={abspath!r} positions={len(pd)} "
          f"elapsed={elapsed:.2f}s")

    _DB_BOOK_CACHE[abspath] = (sig, pd)
    try:
        with open(cache_path, "w", encoding="utf-8") as cf:
            json.dump({
                "mtime_ns": stt.st_mtime_ns,
                "size": stt.st_size,
                "source": os.path.basename(abspath),
                "positions": pd,
            }, cf, ensure_ascii=False)
        _flog(f"[bookloader-db] ディスクキャッシュ書込 path={cache_path!r}")
    except Exception as e:
        _flog(f"[bookloader-db] ディスクキャッシュ書込失敗 (無視): {e}")

    return pd


class _NullBookEngine(USIEngine):

    def __init__(self):
        super().__init__(path="", name="bookloader-sbk-null")
        self._alive = True

    def start(self):
        pass

    def send(self, cmd):
        pass

    def quit(self):
        pass

    def wait_for(self, keyword, timeout=300.0):
        return f"{keyword} (sbk-null stub)"

    def read_until(self, keyword, timeout=60.0):
        return [f"{keyword} (sbk-null stub)"]

    def readline(self, timeout=5.0):
        return ""

    def initialize(self, options):
        pass

    def setoption(self, key, val):
        pass


def _book_apply_file(ctx, which: str, idx: int, book_file: str, *, send_isready: bool) -> bool:
    eng = ctx.book if which == "book" else ctx.book2
    st = ctx.book_state if which == "book" else ctx.book2_state
    log_tag = "[bookloader]" if which == "book" else "[bookloader2]"

    st.index = idx
    st.book_file = book_file
    st.label = _book_pool_label(idx)
    st.trust = _book_pool_trust(idx, default=("absolute" if which == "book"
                                               else ctx.cfg.book2_default_trust))

    if _book_file_is_sbk(book_file):
        if eng is None or not eng._alive:
            _flog(f"{log_tag} sbk 切替: 子エンジン不在/死亡 — 辞書のみ保持し次回 probe 時に備える。")
        position_dict = _sbk_load_book(book_file)
        if position_dict is None:
            _flog(f"{log_tag} sbk ロード失敗 path={book_file!r} — このプールは定跡なし扱い。")
            st.sbk_position_dict = {}
        else:
            st.sbk_position_dict = position_dict
            _flog(f"{log_tag} sbk 切替成功 path={book_file!r} positions={len(position_dict)} "
                  f"index={idx} trust={st.trust!r}")
        st.db_position_dict = None
        st.db_pool_index = idx
        return True

    if _book_file_is_dbybb(book_file) and _book_pool_db_inmemory(idx):
        if eng is None or not eng._alive:
            _flog(f"{log_tag} db 切替: 子エンジン不在/死亡 — 辞書のみ保持し次回 probe 時に備える。")
        position_dict = _db_load_book(book_file)
        if position_dict is None:
            _flog(f"{log_tag} db ロード失敗 path={book_file!r} — このプールは定跡なし扱い。")
            st.db_position_dict = {}
        else:
            st.db_position_dict = position_dict
            _flog(f"{log_tag} db 切替成功 path={book_file!r} positions={len(position_dict)} "
                  f"index={idx} trust={st.trust!r} mode={_db_pool_select_mode(idx)} "
                  f"eval_diff={_db_pool_eval_diff(idx)} ply_range={_db_pool_ply_range(idx)}")
        st.db_pool_index = idx
        st.sbk_position_dict = None
        return True

    st.sbk_position_dict = None
    st.db_position_dict = None
    if eng is None or not eng._alive:
        _flog(f"{log_tag} BookFile 差し替えスキップ — 子エンジン不在/死亡 (book_file={book_file!r})。")
        return False
    try:
        eng.send(f"setoption name BookFile value {book_file}")
        if send_isready:
            eng.send("isready")
            if eng.wait_for("readyok", timeout=30) is None:
                _flog(f"{log_tag} BookFile 差し替え後の readyok timeout (book_file={book_file!r})。")
                return False
    except Exception as e:
        _flog(f"{log_tag} BookFile 差し替え例外 (book_file={book_file!r}): {e}")
        return False
    return True



@dataclasses.dataclass
class _BookState:
    active:      bool = False
    consec:      int  = 0
    turn:        str  = ""
    turn_hint:   str  = ""
    index:       int  = -1
    book_file:   str  = ""
    label:       str  = ""
    trust:       str  = "absolute"
    initialized: bool = False
    sbk_position_dict: object = None
    db_position_dict: object = None
    db_pool_index: int = -1
    firing:      bool = False
    exhausted:   bool = False

    def reset(self):
        self.consec      = 0
        self.turn        = ""
        self.index       = -1
        self.book_file   = ""
        self.label       = ""
        self.trust       = "absolute"
        self.initialized = False
        self.firing      = False
        self.exhausted   = False


def _book_pool_get(index: int, suffix: str, default: str = "") -> str:
    return str(_cfg.get(f"Book_Pool_{index}_{suffix}", default)).strip()


def _book_pool_file(index: int) -> str:
    return _book_pool_get(index, "BookFile")


def _book_pool_label(index: int) -> str:
    return _book_pool_get(index, "Label")


_BOOK_TRUST_VALID = ("absolute", "advisory", "suspect")


def _book_pool_trust(index: int, default: str = "absolute") -> str:
    t = str(_cfg.get(f"Book_Pool_{index}_Trust", "")).strip().lower()
    if t in _BOOK_TRUST_VALID:
        return t
    return default if default in _BOOK_TRUST_VALID else "absolute"


def _book_council_bias_for_trust(trust: str, cfg) -> float:
    if trust == "advisory":
        return cfg.book_council_bias_advisory
    if trust == "suspect":
        return cfg.book_council_bias_suspect
    return 0.0


def _book_normalize_turn(turn) -> str:
    if turn is None:
        return ""
    t = str(turn).strip().lower()
    if t in ("+", "b", "black", "sente"):
        return "+"
    if t in ("-", "w", "white", "gote"):
        return "-"
    return ""


def _book_resolve_index(turn: str, cfg) -> int:
    nt = _book_normalize_turn(turn)
    if not cfg.book_auto_turn:
        if nt == "+":
            return cfg.book_sente_index
        if nt == "-":
            return cfg.book_gote_index
        return cfg.book_default_index
    if nt == "+":
        return cfg.book_sente_index
    if nt == "-":
        return cfg.book_gote_index
    return cfg.book_default_index


def _book_normalize_filename(name: str) -> str:
    n = (name or "").strip()
    if not n or n.lower() == "no_book":
        return n
    _low = n.lower()
    if _low.endswith(".ybb") or _low.endswith(".db") or _low.endswith(".bin") or _low.endswith(".sbk"):
        return n
    return n + ".ybb"


def _book_resolve_file(index: int) -> str:
    f = _book_pool_file(index)
    if not f:
        f = _book_file_name
    f = _book_normalize_filename(f)
    if (f and f.lower() != "no_book"
            and not os.path.isabs(f)
            and "/" not in f and "\\" not in f
            and _book_dir and os.path.isabs(_book_dir)):
        f = os.path.join(_book_dir, f)
    return f


def _book_start_engine(ctx) -> bool:
    if not _book_enabled:
        _flog("[bookloader] disabled — Book_Path 未設定 または プール空。在来探索のみで動作。")
        ctx.book = None
        ctx.book_state.active = False
        return False

    _idx = ctx.cfg.book_default_index
    _bf = _book_resolve_file(_idx)

    ctx.book = _NullBookEngine()
    ctx.book_state.active = True
    _book_apply_file(ctx, "book", _idx, _bf, send_isready=False)
    _flog(f"[bookloader] 起動成功 pool_indices={_book_pool_indices} "
          f"default_index={_idx} book_file={_bf!r} label={ctx.book_state.label!r} "
          f"trust={ctx.book_state.trust!r}")
    return True

def _book_begin_game(ctx, turn: str = "") -> None:
    if ctx.book is None or not ctx.book._alive:
        if _book_enabled:
            _flog("[bookloader] usinewgame: Book エンジンが不在/死亡 — 再起動を試みます。")
            if ctx.book is not None:
                try:
                    ctx.book.quit()
                except Exception as _qe:
                    _flog(f"[bookloader] 既存ハンドルの quit 例外 (無視): {_qe}")
                ctx.book = None
            _book_start_engine(ctx)
        if ctx.book is None or not ctx.book._alive:
            ctx.book_state.active = False
            return
    st = ctx.book_state
    st.active = True
    st.consec = 0
    nt = _book_normalize_turn(turn)
    st.turn = nt
    st.turn_hint = ""
    idx = _book_resolve_index(nt, ctx.cfg)
    bf = _book_resolve_file(idx)
    if not ctx.cfg.book_auto_turn:
        _route = "Default_Index 固定 (Auto_Turn=false)" if not nt else "turn 指定 (Auto_Turn=false)"
    elif nt:
        _route = "Auto_Turn 使用 (CSA turn / 明示 turn)"
    else:
        _route = "フォールバック (turn 未取得 → Default_Index)"
    _flog(
        f"[bookloader] usinewgame: turn={nt or '?'} → index={idx} "
        f"book_file={bf!r} label={_book_pool_label(idx)!r} 経路={_route}"
    )
    try:
        ctx.book.send("usinewgame")
        _applied = _book_apply_file(ctx, "book", idx, bf, send_isready=True)
        _bf_no_child = (_book_file_is_sbk(bf)
                        or (_book_file_is_dbybb(bf) and _book_pool_db_inmemory(idx)))
        if not _applied and not _bf_no_child:
            _flog("[bookloader] usinewgame 後の BookFile 差し替え失敗 — Book 無効化。")
            _book_kill(ctx, reason="usinewgame BookFile 差し替え失敗")
            return
    except Exception as e:
        _flog(f"[bookloader] usinewgame 送信例外 — Book 無効化: {e}")
        _book_kill(ctx, reason="usinewgame exception")
        return
    st.initialized = True


def _book_maybe_resolve_turn_from_position(ctx, position_cmd: str) -> None:
    st = ctx.book_state
    if not st.active or st.turn:
        return
    if not ctx.cfg.book_auto_turn:
        return
    n_moves = 0
    m = re.search(r"\bmoves\b(.*)$", position_cmd)
    if m:
        n_moves = len([t for t in m.group(1).split() if t])
    nt = "+" if (n_moves % 2 == 0) else "-"
    idx = _book_resolve_index(nt, ctx.cfg)
    bf = _book_resolve_file(idx)
    if idx != st.index or bf != st.book_file:
        st.turn = nt
        _flog(
            f"[bookloader] position から手番判定: n_moves={n_moves} turn={nt} "
            f"→ index={idx} book_file={bf!r} (BookFile 差し替え)"
        )
        try:
            _book_apply_file(ctx, "book", idx, bf, send_isready=True)
        except Exception as e:
            _flog(f"[bookloader] BookFile 差し替え例外: {e}")
    else:
        st.turn = nt


def _book_pool_db_inmemory(index: int) -> bool:
    v = _book_pool_get(index, "DB_InMemory", "false").lower()
    return v in ("true", "1", "yes", "on")


def _db_pool_select_mode(index: int) -> str:
    m = _book_pool_get(index, "DB_SelectMode", "head").lower()
    return m if m in ("head", "value") else "head"


def _db_pool_eval_diff(index: int) -> int:
    try:
        return max(0, int(_book_pool_get(index, "DB_EvalDiff", "0")))
    except Exception:
        return 0



def _mirror_sfen_board(board_s: str) -> str:
    def _mirror_rank(rank: str) -> str:
        toks = []
        i = 0
        n = len(rank)
        while i < n:
            ch = rank[i]
            if ch.isdigit():
                toks.append(ch)
                i += 1
            elif ch == "+":
                toks.append(rank[i:i + 2])
                i += 2
            else:
                toks.append(ch)
                i += 1
        out = []
        for t in reversed(toks):
            if t.isdigit():
                out.append(t)
            else:
                out.append(t.swapcase())
        return "".join(out)

    ranks = board_s.split("/")
    flipped = [_mirror_rank(r) for r in reversed(ranks)]
    return "/".join(flipped)


def _mirror_sfen_hand(hand_s: str) -> str:
    if hand_s == "-" or not hand_s:
        return "-"
    return hand_s.swapcase()


def _mirror_sfen_key(key: str) -> str:
    parts = key.split()
    if len(parts) < 4:
        return ""
    board_s, turn_s, hand_s = parts[0], parts[-3], parts[-2]
    fb = _mirror_sfen_board(board_s)
    ft = "w" if turn_s == "b" else "b"
    fh = _mirror_sfen_hand(hand_s)
    return f"{fb} {ft} {fh} 0"


_USI_SQ_RE = re.compile(r"^([1-9])([a-i])$")


def _mirror_usi_square(sq: str) -> str:
    m = _USI_SQ_RE.match(sq)
    if not m:
        return sq
    f = int(m.group(1))
    r = ord(m.group(2)) - ord("a") + 1
    nf = 10 - f
    nr = 10 - r
    return f"{nf}{chr(ord('a') + nr - 1)}"


def _mirror_usi_move(usi: str) -> str:
    if not usi or usi in ("none", "null", "resign", "win", "pass"):
        return usi
    if "*" in usi:
        piece, dst = usi.split("*", 1)
        return f"{piece}*{_mirror_usi_square(dst)}"
    promo = ""
    body = usi
    if body.endswith("+"):
        promo = "+"
        body = body[:-1]
    if len(body) != 4:
        return usi
    src, dst = body[:2], body[2:]
    return f"{_mirror_usi_square(src)}{_mirror_usi_square(dst)}{promo}"


def _db_pool_ply_range(index: int):
    raw = _book_pool_get(index, "DB_PlyRange", "")
    if not raw or "-" not in raw:
        return None
    lo_s, _, hi_s = raw.partition("-")
    try:
        lo = int(lo_s) if lo_s.strip() else 0
        hi = int(hi_s) if hi_s.strip() else (1 << 30)
    except Exception:
        return None
    if lo > hi:
        lo, hi = hi, lo
    return (lo, hi)


def _db_current_ply(position_cmd: str) -> int:
    m = re.search(r"\bmoves\b(.*)$", position_cmd or "")
    if not m:
        return 0
    return len([t for t in m.group(1).split() if t])


def _db_probe_position(st, position_cmd: str):
    pd = getattr(st, "db_position_dict", None)
    if not pd:
        return (False, None)
    try:
        key = _book_key_from_sfen(_board_for_position(position_cmd).sfen())
    except Exception as e:
        _flog(f"[bookloader-db] 局面復元失敗 (定跡切れ扱い): {e}")
        return (False, None)
    if not key:
        return (False, None)

    idx = getattr(st, "db_pool_index", -1)
    _flipped_hit = False
    moves = pd.get(key)
    if not moves:
        _fkey = _mirror_sfen_key(key)
        if _fkey:
            _fmoves = pd.get(_fkey)
            if _fmoves:
                moves = [(_mirror_usi_move(u), v, c) for (u, v, c) in _fmoves]
                _flipped_hit = True
                _flog(f"[bookloader-db] FlippedBook ヒット key={key} → flip={_fkey} "
                      f"候補={len(moves)}")
    if not moves:
        return (False, None)

    mode = _db_pool_select_mode(idx)
    eval_diff = _db_pool_eval_diff(idx)
    ply_range = _db_pool_ply_range(idx)

    apply_diff = eval_diff > 0
    if apply_diff and ply_range is not None:
        ply = _db_current_ply(position_cmd)
        lo, hi = ply_range
        if not (lo <= ply <= hi):
            apply_diff = False

    cand = moves
    if apply_diff:
        best_v = max(v for (_u, v, _c) in moves)
        cand = [t for t in moves if (best_v - t[1]) <= eval_diff]
        if not cand:
            cand = moves

    if mode == "value":
        move = max(cand, key=lambda t: t[1])[0]
    else:
        move = cand[0][0]

    _flog(f"[bookloader-db] 定跡ヒット key={key} 候補={len(moves)}→{len(cand)} "
          f"mode={mode} eval_diff={eval_diff} ply_range={ply_range} "
          f"flipped={_flipped_hit} move={move}")
    return (True, move)


def _sbk_probe_position(st, position_cmd: str):
    pd = getattr(st, "sbk_position_dict", None)
    if not pd:
        return (False, None)
    try:
        key = _book_key_from_sfen(_board_for_position(position_cmd).sfen())
    except Exception as e:
        _flog(f"[bookloader-sbk] 局面復元失敗 (定跡切れ扱い): {e}")
        return (False, None)
    if not key:
        return (False, None)
    bucket = pd.get(key)
    _flipped_hit = False
    if not bucket:
        _fkey = _mirror_sfen_key(key)
        if _fkey:
            _fbucket = pd.get(_fkey)
            if _fbucket:
                bucket = {_mirror_usi_move(u): w for u, w in _fbucket.items()}
                _flipped_hit = True
                _flog(f"[bookloader-sbk] FlippedBook ヒット key={key} → flip={_fkey} "
                      f"候補={len(bucket)}")
    if not bucket:
        return (False, None)
    moves = list(bucket.keys())
    weights = [max(int(bucket[m]), 0) for m in moves]
    if sum(weights) <= 0:
        move = random.choice(moves)
    else:
        move = random.choices(moves, weights=weights, k=1)[0]
    _flog(f"[bookloader-sbk] 定跡ヒット key={key} 候補={len(moves)} "
          f"flipped={_flipped_hit} move={move} weight={bucket.get(move)}")
    return (True, move)


def _book_probe(ctx, position_cmd: str, eng=None, st=None):
    if eng is None:
        eng = ctx.book
    if st is None:
        st = ctx.book_state
    if st is not None and getattr(st, "sbk_position_dict", None) is not None:
        return _sbk_probe_position(st, position_cmd)
    if st is not None and getattr(st, "db_position_dict", None) is not None:
        return _db_probe_position(st, position_cmd)
    if eng is None or not eng._alive:
        return (False, None)
    while True:
        try:
            eng._q.get_nowait()
        except queue.Empty:
            break
    try:
        eng.send(position_cmd)
        eng.send(f"go movetime {ctx.cfg.book_timeout_ms}")
    except Exception as e:
        _flog(f"[bookloader] probe 送信例外: {e}")
        return (False, None)

    scored_info_seen = False
    book_info_seen   = False
    bestmove         = None
    global _BOOK_PROBE_TRACE_LEFT
    _trace_this = _BOOK_PROBE_TRACE_LEFT > 0
    if _trace_this:
        _BOOK_PROBE_TRACE_LEFT -= 1
        _flog(f"[bookloader] probe trace start: {position_cmd}")
    t_start = time.perf_counter()
    _bk_grace_s = 2.0
    try:
        _bk_ck = ctx.ps.go_clock or ctx.ps.ponder_clock
        if _bk_ck is not None:
            _bk_tot_ms = ((_bk_ck.remaining_ms or 0) + (_bk_ck.floor_ms or 0)
                          + (_bk_ck.inc_ms or 0))
            if _bk_tot_ms > 0:
                _bk_grace_s = max(0.3, min(2.0, _bk_tot_ms / 1000.0 * 0.10))
                if _bk_tot_ms >= 8000:
                    _bk_grace_s = max(_bk_grace_s, 1.5)
    except Exception:
        pass
    deadline = t_start + (ctx.cfg.book_timeout_ms / 1000.0) + _bk_grace_s
    while True:
        remaining = deadline - time.perf_counter()
        if remaining <= 0:
            _flog(f"[bookloader] probe タイムアウト (bestmove 未到達, "
                  f"{ctx.cfg.book_timeout_ms}ms+余裕 超過)")
            try:
                eng.send("stop")
            except Exception as _ie:
                _flog(f"[ignored] _book_probe: {_ie!r}")
            return (False, None)
        line = eng.readline(timeout=min(remaining, 1.0))
        if line is None:
            _flog("[bookloader] probe 中にエンジン死亡 (readline None)")
            return (False, None)
        if line == "":
            continue
        if _trace_this:
            _flog(f"[bookloader] probe<< {line}")
        if line.startswith("info"):
            low = line.lower()
            if "depth" in line and "score" in line:
                scored_info_seen = True
            if line.startswith("info string") and (
                    "book" in low
                    or "moves to" in low
                    or "bookeval" in low):
                book_info_seen = True
            continue
        if line.startswith("bestmove"):
            m = _RE_BESTMOVE.match(line)
            bestmove = m.group(1) if m else None
            break
    elapsed = time.perf_counter() - t_start
    if bestmove is None:
        return (False, None)
    if book_info_seen:
        _flog(f"[bookloader] 定跡ヒット (info string book) move={bestmove} "
              f"elapsed={elapsed:.3f}s")
        return (True, bestmove)
    if scored_info_seen:
        _flog(f"[bookloader] 探索手 (book シグナル無し) move={bestmove} "
              f"elapsed={elapsed:.3f}s → 定跡切れ")
    else:
        _flog(f"[bookloader] 定跡シグナル無し move={bestmove} "
              f"elapsed={elapsed:.3f}s → 定跡切れ")
    return (False, None)


def _book_try_move(ctx, position_cmd: str, eng=None, st=None, kill_fn=None,
                   consec_max=None):
    if eng is None:
        eng = ctx.book
    if st is None:
        st = ctx.book_state
    if kill_fn is None:
        kill_fn = _book_kill
    if consec_max is None:
        consec_max = ctx.cfg.book_consec_max
    if not _book_enabled or not st.active or eng is None or not eng._alive:
        return None
    if st is ctx.book_state:
        _book_maybe_resolve_turn_from_position(ctx, position_cmd)
    hit, move = _book_probe(ctx, position_cmd, eng=eng, st=st)
    if hit and move not in (None, ""):
        st.consec = 0
        _flog(f"[bookloader] 定跡ヒット turn={st.turn or '?'} move={move} "
              f"trust={st.trust} consec=0/{consec_max} book_file={st.book_file!r}")
        return move
    st.consec += 1
    _flog(f"[bookloader] 定跡切れ turn={st.turn or '?'} "
          f"consec={st.consec}/{consec_max}")
    _hard_kill_consec = ctx.cfg.book_hard_kill_consec
    if _hard_kill_consec and st.consec >= _hard_kill_consec:
        kill_fn(ctx, reason=f"連続定跡切れ {st.consec} 回 "
                            f"(hard_kill={_hard_kill_consec}; エンジン応答不能とみなす)")
    return None


def _book_consult(ctx, position_cmd: str):
    move = _book_try_move(ctx, position_cmd)
    if move:
        return (move, ctx.book_state.trust)

    if (ctx.book_state.turn == "+"
            and not ctx.book2_state.exhausted
            and ctx.book_state.consec >= ctx.cfg.book2_fire_consec
            and (ctx.book2 is None or not ctx.book2._alive)):
        _book2_fire_async(ctx)

    return (None, "")


def _book2_fire(ctx) -> None:
    if ctx.book2 is not None and ctx.book2._alive:
        return
    _idx = ctx.cfg.book2_pool_index
    _bf = _book_resolve_file(_idx)
    if not _bf:
        _flog(f"[bookloader2] Book2_Pool_Index={_idx} の BookFile 未解決 — 第2 Book 起動中止。")
        return
    _b2_kind = "sbk" if _book_file_is_sbk(_bf) else "db"
    _flog(f"[bookloader2] 定跡切れ検出 (main consec={ctx.book_state.consec}) — "
          f"第2 Book ({_b2_kind}) を Fire します pool={_idx} book_file={_bf!r}")
    try:
        ctx.book2 = _NullBookEngine()
        st = ctx.book2_state
        st.active = True
        st.consec = 0
        st.turn = ctx.book_state.turn
        _ok = _book_apply_file(ctx, "book2", _idx, _bf, send_isready=False)
        st.initialized = True
        _flog(f"[bookloader2] 第2 Book ({_b2_kind}) 起動成功 pool={_idx} book_file={_bf!r} "
              f"label={st.label!r} trust={st.trust!r} apply_ok={_ok}")
    except Exception as e:
        _flog(f"[bookloader2] {_b2_kind} 起動例外 — 第2 Book 無効化: {e}")
        ctx.book2 = None
        ctx.book2_state.active = False
def _book2_fire_async(ctx) -> None:
    st = ctx.book2_state
    if st.firing:
        return
    if ctx.book2 is not None and ctx.book2._alive:
        return
    st.firing = True

    def _run():
        try:
            _book2_fire(ctx)
        except Exception as _e:
            _flog(f"[bookloader2] async fire 例外 (無視): {_e}")
        finally:
            ctx.book2_state.firing = False

    threading.Thread(target=_run, daemon=True, name="book2-async-fire").start()
    _flog("[bookloader2] 非同期 fire 開始 — council を回す裏で第2 Book を起動")


def _book2_probe_seed_if_ready(ctx, position_cmd: str):
    st = ctx.book2_state
    if not (ctx.book2 is not None and ctx.book2._alive
            and st.active and st.initialized):
        return (None, "")
    hit, move = _book_probe(ctx, position_cmd, eng=ctx.book2, st=st)
    if hit and move not in (None, ""):
        return (move, st.trust)
    return (None, "")


def _book2_kill(ctx, reason: str = "") -> None:
    st = ctx.book2_state
    st.active = False
    st.initialized = False
    st.exhausted = True
    if ctx.book2 is None:
        return
    _flog(f"[bookloader2] 終了: {reason} — 第2 Book エンジンを quit します。")
    try:
        ctx.book2.quit()
    except Exception as e:
        _flog(f"[bookloader2] quit 例外 (無視): {e}")
    ctx.book2 = None


def _book_any_active(ctx) -> bool:
    if not _book_enabled:
        return False
    if (ctx.book is not None and ctx.book._alive
            and ctx.book_state.active and ctx.book_state.initialized):
        return True
    if (ctx.book2 is not None and ctx.book2._alive
            and ctx.book2_state.active and ctx.book2_state.initialized):
        return True
    return False


def _book_kill(ctx, reason: str = "") -> None:
    st = ctx.book_state
    st.active = False
    st.initialized = False
    if ctx.book is None:
        return
    _flog(f"[bookloader] 終了: {reason} — Book エンジンを quit します。")
    try:
        ctx.book.quit()
    except Exception as e:
        _flog(f"[bookloader] quit 例外 (無視): {e}")
    ctx.book = None



class EngineContext:

    __slots__ = (
        "dl_1", "nnue_1", "dl_2", "nnue_2", "mate_solver", "dl_3",
        "dl_2_lock", "mate_solver_lock", "dl_3_lock",
        "prefetch", "ps",
        "revive",
        "current_position", "endgame_mode",
        "csa_board",
        "game_log", "game_meta",
        "nnue_root_history",
        "nnue_health",
        "gps",
        "cfg",
        "time_aggression",
        "bestmove_sink",
        "book", "book_state",
        "book2", "book2_state",
        "mate_pv", "mate_pv_base_position",
        "_mate_ponder_thread", "_mate_ponder_cancel", "_mate_ponder_pos", "_mate_ponder_result",
        "_mate_go_mate_ok", "_mate_go_mate_silent",
        "_mate_nomate_cache", "_mate_cache_hits",
        "_zyfamate", "_zyfamate_has_tsumero", "_zyfamate_has_tesuki",
        "_original_fv_scale",
    )

    def __init__(self, dl_1, nnue_1, dl_2, nnue_2,
                 mate_solver, dl_3,
                 dl_2_lock, mate_solver_lock,
                 prefetch, ps,
                 dl_1_model_default,
                 eng_cfg):
        self.dl_1          = dl_1
        self.nnue_1        = nnue_1
        self.dl_2          = dl_2
        self.nnue_2        = nnue_2
        self.mate_solver   = mate_solver
        self.dl_3          = dl_3
        self.dl_2_lock        = dl_2_lock
        self.mate_solver_lock = mate_solver_lock
        self.dl_3_lock        = threading.Lock()
        self.prefetch          = prefetch
        self.ps                = ps
        self.revive            = {}
        self.current_position        = "position startpos"
        self.csa_board               = None
        self.endgame_mode          = False
        self.game_log                = []
        self.game_meta               = {"endgame_triggered": False, "result": "unknown"}
        self.nnue_root_history       = []
        self.nnue_health = NnueHealthState()
        self.gps         = GameProgressState(dl_1_model_current=dl_1_model_default)
        self.cfg         = eng_cfg
        self.time_aggression = TimeAggressionState.from_config(
            base=_time_aggression_base,
            resolve_ta_fn=_resolve_ta,
        )
        self.bestmove_sink = None
        self.book        = None
        self.book_state  = _BookState()
        self.book2       = None
        self.book2_state = _BookState()
        self.mate_pv               = []
        self.mate_pv_base_position = ""
        self._mate_ponder_thread = None
        self._mate_ponder_cancel = None
        self._mate_ponder_pos    = None
        self._mate_ponder_result = None
        self._mate_go_mate_ok     = None
        self._mate_go_mate_silent = 0
        self._mate_nomate_cache   = None
        self._mate_cache_hits     = 0
        self._zyfamate = _zyfamate_enable
        self._zyfamate_has_tsumero = _zyfamate_has_tsumero
        self._zyfamate_has_tesuki = _zyfamate_has_tesuki
        self._original_fv_scale   = None

    def reset_game(self):
        self.current_position        = "position startpos"
        self.endgame_mode          = False
        self.game_log.clear()
        self.game_meta["endgame_triggered"] = False
        self.game_meta["result"]              = "unknown"
        self.ps.reset(_game_phase_handover_default)
        self.nnue_root_history.clear()
        self.gps.reset()
        self.nnue_health.reset()
        for _lr_eng in (self.nnue_1, self.nnue_2, self.dl_1, self.dl_2, self.dl_3):
            if _lr_eng is not None:
                try:
                    _lr_eng._empty_relay_streak = 0
                except Exception:
                    pass
        _calc_game_phase_features.cache_clear()
        _board_for_position_cached.cache_clear()
        _tracking_board_for.cache_clear()
        self.book_state.reset()
        self.book2_state.reset()
        self.mate_pv               = []
        self.mate_pv_base_position = ""
        self._original_fv_scale = None
        _sr_ja_empty_seen.clear()

def _extract_clock_sides(go_line, move_count):
    _btime_m = _RE_BTIME.search(go_line)
    _wtime_m = _RE_WTIME.search(go_line)
    _byo_m   = _RE_BYOYOMI.search(go_line)
    _binc_m  = _RE_BINC.search(go_line)
    _winc_m  = _RE_WINC.search(go_line)

    our_remaining_ms = 0
    if move_count is not None:
        _side_m = _btime_m if (move_count % 2 == 0) else _wtime_m
        if _side_m:
            our_remaining_ms = int(_side_m.group(1))

    byo_ms = int(_byo_m.group(1)) if _byo_m else 0

    our_inc_ms = 0
    if move_count is not None:
        _inc_m = _binc_m if (move_count % 2 == 0) else _winc_m
        if _inc_m:
            our_inc_ms = int(_inc_m.group(1))
    else:
        _inc_cands = [int(m.group(1)) for m in (_binc_m, _winc_m) if m]
        _inc_pos = [v for v in _inc_cands if v > 0]
        our_inc_ms = min(_inc_pos) if _inc_pos else 0

    return our_remaining_ms, byo_ms, our_inc_ms


def _resolve_ponder_clock(ctx, label):
    if ctx.ps.ponder_clock is not None:
        return ctx.ps.ponder_clock
    if ctx.ps.go_clock is not None:
        _flog(f"[{label}] ponder_clock=None — go_clock fallback "
              f"eff_s={ctx.ps.go_clock.eff_s:.2f}s")
        return ctx.ps.go_clock
    _flog(f"[{label}] ponder_clock=None, go_clock=None")
    return None


def _parse_go_clock_base(go_line, our_side_ply=None):
    remaining_ms = 0
    floor_ms     = 0
    eff_s        = 0.0

    def _u(key):
        m = re.search(rf"{key}\s+(\d+)", go_line)
        return int(m.group(1)) if m else None

    btime_val = _u("btime")
    wtime_val = _u("wtime")
    byo_val   = _u("byoyomi")

    if our_side_ply is None:
        _clock_is_sente = None
    else:
        _clock_is_sente = (our_side_ply % 2 == 0)

    if _clock_is_sente is None:
        our_main = opponent_main = None
    elif _clock_is_sente:
        our_main = btime_val
        opponent_main = wtime_val
    else:
        our_main = wtime_val
        opponent_main = btime_val

    if our_main is not None and our_main > 0:
        remaining_ms = our_main
    elif _clock_is_sente is None and btime_val is not None and wtime_val is not None:
        if btime_val > 0 and wtime_val > 0:
            remaining_ms = min(btime_val, wtime_val)

    if byo_val:
        floor_ms = byo_val

    byo_m = re.search(r"byoyomi\s+(\d+)", go_line)

    _both_times_zero = ((btime_val or 0) == 0 and (wtime_val or 0) == 0
                        and (btime_val is not None or wtime_val is not None))
    _has_byoyomi = (byo_val is not None and byo_val > 0
                    and not _both_times_zero)
    _byoyomi_patch_needed = (byo_val is not None and byo_val > 0)
    if _both_times_zero and byo_val is not None and byo_val > 0:
        _dlog(f"_parse_go_clock: btime=wtime=0 byoyomi={byo_val}ms — "
              f"treated as Fischer increment (pseudo-Fischer GUI)")
    _has_increment_field = ((_u("binc") or 0) > 0 or (_u("winc") or 0) > 0)
    _our_field_present = (our_main is not None) if _clock_is_sente is not None else False
    if remaining_ms == 0 and floor_ms > 0 and _clock_is_sente is not None \
            and not _has_byoyomi and _our_field_present and not _has_increment_field:
        if opponent_main is not None and opponent_main > 0:
            remaining_ms = opponent_main

    inc_ms = 0
    binc_val = _u("binc")
    winc_val = _u("winc")
    if binc_val is not None or winc_val is not None:
        binc_val = binc_val or 0
        winc_val = winc_val or 0
        if _clock_is_sente is not None:
            inc_ms = binc_val if _clock_is_sente else winc_val
        else:
            positives = [v for v in (binc_val, winc_val) if v > 0]
            inc_ms = min(positives) if len(positives) == 2 else (positives[0] if positives else 0)
        _inc_floor = int(inc_ms * _inc_spend_ratio)
        floor_ms = max(floor_ms, _inc_floor)

    if remaining_ms == 0 and floor_ms == 0:
        mt_val = _u("movetime")
        if mt_val:
            floor_ms = mt_val

    if _move_overhead_ms > 0 and floor_ms > 0:
        floor_ms = max(int(floor_ms * 0.05), floor_ms - _move_overhead_ms)

    patched_line = go_line
    if byo_m:
        byoyomi_val = byo_val
        if byoyomi_val > 0 and _clock_is_sente is not None and _byoyomi_patch_needed:
            if _clock_is_sente:
                if btime_val is not None and btime_val == 0:
                    patched_line = re.sub(r"btime\s+\d+", "btime 1", patched_line)
                    _flog(f"_parse_go_clock: btime 0 -> 1 (byoyomi補完, our_side_ply={our_side_ply})")
            else:
                if wtime_val is not None and wtime_val == 0:
                    patched_line = re.sub(r"wtime\s+\d+", "wtime 1", patched_line)
                    _flog(f"_parse_go_clock: wtime 0 -> 1 (byoyomi補完, our_side_ply={our_side_ply})")
        if byoyomi_val > 0 and _move_overhead_ms > 0:
            _byo_safe = max(100, byoyomi_val - _move_overhead_ms)
            if _byo_safe != byoyomi_val:
                patched_line = re.sub(r"byoyomi\s+\d+", f"byoyomi {_byo_safe}", patched_line)
                _dlog(f"_parse_go_clock: byoyomi {byoyomi_val} -> {_byo_safe} (Move_Overhead={_move_overhead_ms}ms)")

    if inc_ms > 0 and _move_overhead_ms > 0 and _clock_is_sente is not None:
        _our_key = "btime" if _clock_is_sente else "wtime"
        _our_val = (btime_val if _clock_is_sente else wtime_val) or 0
        if _our_val > _move_overhead_ms:
            _safe_val = _our_val - _move_overhead_ms
            patched_line = re.sub(rf"{_our_key}\s+\d+", f"{_our_key} {_safe_val}", patched_line)
            _dlog(f"_parse_go_clock: Fischer overhead: {_our_key} {_our_val} -> {_safe_val} "
                  f"(Move_Overhead={_move_overhead_ms}ms)")

    _dl_skip = False
    rem_moves = None
    if remaining_ms > 0 and remaining_ms < 5000 and floor_ms == 0:
        _dl_skip = True
        _dlog(f"DL skip: sudden death emergency ({remaining_ms}ms < 5000)")
    elif remaining_ms == 0 and floor_ms == 0:
        eff_s = 0.0
    else:
        if _clock_is_sente is not None:
            rem_moves = _calc_remaining_moves(our_side_ply, remaining_ms)
            if (inc_ms > 0 and _fischer_horizon_moves > 0
                    and rem_moves > _fischer_horizon_moves):
                _orig_rem_moves = rem_moves
                rem_moves = _fischer_horizon_moves
                _dlog(f"_parse_go_clock: rem_moves {_orig_rem_moves} -> {rem_moves} "
                      f"(Fischer horizon clamp; inc={inc_ms}ms "
                      f"horizon={_fischer_horizon_moves})")
            eff_s = (remaining_ms / rem_moves + floor_ms) / 1000.0
        else:
            eff_s = (remaining_ms + floor_ms) / 1000.0
            _dlog(f"_parse_go_clock: our_side_ply=None → eff_s={eff_s:.2f}s is total budget "
                  f"(not per-move); remaining={remaining_ms}ms floor={floor_ms}ms")

    _fischer_cap_bound = False
    if _eff_s_fischer_cap_ratio > 0.0 and eff_s > 0.0 \
            and remaining_ms > 0 and inc_ms > 0:
        cap_s = (remaining_ms * _eff_s_fischer_cap_ratio) / 1000.0
        if inc_ms > 0:
            _fischer_cap_floor_s = (inc_ms / 1000.0) * 0.8
            cap_s = max(cap_s, _fischer_cap_floor_s)
        if eff_s > cap_s:
            _dlog(f"_parse_go_clock: eff_s {eff_s:.2f}s -> {cap_s:.2f}s "
                  f"(Fischer increment cap; remaining={remaining_ms}ms "
                  f"inc={inc_ms}ms ratio={_eff_s_fischer_cap_ratio:.3f})")
            eff_s = cap_s
            _fischer_cap_bound = True

    _dl_time_min_threshold_ms = max(800, _dl_time_min_ms)
    if not _dl_skip and eff_s > 0.0 and eff_s * 1000.0 < _dl_time_min_threshold_ms:
        _dl_skip = True
        _dlog(f"DL skip: eff_s {eff_s:.2f}s < DL_Time_Min "
              f"({_dl_time_min_threshold_ms:.0f}ms) → Light Council")

    return GoClockInfo(
        eff_s        = eff_s,
        dl_timeout_s = 0.0,
        patched_line = patched_line,
        remaining_ms = remaining_ms,
        floor_ms     = floor_ms,
        inc_ms       = inc_ms,
        is_total_budget = (_clock_is_sente is None and remaining_ms > 0),
        byo_ms       = byo_val or 0,
    ), _fischer_cap_bound, _dl_skip


def _compute_dl_timeout_s(clock_base, score_cp=0, fischer_cap_bound=False, dl_skip=False):
    if dl_skip:
        return 0.0
    eff_s = clock_base.eff_s
    remaining_ms = clock_base.remaining_ms
    floor_ms = clock_base.floor_ms
    if remaining_ms == 0 and floor_ms == 0:
        _fb = _tdg.dl_time_fallback_ms / 1000.0
        _dlog(f"DL timeout: no usable clock → fallback {_fb:.2f}s")
        return _fb
    effective_ms = eff_s * 1000.0
    _effective_ratio = max(0.01, min(0.95,
        _tdg.dl_time_ratio + _dl_time_ratio_eff_s_coef * eff_s))
    ratio_budget = effective_ms * _effective_ratio
    if remaining_ms == 0:
        effective_min_ms = min(_dl_time_min_ms, ratio_budget)
    else:
        if fischer_cap_bound:
            _eff_based_cap_ms = eff_s * 1000.0 * _dl_time_min_eff_s_cap_ratio if _dl_time_min_eff_s_cap_ratio > 0.0 else ratio_budget
            effective_min_ms = min(_dl_time_min_ms, _eff_based_cap_ms)
        elif _dl_time_min_eff_s_cap_ratio > 0.0 and eff_s > 0.0:
            _eff_based_cap_ms = eff_s * 1000.0 * _dl_time_min_eff_s_cap_ratio
            effective_min_ms = min(_dl_time_min_ms, max(ratio_budget, _eff_based_cap_ms))
        else:
            effective_min_ms = _dl_time_min_ms
    budget_ms = max(effective_min_ms, min(_tdg.dl_time_max_ms, ratio_budget))
    score_scale = 1.0
    if remaining_ms > 0 and score_cp > 0:
        score_scale = max(0.0, 1.0 - score_cp / 1000.0)
    _scaled_ms = budget_ms * score_scale
    _score_scale_floor_ms = effective_min_ms
    _scaled_ms = max(_scaled_ms, _score_scale_floor_ms)
    _dlog(
        f"DL timeout: remaining={remaining_ms}ms "
        f"+ byoyomi/inc={floor_ms}ms = eff={effective_ms:.0f}ms "
        f"x {_tdg.dl_time_ratio} -> budget={budget_ms:.0f}ms "
        f"(min={effective_min_ms:.0f}[{'capped-byoyomi' if remaining_ms == 0 else 'fischer-bound' if fischer_cap_bound else 'capped-effs' if (_dl_time_min_eff_s_cap_ratio > 0.0 and effective_min_ms < _dl_time_min_ms) else 'fixed'}] "
        f"max={_tdg.dl_time_max_ms:.0f}) score_scale={score_scale:.3f}"
        f"(score_cp={score_cp}) -> {_scaled_ms / 1000:.2f}s"
    )
    return _scaled_ms / 1000.0


def _parse_go_clock(go_line, our_side_ply=None, score_cp=0):
    base, _fcb, _dls = _parse_go_clock_base(go_line, our_side_ply)
    dl_to = _compute_dl_timeout_s(base, score_cp,
                                   fischer_cap_bound=_fcb, dl_skip=_dls)
    return base._replace(dl_timeout_s=dl_to)


def _get_handover_game_phase(eff_s, cfg) -> float:
    _threshold = cfg.game_phase_handover_threshold
    _per_sec   = cfg.game_phase_handover_per_sec
    _game_phase_min    = cfg.game_phase_handover_min
    _game_phase_max    = cfg.game_phase_handover_max
    if _per_sec == 0.0 or eff_s is None:
        return _checked_range(_threshold, 0.0, 1.0, "handover_game_phase(fixed)")
    raw = _threshold + eff_s * _per_sec
    clamped = max(_game_phase_min, min(_game_phase_max, raw))
    return _checked_range(clamped, 0.0, 1.0, "handover_game_phase(dynamic)")


def _game_phase_response(game_phase: float, coef: float) -> float:
    if coef == 0.0:
        return 0.0
    g = 0.0 if game_phase < 0.0 else (1.0 if game_phase > 1.0 else game_phase)
    return coef * g


def _calc_dl_score_gap_min(eff_s: float, cfg=None, game_phase: float = 0.0) -> int:
    _base    = cfg.dl_gap_min_base    if cfg is not None else _dl_gap_min_base
    _per_sec = cfg.dl_gap_min_per_sec if cfg is not None else _dl_gap_min_per_sec
    _min     = cfg.dl_gap_min_min     if cfg is not None else _dl_gap_min_min
    _max     = cfg.dl_gap_min_max     if cfg is not None else _dl_gap_min_max
    _game_phase_coef = cfg.dl_gap_min_game_phase_coef if cfg is not None else _dl_gap_min_game_phase_coef
    raw = _base + eff_s * _per_sec + _game_phase_response(game_phase, _game_phase_coef)
    return int(round(max(_min, min(_max, raw))))



def _calc_dl_model_aware_stability_threshold(eff_s: float, model_mb: float = None,
                                      nodes: int = None, game_phase: float = 0.0,
                                      cfg=None) -> int:
    _stab_max       = cfg.dl_stab_max       if cfg is not None else _dl_stab_max
    _stab_base      = cfg.dl_stab_base      if cfg is not None else _dl_stab_base
    _stab_per_sec   = cfg.dl_stab_per_sec   if cfg is not None else _dl_stab_per_sec
    _stab_min       = cfg.dl_stab_min       if cfg is not None else _dl_stab_min
    _game_phase_tighten     = cfg.dl_stab_game_phase_tighten if cfg is not None else _dl_stab_game_phase_tighten
    if _stab_max == 0:
        return 0
    raw = _stab_base + eff_s * _stab_per_sec
    base_threshold = max(_stab_min, min(_stab_max, raw))
    if model_mb is not None and model_mb < 200.0:
        model_factor = 3.0
    elif model_mb is not None and model_mb < 400.0:
        model_factor = 2.0
    else:
        model_factor = 1.0
    effective_nodes = nodes if nodes else _params.get("POLICY_NODES", 2000)
    if effective_nodes < 1500:
        node_factor = 2.0
    elif effective_nodes < 3000:
        node_factor = 1.5
    else:
        node_factor = 1.0
    factor = max(model_factor, node_factor)
    adjusted = base_threshold * factor
    _game_phase_term = _game_phase_response(game_phase, _game_phase_tighten)
    if _game_phase_term != 0.0:
        adjusted = max(0.0, adjusted - _game_phase_term)
    return int(round(min(adjusted, 1500.0)))


def _calc_weight_floor_gp(game_phase, floor_early, floor_late):
    gp = max(0.0, min(1.0, game_phase if game_phase is not None else 0.0))
    return floor_early + (floor_late - floor_early) * gp


def _apply_weight_floor(raw_weight, floor=None, game_phase=None, cfg=None):
    if floor is None:
        if cfg is not None and game_phase is not None:
            floor = _calc_weight_floor_gp(
                game_phase,
                cfg.council_weight_floor_early,
                cfg.council_weight_floor_late)
        else:
            floor = _COUNCIL_WEIGHT_FLOOR
    if raw_weight <= 0:
        return 0.0
    return max(floor, raw_weight)


_PONDER_CLOCK_KEYS = ("btime", "wtime", "binc", "winc", "byoyomi", "movetime")


def _extract_clock_tokens(line) -> str:
    if not line or not any(k in line for k in _PONDER_CLOCK_KEYS):
        return ""
    parts = line.split()
    out = []
    idx = 0
    while idx < len(parts):
        if parts[idx] in _PONDER_CLOCK_KEYS and idx + 1 < len(parts):
            out.append(parts[idx])
            out.append(parts[idx + 1])
            idx += 2
            continue
        idx += 1
    return " ".join(out)


def _ponderhit_line_for_nnue(ps) -> str:
    _ph_src = ps.ponder_line or ""
    _ph_pc = getattr(ps, "ponder_clock", None)
    if _ph_pc is not None and getattr(_ph_pc, "patched_line", None):
        _ph_src = _ph_pc.patched_line
    _clock = _extract_clock_tokens(_ph_src)
    return ("ponderhit " + _clock) if _clock else "ponderhit"


def _patch_ponder_clock_from_ponderhit(ps, ponderhit_line):
    clock = _extract_clock_tokens(ponderhit_line)
    if not clock:
        return
    ps.ponder_line = "go " + clock
    _dlog("[PH-CLOCK-PATCH] ponder_line updated: %s" % ps.ponder_line)

def _calc_slow_mover(eff_s, cfg, time_aggression=None):
    base    = cfg.slow_mover_base
    per_sec = cfg.slow_mover_per_sec
    lo      = cfg.slow_mover_min
    hi      = cfg.slow_mover_max
    time_aggression_eff      = time_aggression if time_aggression is not None else _tdg.time_aggression

    per_sec_eff = per_sec * time_aggression_eff
    _t_for_max = max(0.0, min(1.0, time_aggression_eff))
    max_eff     = lo + (hi - lo) * _t_for_max
    raw = base + eff_s * per_sec_eff
    return int(round(max(lo, min(max_eff, raw))))


def _calc_per_move_thresholds(eff_s, cfg, game_phase: float = 0.0):
    return _PerMoveThresholds(
        gap_min    = _calc_dl_score_gap_min(eff_s, cfg=cfg, game_phase=game_phase),
        stab       = _calc_dl_model_aware_stability_threshold(eff_s, model_mb=_dl1_mb_for_stab, nodes=_params.get("POLICY_NODES", 2000), game_phase=game_phase, cfg=cfg),
        slow_mover = _calc_slow_mover(eff_s, cfg=cfg),
    )


def _calc_dynamic_policy_nodes(eff_s, cfg):
    base = _params.get('POLICY_NODES', 2000)
    if eff_s <= 0:
        return base
    per_eff_s = cfg.policy_nodes_per_eff_s
    raw = int(eff_s * per_eff_s)
    return max(base, min(10000, raw))


def _ponderhit_calc_relay_timeout(relay_line, move_count, ponder_clock):
    eff_s_fallback = ponder_clock.eff_s if ponder_clock is not None else 0.0
    clock, _, _ = _parse_go_clock_base(relay_line, move_count)
    eff_s = clock.eff_s if clock.eff_s > 0 else eff_s_fallback
    budget_ms = eff_s * 1000.0

    byo_raw   = clock.floor_ms + _move_overhead_ms
    r_floor   = _lerp(0.04, 0.07, _tdg.time_aggression)
    r_ceil    = _lerp(0.18, 0.33, _tdg.time_aggression)
    r_byo     = _lerp(0.10, 0.20, _tdg.time_aggression)
    buf_floor = max(50,  int(eff_s * 1000 * r_floor))
    buf_ceil  = max(int(eff_s * 1000 * 0.12), int(eff_s * 1000 * r_ceil))
    margin_ms = max(buf_floor, min(buf_ceil, int(byo_raw * r_byo)))

    if budget_ms > 0:
        _to_floor_native = max(_move_overhead_s, budget_ms * 0.30 / 1000.0)
        return max(_to_floor_native, (budget_ms - margin_ms) / 1000.0)
    return _tdg.dl_time_fallback_ms * 2 / 1000.0


def _calc_dynamic_top_n(go_ponder_clock, base_n, cfg):
    if not go_ponder_clock or cfg.dl_prefetch_dl2_median_s <= 0:
        return base_n
    eff_s = go_ponder_clock.eff_s

    idp_overhead_s = 0.0
    if cfg.dl_prefetch_idp_nodes > 0:
        effective_policy_nodes = _params.get("POLICY_NODES", 2000)
        _base_idp_overhead_s = cfg.dl_prefetch_dl1_est_s * (
            cfg.dl_prefetch_idp_nodes / max(1, effective_policy_nodes)
        )
        if cfg.dl_prefetch_idp_nodes > 0:
            j_count = max(0, base_n - 1)
            idp_overhead_s = _base_idp_overhead_s * (1 + j_count)
        else:
            idp_overhead_s = _base_idp_overhead_s

    budget_s = eff_s - cfg.dl_prefetch_dl1_est_s - idp_overhead_s
    if budget_s <= 0:
        return 1
    dynamic_n = max(1, int(budget_s / cfg.dl_prefetch_dl2_median_s))
    return min(base_n, dynamic_n)


def _prefetch_budget_arms_core(
    opponent_remaining_s,
    per_arm_est_s,
    requested_top_n,
    safety_ratio,
):
    if opponent_remaining_s is None or per_arm_est_s <= 0.0:
        return max(1, int(requested_top_n))
    affordable = int((opponent_remaining_s * safety_ratio) / per_arm_est_s)
    return max(1, min(int(requested_top_n), affordable))


def _root_park_budget_core(
    base_park_nodes,
    max_voi_among_arms,
    park_voi_scale,
):
    factor = 1.0 + park_voi_scale * max(0.0, min(1.0, max_voi_among_arms))
    return int(base_park_nodes * factor)


def _voi_weighted_hit_core(hit, arm_voi):
    raw = 1.0 if hit else 0.0
    if not hit:
        return raw, 0.0
    voi = 0.0 if arm_voi is None else max(0.0, min(1.0, arm_voi))
    return raw, 1.0 + voi


def _update_latency_ewma(prev_ewma, prev_count, observed_fetch_ms, model_mb, alpha):
    if model_mb is None or model_mb <= 0.0 or observed_fetch_ms is None \
            or observed_fetch_ms <= 0.0:
        return prev_ewma, prev_count
    sample = (observed_fetch_ms / 1000.0) / model_mb
    if prev_count <= 0 or prev_ewma is None:
        return sample, 1
    a = max(0.0, min(1.0, alpha))
    return (1.0 - a) * prev_ewma + a * sample, prev_count + 1


def _effective_latency_per_mb(cfg_value, ewma, count, min_samples, enabled):
    if not enabled or ewma is None or count < min_samples:
        return cfg_value
    return ewma


def _calc_dl_2_time_margin_ms(eff_s: float, model_mb: float,
                              cfg, margin_min_ms: float = None,
                              cold_launch: bool = False,
                              latency_per_mb_override: float = None) -> float:
    ratio    = cfg.dl_2_margin_ratio
    max_ms   = cfg.dl_2_margin_max_ms
    lat_permb = cfg.dl_2_latency_per_mb_s
    if latency_per_mb_override is not None:
        lat_permb = latency_per_mb_override
    min_ms   = margin_min_ms if margin_min_ms is not None else _tdg.dl_2_margin_min_ms

    base_ms = eff_s * ratio * 1000.0
    base_ms = max(min_ms, min(max_ms, base_ms))

    latency_ms = (model_mb * lat_permb * 1000.0) if model_mb is not None else 0.0

    if cold_launch:
        factor = cfg.dl_2_cold_launch_latency_factor
        latency_ms *= factor

    return base_ms + latency_ms


_LIVE_BOARD = (None, None)
_LIVE_BOARD_VERIFY = False


def _parse_position_moves(position_cmd: str):
    toks = (position_cmd or "").split()
    if toks and toks[0] == "position":
        toks = toks[1:]
    if "moves" in toks:
        mi = toks.index("moves")
        return " ".join(toks[:mi]), toks[mi + 1:]
    return " ".join(toks), []


def _advance_live_board(pos: str) -> "ShogiBoard":
    old_pos, old_board = _LIVE_BOARD
    if old_board is not None and old_pos:
        ob, om = _parse_position_moves(old_pos)
        nb, nm = _parse_position_moves(pos)
        if ob == nb and len(om) <= len(nm) and nm[:len(om)] == om:
            b = old_board.clone()
            for m in nm[len(om):]:
                b.apply_usi(m)
            return b
    return ShogiBoard(sfen=pos, track_history=False)


def _set_current_position(ctx, pos: str) -> None:
    ctx.current_position = pos
    if not pos:
        return
    try:
        new_board = _advance_live_board(pos)
        if _LIVE_BOARD_VERIFY:
            _ref = ShogiBoard(sfen=pos, track_history=False)
            if new_board.sfen() != _ref.sfen():
                _flog(f"[UNIFIED-BOARD][WARN] incremental != rebuild for {pos!r} — "
                      f"rebuild を採用")
                new_board = _ref
        global _LIVE_BOARD
        _LIVE_BOARD = (pos, new_board)
        try:
            _zenrei_live_push(new_board)
        except Exception:
            pass
    except Exception as _lbe:
        _dlog(f"[UNIFIED-BOARD] live 盤更新スキップ (fallback ビルドへ): {_lbe!r}")


@functools.lru_cache(maxsize=4)
def _board_for_position_cached(position_cmd: str) -> "ShogiBoard":
    return ShogiBoard(sfen=position_cmd, track_history=False)


def _board_for_position(position_cmd: str) -> "ShogiBoard":
    live = _LIVE_BOARD
    if live[0] == position_cmd and live[1] is not None:
        return live[1]
    return _board_for_position_cached(position_cmd)


def _calc_game_phase_features_uncached(position_cmd: str) -> tuple:
    try:
        board_feats = _game_phase_state_counts_core(_board_for_position(position_cmd))
        parts = position_cmd.split()
        try:
            mi = parts.index("moves")
            ply = len(parts) - mi - 1
        except ValueError:
            ply = 0
        return (*board_feats, ply)
    except Exception:
        return (0, 0, 0, 0.0, 0, 0)


def _calc_state_phase(WHAND: int, PROMO: int, CAMP: int, KING: float,
                      EXPOSURE: int, *, cfg, ply: int = 0) -> float:
    _w_hand    = cfg.game_phase_w_hand
    _w_promo   = cfg.game_phase_w_promo
    _w_camp    = cfg.game_phase_w_camp
    _w_king    = cfg.game_phase_w_king
    _hand_ref  = cfg.game_phase_hand_ref
    _promo_ref = cfg.game_phase_promo_ref
    _camp_ref  = cfg.game_phase_camp_ref
    _king_ref  = cfg.game_phase_king_ref
    _scale     = cfg.game_phase_scale
    _w_ply     = cfg.game_phase_w_ply
    _ply_ref   = cfg.game_phase_ply_ref
    _w_expo    = cfg.game_phase_w_exposure
    _expo_ref  = cfg.game_phase_exposure_ref
    _ply_term = (_w_ply * ply / _ply_ref) if cfg.game_phase_ply_enable else 0.0
    S = (_w_hand  * WHAND / _hand_ref +
         _w_promo * PROMO / _promo_ref +
         _w_camp  * CAMP  / _camp_ref +
         _w_king  * KING  / _king_ref +
         _ply_term +
         _w_expo  * EXPOSURE / _expo_ref)
    neg_s_over_scale = -S / _scale
    if neg_s_over_scale < -10.0:
        game_phase_core = 1.0
    else:
        game_phase_core = 1.0 - math.exp(neg_s_over_scale)

    _onset = cfg.game_phase_nyugyoku_king_onset
    _full  = cfg.game_phase_nyugyoku_king_full
    nyugyoku_bonus = 0.0
    if KING > _onset:
        frac = (KING - _onset) / (_full - _onset)
        if frac > 1.0:
            frac = 1.0
        nyugyoku_bonus = 0.5 * frac

    game_phase = game_phase_core + nyugyoku_bonus
    return max(0.0, min(1.5, game_phase))



_GAME_PHASE_NYUGYOKU_BAND_WIDTH = 0.5


def _game_phase_for_phase_council(raw_game_phase: float, restore_ratio: float) -> float:
    if raw_game_phase is None:
        return 0.0
    if raw_game_phase <= 1.0 or restore_ratio <= 0.0:
        return min(max(raw_game_phase, 0.0), 1.0)
    frac = (raw_game_phase - 1.0) / _GAME_PHASE_NYUGYOKU_BAND_WIDTH
    if frac > 1.0:
        frac = 1.0
    return max(0.0, 1.0 - restore_ratio * frac)


def _calc_game_phase(position_cmd: str, cfg,
                     child_agreement=None) -> float:
    feats = _calc_game_phase_features(position_cmd)
    whand, promo, camp, king, exposure, ply = feats
    gp = _calc_state_phase(whand, promo, camp, king, exposure, cfg=cfg, ply=ply)
    if child_agreement is not None:
        disagreement = 1.0 - child_agreement
        gp = gp - (gp - 0.5) * disagreement * cfg.game_phase_child_pull
    return max(0.0, min(1.5, gp))




@functools.lru_cache(maxsize=4)
def _calc_game_phase_features(position_cmd: str) -> tuple:
    return _calc_game_phase_features_uncached(position_cmd)


def _calc_phase_weight_game_phase(game_phase: float, weight_early: float, weight_late: float) -> float:
    game_phase = _checked_range(game_phase, 0.0, 1.0, "phase_weight_game_phase(input)")
    return weight_early + game_phase * (weight_late - weight_early)


def _calc_dl_depth_trust(depth: int, cfg) -> float:
    _trust_max       = cfg.dl1_depth_trust_max
    _trust_base      = cfg.dl1_depth_trust_base
    _trust_per_depth = cfg.dl1_depth_trust_per_depth
    _trust_min       = cfg.dl1_depth_trust_min
    if depth is None:
        return _trust_max
    raw = _trust_base + depth * _trust_per_depth
    return max(_trust_min, min(_trust_max, raw))


def _calc_dl_phase_trust(game_phase, cfg, score_gap=None):
    _trust_max = cfg.dl1_game_phase_trust_max
    _trust_min = cfg.dl1_game_phase_trust_min
    if _trust_max < _trust_min:
        _trust_max = _trust_min
    if score_gap is not None:
        _g = score_gap / cfg.gap_norm_cp if cfg.gap_norm_cp > 0 else 0.0
        _g = 0.0 if _g < 0.0 else (1.0 if _g > 1.0 else _g)
        return _trust_max - _g * (_trust_max - _trust_min)
    return _trust_max - game_phase * (_trust_max - _trust_min)


def _calc_dl_pv_overlap_boost(pv_overlap, cfg):
    if pv_overlap is None:
        return 1.0
    _max_boost = cfg.dl1_pv_overlap_max_boost
    t = max(0.0, min(1.0, pv_overlap / 2.0))
    return 1.0 + (_max_boost - 1.0) * t


def _check_council_stale(ctx, dl_top_move):
    if not ctx.cfg.council_sanity_enable:
        return False
    if dl_top_move is None:
        return False
    window = ctx.cfg.council_sanity_window
    log = ctx.game_log
    if len(log) < window:
        return False
    recent = log[-window:]
    for m in recent:
        winner = m.get("council_winner")
        if winner != dl_top_move:
            return False
    _last_rec = recent[-1] if recent else None
    if _last_rec is not None:
        _sgap = _last_rec.get("dl_score_gap")
        _gmin = _last_rec.get("dl_gap_min_used", 50)
        if _sgap is not None and _sgap > max(100, 2 * _gmin):
            _dlog(
                "[COUNCIL-STALE-EXEMPT] dl_top=%s repeated %d wins but "
                "score_gap=%d >> gap_min=%d — unique best, withdrawal suppressed"
                % (dl_top_move, window, _sgap, _gmin)
            )
            return False
    _dlog(
        "[COUNCIL-STALE] dl_top=%s repeated %d consecutive council wins "
        "— DL vote withdrawn" % (dl_top_move, window)
    )
    return True


def _cp_to_winrate(score, slope, game_phase=None, a=0.0):
    x = (score - a) * slope
    if x > 60.0:
        return 1.0
    if x < -60.0:
        return 0.0
    return 1.0 / (1.0 + math.exp(-x))


def _win_rate_params_for_phase(game_phase, family, cfg):
    if family == 'dl':
        anchor = cfg.council_wr_scale_dl
        early  = cfg.council_wr_scale_dl_early
        late   = cfg.council_wr_scale_dl_late
        offset = cfg.council_wr_offset_dl
    else:
        anchor = cfg.council_wr_scale_nnue
        early  = cfg.council_wr_scale_nnue_early
        late   = cfg.council_wr_scale_nnue_late
        offset = cfg.council_wr_offset_nnue
    if game_phase is None:
        return anchor, 0.0
    prog = _game_phase_for_phase_council(game_phase, cfg.council_nyugyoku_dl_restore)
    prog = 0.0 if prog < 0.0 else 1.0 if prog > 1.0 else prog
    slope_eff = early + (late - early) * prog
    if slope_eff < 1e-6:
        slope_eff = 1e-6
    return slope_eff, offset * prog



def _council_wr_discount_core(dl_score, nnue_score, cfg, game_phase=None):
    if dl_score is None or nnue_score is None:
        return 1.0, None, None
    _sl_dl, _a_dl = _win_rate_params_for_phase(game_phase, 'dl', cfg)
    _sl_nn, _a_nn = _win_rate_params_for_phase(game_phase, 'nnue', cfg)
    win_rate_dl = _cp_to_winrate(dl_score, _sl_dl, game_phase=game_phase, a=_a_dl)
    win_rate_nnue = _cp_to_winrate(nnue_score, _sl_nn, game_phase=game_phase, a=_a_nn)
    win_rate_diff = abs(win_rate_dl - win_rate_nnue)
    discount = max(cfg.council_wr_discount_min,
                   1.0 - win_rate_diff * cfg.council_wr_discount_scale)
    return discount, win_rate_dl, win_rate_nnue


def _council_maxmin_tiebreak_core(votes, winner, claimed_wr_lists, tie_margin):
    if not tie_margin or tie_margin <= 0 or not votes or winner not in votes:
        return None
    top_w = votes[winner]
    band = [m for m, w in votes.items()
            if m == winner or 1e-9 < top_w - w < tie_margin]
    if len(band) < 2:
        return None
    if not all(claimed_wr_lists.get(m) for m in band):
        return None
    worst = {m: min(claimed_wr_lists[m]) for m in band}
    best = max(band, key=lambda m: worst[m])
    if best != winner and worst[best] > worst[winner] + 1e-12:
        return best
    return None


def _council_override_source_core(winner, nnue_top, dl_top, dl_2_top,
                                  book_seed_move, mm_flipped):
    if nnue_top and winner != nnue_top:
        override = True
        if winner == dl_top and winner == dl_2_top:
            source = "dl1+dl2"
        elif winner == dl_top:
            source = "dl1"
        elif winner == dl_2_top:
            source = "dl2"
        elif winner == book_seed_move:
            source = "book_seed"
        else:
            source = None
    else:
        override = False
        source = None
    if mm_flipped and override:
        source = "maxmin"
    return override, source


def _council_score_discount_core(dl_top_score, dl_2_top_score, nnue_score_cp,
                                 dl_2_top_depth, cfg, game_phase=None):
    disc_dl1, win_rate_dl_val, win_rate_nnue_val = _council_wr_discount_core(
        dl_top_score, nnue_score_cp, cfg, game_phase=game_phase)
    disc_dl2, win_rate_dl2_val, win_rate_nnue_for_dl2 = _council_wr_discount_core(
        dl_2_top_score, nnue_score_cp, cfg, game_phase=game_phase)
    w_dl2_saturation_guard = 1.0
    if (dl_2_top_depth is None
            and win_rate_dl2_val is not None and win_rate_nnue_for_dl2 is not None
            and win_rate_dl2_val >= 0.95 and win_rate_nnue_for_dl2 >= 0.95
            and disc_dl2 >= 0.95):
        w_dl2_saturation_guard = 0.85
    return (disc_dl1, win_rate_dl_val, win_rate_nnue_val,
            disc_dl2, win_rate_dl2_val, win_rate_nnue_for_dl2, w_dl2_saturation_guard)


def _council_claimed_wr_max_core(dl_top, dl_top_score, dl_2_top, dl_2_top_score,
                                 nnue_top, nnue_score_cp, game_phase, cfg):
    claimed = {}
    for _mv, _sc, _fam in ((dl_top,   dl_top_score,   'dl'),
                           (dl_2_top, dl_2_top_score, 'dl'),
                           (nnue_top, nnue_score_cp,  'nnue')):
        if _mv is None or _sc is None:
            continue
        _sl, _a = _win_rate_params_for_phase(game_phase, _fam, cfg)
        _win_rate = _cp_to_winrate(_sc, _sl, game_phase=game_phase, a=_a)
        if _mv not in claimed or _win_rate > claimed[_mv]:
            claimed[_mv] = _win_rate
    return claimed


def _council_wr_lists_core(dl_top, dl_top_score, dl_2_top, dl_2_top_score,
                           nnue_top, nnue_score_cp, game_phase, cfg):
    lists = {}
    for _mv, _sc, _fam in ((dl_top,   dl_top_score,   'dl'),
                           (dl_2_top, dl_2_top_score, 'dl'),
                           (nnue_top, nnue_score_cp,  'nnue')):
        if _mv is None or _sc is None:
            continue
        _sl, _a = _win_rate_params_for_phase(game_phase, _fam, cfg)
        lists.setdefault(_mv, []).append(_cp_to_winrate(_sc, _sl, game_phase=game_phase, a=_a))
    return lists


def _council_correlation_dampen_core(w_dl2, dl_top, dl_2_top, nnue_top,
                                     win_rate_dl1, win_rate_dl2, dampen, win_rate_scale):
    if dampen <= 0.0:
        return w_dl2
    if dl_top is None or dl_2_top is None or dl_top != dl_2_top:
        return w_dl2
    if not nnue_top or nnue_top == dl_top:
        return w_dl2
    if win_rate_dl1 is None or win_rate_dl2 is None:
        return w_dl2
    _scale = win_rate_scale if win_rate_scale > 1e-9 else 1.0
    affinity = 1.0 - min(1.0, abs(float(win_rate_dl1) - float(win_rate_dl2)) / _scale)
    if affinity <= 0.0:
        return w_dl2
    keep = 1.0 - min(0.5, dampen) * affinity
    return w_dl2 * keep


def _council_vote(dl_top, dl_2_top, nnue_top, ply=0,
                  dl_top_depth=None, dl_2_top_depth=None,
                  dl_pv_overlap=None, dl_top_score=None,
                  nnue_score_cp=None,
                  score_gap=None,
                  dl_2_weight_override=None,
                  stale_withdraw=False,
                  win_rate_discount_holder=None,
                  dl_2_top_score=None,
                  game_phase=None,
                  cfg=None,
                  nnue_vote_weight=None,
                  game_phase_surge_dl_boost=1.0,
                  book_seed_move=None,
                  book_seed_weight=0.0,
                  game_phase_policy_dir=0,
                  cand_game_phase_delta=None,
                  game_phase_policy_vote_weight=1.0,
                  game_phase_policy_holder=None):
    if stale_withdraw and dl_top is not None:
        _dlog("[COUNCIL-VOTE] stale_withdraw: dl_top=%s suppressed" % dl_top)
        dl_top = None

    _nyug_restore = cfg.council_nyugyoku_dl_restore
    _game_phase_for_pw = (_game_phase_for_phase_council(game_phase, _nyug_restore)
                  if game_phase is not None else 0.0)
    if game_phase is not None and game_phase > 1.0 and _nyug_restore > 0.0:
        _dlog(f"[NYUG-DLR] game_phase={game_phase:.3f} (入玉域) → phase座標 {_game_phase_for_pw:.3f} へ"
              f"折り返し (restore={_nyug_restore:.2f}) — DL 信頼回復")
    _phase_enable  = cfg.council_phase_enable
    _w1_early      = cfg.dl1_weight_early
    _w1_late       = cfg.dl1_weight_late
    _w2_early      = cfg.dl2_weight_early
    _w2_late       = cfg.dl2_weight_late
    if _phase_enable:
        w_dl1 = _calc_phase_weight_game_phase(_game_phase_for_pw, _w1_early, _w1_late)
        w_dl2 = _calc_phase_weight_game_phase(_game_phase_for_pw, _w2_early, _w2_late)
    else:
        w_dl1 = 1.0
        w_dl2 = 1.0

    _dt_dl1 = 1.0
    if dl_top_depth is not None:
        _dt_dl1 = _calc_dl_depth_trust(dl_top_depth, cfg=cfg)
    _dl_consensus_vs_nnue = (dl_top is not None and dl_2_top is not None
                              and dl_top == dl_2_top
                              and nnue_top is not None and dl_top != nnue_top)
    if _dl_consensus_vs_nnue and _dt_dl1 < 1.0:
        _dt_dl1 = math.sqrt(_dt_dl1)
    w_dl1 *= _dt_dl1

    _w_dl2_depth_trust = 1.0
    if dl_2_top_depth is not None:
        _w_dl2_depth_trust = _calc_dl_depth_trust(dl_2_top_depth, cfg=cfg)
    if _dl_consensus_vs_nnue and _w_dl2_depth_trust < 1.0:
        _w_dl2_depth_trust = math.sqrt(_w_dl2_depth_trust)

    _pt_dl1 = _calc_dl_phase_trust(_game_phase_for_pw, cfg=cfg, score_gap=score_gap)
    if _dl_consensus_vs_nnue and _pt_dl1 < 1.0:
        _pt_dl1 = math.sqrt(_pt_dl1)
    w_dl1 *= _pt_dl1

    if dl_pv_overlap is not None:
        w_dl1 *= _calc_dl_pv_overlap_boost(dl_pv_overlap, cfg=cfg)

    if game_phase_surge_dl_boost > 1.0 and dl_top is not None:
        w_dl1 *= game_phase_surge_dl_boost
        _dlog(f"[GP-SURGE③] DL weight ×{game_phase_surge_dl_boost:.3f} → w_dl1={w_dl1:.3f}")

    (_disc_dl1, _win_rate_dl_val, _win_rate_nnue_val,
     _disc_dl2, _win_rate_dl2_val, _win_rate_nnue_for_dl2,
     _w_dl2_saturation_guard) = _council_score_discount_core(
        dl_top_score, dl_2_top_score, nnue_score_cp, dl_2_top_depth, cfg, game_phase=game_phase)
    _two_dl_consensus = (
        dl_top is not None and dl_2_top is not None and dl_top == dl_2_top
        and _win_rate_dl_val is not None and _win_rate_dl2_val is not None
        and abs(_win_rate_dl_val - _win_rate_dl2_val) < max(0.0, cfg.council_corr_wr_scale)
    )
    if _two_dl_consensus:
        if _disc_dl1 < 1.0:
            _disc_dl1 = math.sqrt(_disc_dl1)
        if _disc_dl2 < 1.0:
            _disc_dl2 = math.sqrt(_disc_dl2)
    if _dt_dl1 >= cfg.auftragstaktik_dt_threshold and _disc_dl1 < 1.0:
        _disc_dl1 = math.sqrt(_disc_dl1)
    if _disc_dl1 != 1.0:
        w_dl1 *= _disc_dl1

    if win_rate_discount_holder is not None:
        try:
            win_rate_discount_holder.value = (_disc_dl1, _win_rate_dl_val, _win_rate_nnue_val,
                                        _disc_dl2, _win_rate_dl2_val)
        except (AttributeError, TypeError):
            pass

    if dl_top is not None:
        w_dl1 = _apply_weight_floor(w_dl1, game_phase=game_phase, cfg=cfg)
    if dl_2_top is not None:
        if dl_2_weight_override is not None:
            try:
                _w2e_eff = max(_w2_early, 1e-9)
                w_dl2 = dl_2_weight_override * (w_dl2 / _w2e_eff)
            except Exception:
                w_dl2 = dl_2_weight_override
        if _disc_dl2 != 1.0:
            w_dl2 *= _disc_dl2
        if _w_dl2_depth_trust != 1.0:
            w_dl2 *= _w_dl2_depth_trust
            _dlog(f"[COUNCIL-VOTE] DL_2/DL_3 depth_trust ×{_w_dl2_depth_trust:.3f} "
                  f"(depth={dl_2_top_depth}) → w_dl2={w_dl2:.3f}")
        if _w_dl2_saturation_guard != 1.0:
            w_dl2 *= _w_dl2_saturation_guard
            _dlog(f"[COUNCIL-VOTE] DL_2/DL_3 saturation_guard ×{_w_dl2_saturation_guard:.3f} "
                  f"(depth unknown, both WR≥0.95) → w_dl2={w_dl2:.3f}")
        w_dl2 = _council_correlation_dampen_core(
            w_dl2, dl_top, dl_2_top, nnue_top, _win_rate_dl_val, _win_rate_dl2_val,
            cfg.council_corr_dampen, cfg.council_corr_wr_scale)
        w_dl2 = _apply_weight_floor(w_dl2, game_phase=game_phase, cfg=cfg)

    if cfg is not None and game_phase is not None:
        _inv_floor = _calc_weight_floor_gp(
            game_phase, cfg.council_weight_floor_early, cfg.council_weight_floor_late)
    else:
        _inv_floor = _COUNCIL_WEIGHT_FLOOR
    if dl_top is not None and 0 < w_dl1 < _inv_floor - 1e-9:
        _dlog(f"[COUNCIL-INVARIANT] w_dl1={w_dl1:.4f} < floor={_inv_floor:.4f} — 層順序異常。再適用")
        w_dl1 = _inv_floor
    if dl_2_top is not None and 0 < w_dl2 < _inv_floor - 1e-9:
        _dlog(f"[COUNCIL-INVARIANT] w_dl2={w_dl2:.4f} < floor={_inv_floor:.4f} — 層順序異常。再適用")
        w_dl2 = _inv_floor

    _ho_fade = 1.0
    if game_phase is not None:
        _ho_threshold = cfg.game_phase_handover_threshold
        _ho_band = cfg.handover_reverse_hysteresis
        if _ho_band > 1e-9 and game_phase > (_ho_threshold - _ho_band):
            _ho_t = min(1.0, max(0.0,
                        (game_phase - (_ho_threshold - _ho_band)) / _ho_band))
            _ho_fade = 0.5 * (1.0 + math.cos(math.pi * _ho_t))
            if dl_top is not None:
                w_dl1 *= _ho_fade
            if dl_2_top is not None:
                w_dl2 *= _ho_fade
            if _ho_fade < 0.99:
                _dlog(f"[HO-FADE] GP={game_phase:.3f} "
                      f"band=[{_ho_threshold - _ho_band:.3f},{_ho_threshold:.3f}] "
                      f"t={_ho_t:.3f} fade={_ho_fade:.3f}")

    votes = {}
    if dl_top is not None:
        votes[dl_top] = votes.get(dl_top, 0.0) + w_dl1
    if dl_2_top is not None:
        votes[dl_2_top] = votes.get(dl_2_top, 0.0) + w_dl2
    w_nnue = 1.0
    if nnue_vote_weight is not None:
        w_nnue = nnue_vote_weight
    if nnue_top:
        votes[nnue_top] = votes.get(nnue_top, 0.0) + w_nnue

    _SEED_DISADV_CP = -50
    if book_seed_move is not None and book_seed_weight > 0.0:
        _seed_backed = (book_seed_move == dl_top
                        or book_seed_move == dl_2_top
                        or book_seed_move == nnue_top)
        _seed_disadv = (nnue_score_cp is not None
                        and nnue_score_cp <= _SEED_DISADV_CP)
        if not _seed_backed and _seed_disadv:
            _dlog(f"[BOOK-COUNCIL] seed={book_seed_move} 棄却 "
                  f"(孤立かつ劣勢 nnue_cp={nnue_score_cp} <= {_SEED_DISADV_CP}) "
                  f"— NNUE にフォールバック")
        elif not _seed_backed:
            _seed_w_cap = max(0.0, min(book_seed_weight, w_nnue * 0.99))
            votes[book_seed_move] = votes.get(book_seed_move, 0.0) + _seed_w_cap
            _dlog(f"[BOOK-COUNCIL] seed={book_seed_move} 孤立 → weight clamp "
                  f"{book_seed_weight:.3f}→{_seed_w_cap:.3f} "
                  f"(w_nnue={w_nnue:.3f}) → votes[{book_seed_move}]="
                  f"{votes[book_seed_move]:.3f}")
        else:
            votes[book_seed_move] = votes.get(book_seed_move, 0.0) + book_seed_weight
            _dlog(f"[BOOK-COUNCIL] seed={book_seed_move} weight={book_seed_weight:.3f} "
                  f"(エンジン裏付けあり) → votes[{book_seed_move}]="
                  f"{votes[book_seed_move]:.3f}")

    if not votes:
        return nnue_top, False, None

    _game_phase_pol_fired = None
    if (game_phase_policy_dir != 0 and cand_game_phase_delta
            and game_phase_policy_vote_weight > 1.0 and len(votes) > 1):
        _game_phase_known = [m for m in votes if m in cand_game_phase_delta]
        if len(_game_phase_known) > 1:
            _game_phase_best = max(_game_phase_known,
                           key=lambda m: game_phase_policy_dir * cand_game_phase_delta[m])
            _game_phase_lo = min(game_phase_policy_dir * cand_game_phase_delta[m] for m in _game_phase_known)
            if game_phase_policy_dir * cand_game_phase_delta[_game_phase_best] > _game_phase_lo + 1e-12:
                votes[_game_phase_best] *= game_phase_policy_vote_weight
                _game_phase_pol_fired = "weight"
                _dlog(f"[GP-POL] ε重み ×{game_phase_policy_vote_weight:.3f} → "
                      f"{_game_phase_best} (dir={game_phase_policy_dir:+d} "
                      f"Δgame_phase={cand_game_phase_delta[_game_phase_best]:+.4f}) "
                      f"votes[{_game_phase_best}]={votes[_game_phase_best]:.3f}")

    winner = max(votes, key=votes.get)

    _tie_opt_enable = True
    _win_rate_valid = True
    _game_phase_tie_claimed_wr = None
    if _tie_opt_enable and _win_rate_valid and len(votes) > 1:
        _top_w = votes[winner]
        _tied = [m for m, w in votes.items() if abs(w - _top_w) <= 1e-9]
        if len(_tied) > 1:
            _claimed_wr = _council_claimed_wr_max_core(
                dl_top, dl_top_score, dl_2_top, dl_2_top_score,
                nnue_top, nnue_score_cp, game_phase, cfg)
            if all(_mv in _claimed_wr for _mv in _tied):
                _game_phase_tie_claimed_wr = _claimed_wr
                _opt = max(_tied, key=lambda _mv: _claimed_wr[_mv])
                if _opt != winner and _claimed_wr[_opt] > _claimed_wr[winner]:
                    _dlog(f"[MONJU-OPT] 同点票 {_tied} (w={_top_w:.3f}) → 楽観合議: "
                          f"{winner} (WR={_claimed_wr[winner]:.3f}) を "
                          f"{_opt} (WR={_claimed_wr[_opt]:.3f}) で置換")
                    winner = _opt

    if game_phase_policy_dir != 0 and cand_game_phase_delta and len(votes) > 1:
        _game_phase_top_w = votes[winner]
        _game_phase_tied = [m for m, w in votes.items() if abs(w - _game_phase_top_w) <= 1e-9]
        if len(_game_phase_tied) > 1 and all(m in cand_game_phase_delta for m in _game_phase_tied):
            _game_phase_wr_resolved = False
            if (_game_phase_tie_claimed_wr is not None
                    and all(m in _game_phase_tie_claimed_wr for m in _game_phase_tied)):
                _game_phase_wrs = sorted((_game_phase_tie_claimed_wr[m] for m in _game_phase_tied),
                                 reverse=True)
                _game_phase_wr_resolved = (len(_game_phase_wrs) > 1
                                   and _game_phase_wrs[0] > _game_phase_wrs[1] + 1e-9)
            if not _game_phase_wr_resolved:
                _game_phase_pref = max(_game_phase_tied,
                               key=lambda m: game_phase_policy_dir * cand_game_phase_delta[m])
                if (_game_phase_pref != winner
                        and game_phase_policy_dir * cand_game_phase_delta[_game_phase_pref]
                            > game_phase_policy_dir * cand_game_phase_delta[winner] + 1e-12):
                    _dlog(f"[GP-POL] 同点票 {_game_phase_tied} (w={_game_phase_top_w:.3f}) → "
                          f"GP方向タイブレーク (dir={game_phase_policy_dir:+d}): "
                          f"{winner} (Δgame_phase={cand_game_phase_delta[winner]:+.4f}) を "
                          f"{_game_phase_pref} (Δgame_phase={cand_game_phase_delta[_game_phase_pref]:+.4f}) で置換")
                    winner = _game_phase_pref
                    _game_phase_pol_fired = "tiebreak"

    if game_phase_policy_holder is not None:
        try:
            game_phase_policy_holder.value = _game_phase_pol_fired
        except (AttributeError, TypeError):
            pass

    if cfg.maxmin_tie_margin > 0.0 and _win_rate_valid and len(votes) > 1:
        _mm_wr_lists = _council_wr_lists_core(
            dl_top, dl_top_score, dl_2_top, dl_2_top_score,
            nnue_top, nnue_score_cp, game_phase, cfg)
        _mm_new = _council_maxmin_tiebreak_core(
            votes, winner, _mm_wr_lists, cfg.maxmin_tie_margin)
        if _mm_new is not None:
            _dlog(f"[MAXMIN] 接戦票 (margin<{cfg.maxmin_tie_margin:.3f}) → "
                  f"max-min: {winner} "
                  f"(worst={min(_mm_wr_lists[winner]):.3f}) を {_mm_new} "
                  f"(worst={min(_mm_wr_lists[_mm_new]):.3f}) で置換")
            winner = _mm_new
            _mm_flipped = True
        else:
            _mm_flipped = False
    else:
        _mm_flipped = False

    _council_override, _council_override_source = _council_override_source_core(
        winner, nnue_top, dl_top, dl_2_top, book_seed_move, _mm_flipped)

    return winner, _council_override, _council_override_source


_CSM_WR_SLOPE = 0.004
_CSM_TIGHTNESS_SLOPE = math.log(3) / 25.0
_CSM_INSTABILITY_SLOPE = math.log(3) / 30.0

_REGIME_EMA_ALPHA               = 0.20
_REGIME_CRUISE_THRESHOLD        = 0.65
_REGIME_CRISIS_THRESHOLD        = 0.35
_REGIME_COLLAPSE_THRESHOLD      = 0.15
_REGIME_CRUISE_EFF_S_SCALE      = 0.85
_REGIME_CRUISE_CS_DEPTH_SCALE   = 0.70
_REGIME_CRISIS_EFF_S_BOOST      = 1.25
_REGIME_ALERT_TONSHI_KP_REDUCE  = 1
_REGIME_CRISIS_TONSHI_KP_REDUCE = 2
_REGIME_CONVICTION_RAW_W_CONF    = 0.55
_REGIME_CONVICTION_RAW_W_CLARITY = 0.25
_REGIME_CONVICTION_RAW_W_AGREE   = 0.20


def _regime_conviction_raw(confidence, sharpness, council_agree):
    c = 0.5 if confidence is None else float(confidence)
    s = 0.5 if sharpness is None else float(sharpness)
    clarity = 1.0 - s
    agree = 1.0 if council_agree else 0.0
    raw = (_REGIME_CONVICTION_RAW_W_CONF * c
         + _REGIME_CONVICTION_RAW_W_CLARITY * clarity
         + _REGIME_CONVICTION_RAW_W_AGREE * agree)
    return max(0.0, min(1.0, raw))


def _regime_classify(conviction, force_crisis):
    if force_crisis:
        return "crisis"
    if conviction >= _REGIME_CRUISE_THRESHOLD:
        return "cruise"
    if conviction <= _REGIME_CRISIS_THRESHOLD:
        return "crisis"
    return "alert"


def _regime_update_ema(gps, confidence, sharpness, council_agree):
    try:
        raw = _regime_conviction_raw(confidence, sharpness, council_agree)
        prev = gps.regime_conviction
        new = (1.0 - _REGIME_EMA_ALPHA) * prev + _REGIME_EMA_ALPHA * raw
        gps.regime_conviction_prev = prev
        gps.regime_conviction = new
        collapse = (prev - new) >= _REGIME_COLLAPSE_THRESHOLD
        if collapse:
            gps.regime_force_crisis = True
        gps.regime_label = _regime_classify(new, gps.regime_force_crisis)
        gps.regime_force_crisis = False
        _r = gps.regime_label
        if _r == "cruise":
            _DLPONDER_STATE["regime_cruise_count"] = int(_DLPONDER_STATE.get("regime_cruise_count", 0)) + 1
        elif _r == "crisis":
            _DLPONDER_STATE["regime_crisis_count"] = int(_DLPONDER_STATE.get("regime_crisis_count", 0)) + 1
        else:
            _DLPONDER_STATE["regime_alert_count"] = int(_DLPONDER_STATE.get("regime_alert_count", 0)) + 1
        if collapse:
            _DLPONDER_STATE["regime_collapse_count"] = int(_DLPONDER_STATE.get("regime_collapse_count", 0)) + 1
        return collapse
    except Exception as _ze:
        _flog(f"[REGIME-EMA] update failed: {_ze!r}")
        return False


def _compute_confidence(winner, dl_top, dl_2_top, nnue_top, nnue_score_cp,
                        *, dl_gap_cp=None, dl_spread_cp=None,
                        time_aggression_ratio=None):
    voices = [v for v in (dl_top, dl_2_top, nnue_top) if v is not None]
    if not voices:
        return 0.0
    agree = sum(1 for v in voices if v == winner)
    n = len(voices)
    agreement = (agree / n) * min(1.0, n / 3.0)
    _DLPONDER_STATE["csm_compute_total"] += 1
    if n == 2:
        _DLPONDER_STATE["csm_voices_n2"] += 1
    elif n == 1:
        _DLPONDER_STATE["csm_voices_n1"] += 1
    if dl_spread_cp is None and (dl_gap_cp is None or dl_gap_cp < 0):
        _DLPONDER_STATE["csm_conf_unknown"] += 1
    if dl_spread_cp is not None:
        dl_certainty = max(0.0, 1.0 - dl_spread_cp / 80.0)
    elif dl_gap_cp is not None and dl_gap_cp >= 0:
        dl_certainty = min(1.0, dl_gap_cp / 50.0)
    else:
        dl_certainty = 0.5
    if time_aggression_ratio is not None and time_aggression_ratio > 0:
        ease = max(0.0, min(1.0, 1.5 - time_aggression_ratio))
    else:
        cp = abs(nnue_score_cp or 0)
        ease = abs(2.0 * _cp_to_winrate(cp, _CSM_WR_SLOPE) - 1.0)
    return 0.50 * agreement + 0.25 * dl_certainty + 0.25 * ease


def _compute_sharpness(*, dl_spread_cp=None, dl_gap_cp=None,
                        dl_top=None, nnue_top=None, nnue_score_cp=None,
                        score_gap_dl_nnue=None):
    if dl_spread_cp is not None:
        instability = 2.0 * _cp_to_winrate(dl_spread_cp, _CSM_INSTABILITY_SLOPE) - 1.0
    else:
        instability = 0.5
    if dl_gap_cp is not None and dl_gap_cp >= 0:
        tightness = 2.0 * (1.0 - _cp_to_winrate(dl_gap_cp, _CSM_TIGHTNESS_SLOPE))
    else:
        tightness = 0.5
    if nnue_score_cp is None:
        closeness = 0.5
    else:
        cp = abs(int(nnue_score_cp))
        closeness = 1.0 - abs(2.0 * _cp_to_winrate(cp, _CSM_WR_SLOPE) - 1.0)
    if score_gap_dl_nnue is not None:
        disagree = 2.0 * _cp_to_winrate(score_gap_dl_nnue, _CSM_WR_SLOPE) - 1.0
    elif dl_top is not None and nnue_top is not None:
        disagree = 0.0 if dl_top == nnue_top else 1.0
    else:
        disagree = 0.5
    _shp = 0.30 * instability + 0.25 * tightness + 0.25 * closeness + 0.20 * disagree
    if _shp >= 0.65:
        _DLPONDER_STATE["csm_sharp_difficult"] += 1
    elif _shp <= 0.30:
        _DLPONDER_STATE["csm_sharp_clear"] += 1
    if dl_spread_cp is None and (dl_gap_cp is None or dl_gap_cp < 0):
        _DLPONDER_STATE["csm_sharp_unknown"] += 1
    if nnue_score_cp is None:
        _DLPONDER_STATE["csm_sharp_nnue_score_none"] += 1
    return _shp


def _compute_momentum(*, score_cp=None, prev_score_cp=None,
                       game_phase=None, prev_game_phase=None,
                       council_agree_streak=0,
                       tesuki_n=None):
    if score_cp is not None and prev_score_cp is not None:
        score_trend = max(-1.0, min(1.0, (score_cp - prev_score_cp) / 200.0))
    else:
        score_trend = 0.0
    if game_phase is not None and prev_game_phase is not None:
        gp_delta = game_phase - prev_game_phase
        gp_push = max(-1.0, min(1.0, gp_delta * 5.0))
    else:
        gp_push = 0.0
    streak_calm = max(-1.0, min(1.0, (council_agree_streak - 2.5) / 2.5))
    base = 0.45 * score_trend + 0.35 * gp_push + 0.20 * streak_calm
    if tesuki_n is not None and tesuki_n <= 2:
        base -= max(0.0, 1.0 - tesuki_n / 3.0)
    return max(-1.0, min(1.0, base))


_CSM_INHERIT = object()


def _apply_csm_and_regime(ctx, nnue_info, final_move, *,
                          dl_top=None, dl_2_top=None, nnue_top=None,
                          nnue_score_cp=None, dl_gap_cp=None,
                          dl_spread_cp=None, score_gap_dl_nnue=None,
                          ta_ratio=None, game_phase=None,
                          regime_voices=None, label="",
                          sharpness_dl_top=_CSM_INHERIT):
    _sharp_dl = dl_top if sharpness_dl_top is _CSM_INHERIT else sharpness_dl_top
    try:
        nnue_info["confidence"] = _compute_confidence(
            final_move, dl_top, dl_2_top, nnue_top, nnue_score_cp,
            dl_gap_cp=dl_gap_cp, dl_spread_cp=dl_spread_cp,
            time_aggression_ratio=ta_ratio)
        nnue_info["sharpness"] = _compute_sharpness(
            dl_spread_cp=dl_spread_cp, dl_gap_cp=dl_gap_cp,
            dl_top=_sharp_dl, nnue_top=nnue_top,
            nnue_score_cp=nnue_score_cp,
            score_gap_dl_nnue=score_gap_dl_nnue)
        nnue_info["momentum"] = _compute_momentum(
            score_cp=nnue_score_cp, prev_score_cp=ctx.gps.last_nnue_score_cp,
            game_phase=game_phase, prev_game_phase=ctx.gps.last_game_phase,
            council_agree_streak=ctx.gps.council_agree_streak,
            tesuki_n=ctx.gps.last_tesuki_n)
        ctx.gps.last_momentum = nnue_info["momentum"]
        ctx.gps.last_sharpness = nnue_info["sharpness"]
        if regime_voices is not None:
            _regime_agree = bool(all(v for v in regime_voices)
                                and len(set(regime_voices)) == 1)
            _regime_collapse = _regime_update_ema(
                ctx.gps, nnue_info.get("confidence"),
                nnue_info.get("sharpness"), _regime_agree)
            nnue_info["regime_conviction"] = ctx.gps.regime_conviction
            nnue_info["regime_label"]     = ctx.gps.regime_label
            nnue_info["regime_collapse"]   = _regime_collapse
    except Exception as _met_e:
        _flog(f"[METRICS-{label}] compute failed: {_met_e!r}")


_RE_MATE         = re.compile(r"score mate (-?\d+)")
_RE_SCORE_CP     = re.compile(r"score cp (-?\d+)")
_RE_DEPTH        = re.compile(r"\bdepth\s+(\d+)")
_RE_NODES        = re.compile(r"\bnodes\s+(\d+)")
_RE_PV_FIRST     = re.compile(r" pv (\d[a-z]\d[a-z]\+?|[A-Z]\*\d[a-z])")
_RE_PV_FULL      = re.compile(
    r" pv ((?:\d[a-z]\d[a-z]\+?|[A-Z]\*\d[a-z])"
    r"(?:\s+(?:\d[a-z]\d[a-z]\+?|[A-Z]\*\d[a-z]))*)"
)
_RE_SELDEPTH     = re.compile(r"\bseldepth\s+(\d+)")
_RE_BESTMOVE     = re.compile(r"bestmove\s+(\S+)")
_RE_BESTMOVE_PONDER = re.compile(r"bestmove\s+\S+\s+ponder\s+(\S+)")
_RE_BTIME        = re.compile(r"btime\s+(\d+)")
_RE_WTIME        = re.compile(r"wtime\s+(\d+)")
_RE_BINC         = re.compile(r"binc\s+(\d+)")
_RE_WINC         = re.compile(r"winc\s+(\d+)")
_RE_BYOYOMI      = re.compile(r"byoyomi\s+(\d+)")
_RE_SETOPTION    = re.compile(r"setoption name (\S+) value (.+)")
_RE_SFEN_STM     = re.compile(r"\bsfen\s+\S+\s+([bw])\b")


def _run_dl_1_search(dl_1, position_cmd, n, nodes, timeout,
                        collect_extended=False, eff_s=None,
                        movetime_ms=None, live_depth_holder=None,
                        live_policy_cb=None):
    if not dl_1._alive:
        return {}, {}, {}, {}, False

    if dl_1._last_multipv_sent != n:
        dl_1.send(f"setoption name MultiPV value {n}")
        dl_1._last_multipv_sent = n

    dl_1.send(position_cmd)
    dl_1.send(f"go nodes {int(nodes)}")

    moves_scores  = {}
    pv_lines      = {}
    depth_best    = {}
    score_hist    = {}
    mate_detected = False
    _got_bestmove = False
    _early_stop_sent = False

    _DRAIN_ALLOWANCE_S = min(2.0, eff_s * 0.2) if eff_s is not None else 2.0
    _search_timeout = timeout
    if movetime_ms is not None:
        _search_timeout = min(_search_timeout, movetime_ms / 1000.0 + 0.5)
    _wall_start = time.perf_counter()
    _lp_last_emit = 0.0
    for line in dl_1.read_until("bestmove", timeout=_search_timeout):
        if "bestmove" in line:
            _got_bestmove = True
        mm = _RE_MATE.search(line)
        if mm and int(mm.group(1)) > 0:
            mate_detected = True

        if not _early_stop_sent and not mate_detected:
            if movetime_ms is not None and (
                (time.perf_counter() - _wall_start) * 1000.0 >= movetime_ms
            ):
                try:
                    dl_1.send("stop")
                    _early_stop_sent = True
                    _dlog(
                        "[DL2-WALLCLOCK] movetime %.0fms 経過 — stop 送信 "
                        "(node 上限到達前に時間で打ち切り)" % movetime_ms
                    )
                except Exception as _fe:
                    _flog(f"[ignored] {__file__}: wallclock stop: {_fe}")
            else:
                nm = _RE_NODES.search(line)
                if nm and int(nm.group(1)) >= nodes:
                    try:
                        dl_1.send("stop")
                        _early_stop_sent = True
                    except Exception as _fe:
                        _flog(f"[ignored] {__file__}:3261: {_fe}")

        if "multipv" not in line or " pv " not in line:
            if " pv " not in line or not line.startswith("info"):
                continue

        score = 0
        sm = _RE_SCORE_CP.search(line)
        if sm:
            score = int(sm.group(1))
        if mm:
            score = 30000 if int(mm.group(1)) > 0 else -30000

        if collect_extended:
            pv_m = _RE_PV_FULL.search(line)
            if not pv_m:
                continue
            pv_moves = pv_m.group(1).split()
            root_move = pv_moves[0]
        else:
            pv_m = _RE_PV_FIRST.search(line)
            if not pv_m:
                continue
            root_move = pv_m.group(1)

        moves_scores[root_move] = score

        if collect_extended:
            dm = _RE_DEPTH.search(line)
            depth = int(dm.group(1)) if dm else 0
            if live_depth_holder is not None:
                live_depth_holder[0] = (root_move, depth)
            score_hist.setdefault(root_move, []).append((depth, score))
            if depth > depth_best.get(root_move, -1):
                depth_best[root_move] = depth
                pv_lines[root_move]   = pv_moves
        if live_policy_cb is not None:
            _now_lp = time.perf_counter()
            if _now_lp - _lp_last_emit >= 0.25:
                _lp_last_emit = _now_lp
                try:
                    live_policy_cb(sorted(moves_scores.items(),
                                          key=lambda kv: kv[1], reverse=True))
                except Exception:
                    pass

    if not _got_bestmove and dl_1._alive:
        _drain_budget = _DRAIN_ALLOWANCE_S
        _dlog(f"fetch timeout — flush_with_stop {dl_1.name} "
              f"(drain_budget={_drain_budget:.1f}s)")
        if not dl_1.flush_with_stop(timeout=_drain_budget):
            _dlog(f"{dl_1.name} did not return readyok within {_drain_budget:.1f}s — "
                  f"next fetch may see residual output")

    return moves_scores, pv_lines, depth_best, score_hist, mate_detected

def _run_dl_3_search(dl_3, position_cmd, n, movetime_ms, timeout,
                     collect_extended=False, eff_s=None):
    if not dl_3._alive:
        return {}, {}, {}, {}, False

    if dl_3._last_multipv_sent != n:
        dl_3.send(f"setoption name MultiPV value {n}")
        dl_3._last_multipv_sent = n

    dl_3.send(position_cmd)
    dl_3.send(f"go movetime {int(movetime_ms)}")

    moves_scores  = {}
    pv_lines      = {}
    depth_best    = {}
    score_hist    = {}
    mate_detected = False
    _got_bestmove = False

    _DRAIN_ALLOWANCE_S = min(2.0, eff_s * 0.2) if eff_s is not None else 2.0

    for line in dl_3.read_until("bestmove", timeout=timeout):
        if "bestmove" in line:
            _got_bestmove = True

        mm = _RE_MATE.search(line)
        if mm and int(mm.group(1)) > 0:
            mate_detected = True

        if "multipv" not in line or " pv " not in line:
            if " pv " not in line or not line.startswith("info"):
                continue

        score = 0
        sm = _RE_SCORE_CP.search(line)
        if sm:
            score = int(sm.group(1))
        if mm:
            score = 30000 if int(mm.group(1)) > 0 else -30000

        if collect_extended:
            pv_m = _RE_PV_FULL.search(line)
            if not pv_m:
                continue
            pv_moves = pv_m.group(1).split()
            root_move = pv_moves[0]
        else:
            pv_m = _RE_PV_FIRST.search(line)
            if not pv_m:
                continue
            root_move = pv_m.group(1)

        moves_scores[root_move] = score

        if collect_extended:
            dm = _RE_DEPTH.search(line)
            depth = int(dm.group(1)) if dm else 0
            score_hist.setdefault(root_move, []).append((depth, score))
            if depth > depth_best.get(root_move, -1):
                depth_best[root_move] = depth
                pv_lines[root_move]   = pv_moves

    if not _got_bestmove and dl_3._alive:
        _drain_budget = _DRAIN_ALLOWANCE_S
        _dlog(f"fetch timeout — flush_with_stop {dl_3.name} "
              f"(drain_budget={_drain_budget:.1f}s)")
        if not dl_3.flush_with_stop(timeout=_drain_budget):
            _dlog(f"{dl_3.name} did not return readyok within {_drain_budget:.1f}s — "
                  f"next fetch may see residual output")

    return moves_scores, pv_lines, depth_best, score_hist, mate_detected





def _prefetch_flush(dl_1, label="dl_1", eff_s=None):
    if not dl_1._alive:
        return 0
    if eff_s is not None and eff_s > 0:
        _dl_budget_s = eff_s * _tdg.dl_time_ratio
        timeout = max(0.05, min(0.2, _dl_budget_s * 0.5))
    else:
        timeout = 0.2

    try:
        _pre_drained = 0
        while True:
            try:
                _pln = dl_1._q.get(block=False)
            except queue.Empty:
                break
            if _pln is None:
                _dlog("[PRE-FLUSH] %s: sentinel during pre-drain (%d lines)"
                      % (label, _pre_drained))
                return _pre_drained
            _pre_drained += 1

        dl_1.send("stop")
        dl_1.send("isready")
        drained = _pre_drained
        t0 = time.perf_counter()
        empty_streak = 0
        while True:
            _remaining = timeout - (time.perf_counter() - t0)
            if _remaining <= 0:
                break
            _get_wait = min(0.05, _remaining)
            try:
                ln = dl_1._q.get(timeout=_get_wait)
            except queue.Empty:
                empty_streak += 1
                if empty_streak >= 3:
                    _dlog("[PRE-FLUSH] %s: queue.Empty x%d — breaking"
                          % (label, empty_streak))
                    break
                continue
            empty_streak = 0
            if ln is None:
                _dlog("[PRE-FLUSH] %s: sentinel (engine dead)" % label)
                break
            if "readyok" in ln:
                if _pre_drained > 5:
                    _dlog("[PRE-FLUSH] %s: pre-drained %d stale line(s), "
                          "readyok in %.3fs"
                          % (label, _pre_drained,
                             time.perf_counter() - t0))
                return drained
            drained += 1

        _dlog("[PRE-FLUSH] %s: timeout (%.2fs) after %d line(s) "
              "(pre-drained=%d)"
              % (label, time.perf_counter() - t0, drained, _pre_drained))
        return drained
    except Exception as e:
        _dlog("[PRE-FLUSH] %s: error %s %s" % (label, type(e).__name__, e))
        return 0


def fetch_dl_policy(dl_1, position_cmd, n, nodes, timeout=60.0, gap_min=None, eff_s=None, movetime_ms=None, use_dl3=False, cfg=None, live_depth_holder=None, live_policy_cb=None):
    if cfg is None:
        cfg = EngineConfig.from_cfg(_cfg)

    _t_flush_start = time.perf_counter()
    _prefetch_flush(dl_1, label="dl_1-pre-fetch", eff_s=eff_s)
    _flush_elapsed = time.perf_counter() - _t_flush_start
    if _flush_elapsed > 0.01:
        _remaining_timeout = max(0.05, timeout - _flush_elapsed)
    else:
        _remaining_timeout = timeout

    _timeout_limit_s = timeout * 0.8
    if eff_s is not None and eff_s > 0:
        _dl_budget_s   = eff_s * _tdg.dl_time_ratio
        _flush_limit_s = min(_dl_budget_s * 0.8, _timeout_limit_s)
    else:
        _flush_limit_s = _timeout_limit_s
    if _flush_elapsed >= _flush_limit_s:
        _dlog(
            "[PRE-FLUSH] elapsed=%.3fs >= limit=%.3fs (dl_budget=%s timeout=%.3fs) "
            "— skipping DL fetch (nnue-only fallback)"
            % (_flush_elapsed, _flush_limit_s,
               ("%.3fs" % (eff_s * _tdg.dl_time_ratio)) if (eff_s and eff_s > 0) else "N/A",
               timeout)
        )
        return None

    if use_dl3:
        _dl3_movetime_ms = int(_remaining_timeout * 0.85 * 1000)
        moves_scores, pv_lines, depth_best, score_hist, mate_detected = (
            _run_dl_3_search(dl_1, position_cmd, n, _dl3_movetime_ms, _remaining_timeout,
                             collect_extended=True, eff_s=eff_s)
        )
    else:
        moves_scores, pv_lines, depth_best, score_hist, mate_detected = (
            _run_dl_1_search(dl_1, position_cmd, n, nodes, _remaining_timeout,
                                collect_extended=True, eff_s=eff_s,
                                movetime_ms=movetime_ms,
                                live_depth_holder=live_depth_holder,
                                live_policy_cb=live_policy_cb)
        )

    ranked = sorted(moves_scores.items(), key=lambda x: x[1], reverse=True)
    result = ranked[:n]

    actual_gap = (result[0][1] - result[1][1]) if len(result) >= 2 else None

    _effective_gap_min = gap_min if gap_min is not None else _calc_dl_score_gap_min(0.0, cfg=cfg)
    _glcfg = cfg
    _lift_abstain, _lift_spread, _lift_reason = _dl_gap_lift_decision_core(
        actual_gap, _effective_gap_min, result, score_hist, _glcfg)
    if _lift_reason == "lifted":
        _dlog(
            f"[GAP-LIFT] gap={actual_gap} < threshold={_effective_gap_min} "
            f"but top1_score={result[0][1]} >= {_glcfg.dl_gap_lift_score_min} "
            f"and spread={_lift_spread} <= {_glcfg.dl_gap_lift_spread_max} "
            f"— abstention REVOKED (high-conviction fallback)"
        )
    elif _lift_reason == "unstable":
        _dlog(
            f"[GAP-LIFT] gap={actual_gap} < threshold={_effective_gap_min} "
            f"top1_score={result[0][1]} >= {_glcfg.dl_gap_lift_score_min} "
            f"but spread={_lift_spread} > {_glcfg.dl_gap_lift_spread_max} — not lifted"
        )
    if _lift_abstain:
        _dlog(f"DL gap {actual_gap} < threshold {_effective_gap_min} - skipping filter (extended)")
        return [], mate_detected, actual_gap, pv_lines, depth_best, score_hist

    if result and result[0][0] in score_hist:
        hist = score_hist[result[0][0]]
        if len(hist) >= 2:
            scores_only = [s for _, s in hist]
            spread = max(scores_only) - min(scores_only)
            _dlog(f"[C] top={result[0][0]} score_spread={spread} "
                  f"depth_best={depth_best.get(result[0][0], 0)} "
                  f"iterations={len(hist)}")

    return result, mate_detected, actual_gap, pv_lines, depth_best, score_hist


def _score_stability(score_hist, move):
    hist = score_hist.get(move, [])
    if len(hist) < 2:
        return 0
    scores = [s for _, s in hist]
    return max(scores) - min(scores)


def _dl_gap_lift_decision_core(actual_gap, effective_gap_min, result, score_hist, cfg):
    if not (effective_gap_min > 0 and actual_gap is not None
            and actual_gap < effective_gap_min):
        return False, None, "pass"
    if (result
            and result[0][1] >= cfg.dl_gap_lift_score_min):
        _spread = _score_stability(score_hist, result[0][0]) if score_hist else 9999
        if _spread <= cfg.dl_gap_lift_spread_max:
            return False, _spread, "lifted"
        return True, _spread, "unstable"
    return True, None, "no_lift"


def _dl_conviction_trigger_core(dl_score, nnue_score_cp, dl2_alive,
                                remaining_ms, cfg,
                                dl_top_vote=None, nnue_top_vote=None):
    _dispute = (nnue_top_vote is None) or (dl_top_vote != nnue_top_vote)
    return bool(
        dl2_alive
        and remaining_ms > 200
        and dl_score is not None
        and nnue_score_cp is not None
        and dl_score >= cfg.dl_conviction_score_threshold_cp
        and (dl_score - int(nnue_score_cp)) >= cfg.dl_conviction_score_gap_cp
        and _dispute
    )


def _dl_conviction_wait_s_core(remaining_eff_ms, cfg, safety_ms=200.0,
                               dl_2_remaining_ms=None):
    safe_wait_ms = max(0.0, remaining_eff_ms - safety_ms)
    if dl_2_remaining_ms is not None and dl_2_remaining_ms > 0 and safe_wait_ms > 0:
        _dl2_aware_wait_ms = min(
            max(safe_wait_ms, dl_2_remaining_ms),
            safe_wait_ms * 1.5
        )
        safe_wait_ms = _dl2_aware_wait_ms
    wait_s = min(cfg.dl_conviction_council_wait_ms, safe_wait_ms) / 1000.0
    return wait_s, wait_s > 0.05, safe_wait_ms


def _dl_conviction_withdraw_core(dl_score, nnue_score_cp, cfg):
    return bool(
        dl_score is not None
        and nnue_score_cp is not None
        and (
            dl_score < cfg.dl_conviction_score_threshold_cp
            or (dl_score - int(nnue_score_cp)) < cfg.dl_conviction_score_gap_cp
        )
    )


def _dl_conviction_mate_core(council_override, dl_top_vote, nnue_top_vote,
                             mate_detected, cfg):
    return bool(
        not council_override
        and dl_top_vote is not None
        and dl_top_vote != (nnue_top_vote or "")
        and mate_detected
    )


def _lc_dispatch_core(is_infinite, endgame_mode, dl1_alive,
                      cur_game_phase, handover_game_phase, book_active,
                      dl_timeout_s, eff_s, dl3_alive, cfg):
    _handover_open = (cur_game_phase < handover_game_phase or book_active)
    use_dl = bool(
        not is_infinite
        and not endgame_mode
        and dl1_alive
        and _handover_open
    )
    threshold_s = cfg.dl_time_min_ms / 1000.0
    use_light_council = bool(
        not is_infinite
        and not endgame_mode
        and _handover_open
        and cfg.light_council_enable
        and dl_timeout_s < threshold_s
        and eff_s >= cfg.light_council_min_eff_s
        and dl3_alive
    )
    if use_light_council:
        use_dl = False
    reason = ("light_council" if use_light_council
              else "council" if use_dl
              else "endgame")
    return use_dl, use_light_council, threshold_s, reason


def _lc_dl3_timeout_s_core(eff_s, time_aggression_ratio, cfg):
    return max(0.05, min(
        cfg.light_council_dl3_timeout_s,
        eff_s * cfg.light_council_dl3_timeout_per_s / 1000.0 * time_aggression_ratio,
    ))


def _lc_proxy_gate_core(proxy_enable, nnue_top_vote, dl3_alive,
                        eff_s, rescue_eff_s_min):
    return bool(
        proxy_enable
        and nnue_top_vote is not None
        and dl3_alive
        and eff_s >= rescue_eff_s_min
    )


def _lc_fallback_move_core(nnue_top_vote, seed_move, seed_weight):
    final_move = nnue_top_vote or "resign"
    if (seed_move is not None
            and seed_weight > 0.0
            and seed_move != "resign"):
        w_nnue = 1.0 if (nnue_top_vote and nnue_top_vote != "resign") else 0.0
        if seed_weight > w_nnue:
            return seed_move, w_nnue, "seed"
        return final_move, w_nnue, "nnue"
    return final_move, None, ("endgame" if nnue_top_vote else "resign")


def _lc_prefetch_gate_core(dl_timeout_s, cfg):
    threshold_s = cfg.dl_time_min_ms / 1000.0
    return dl_timeout_s < threshold_s, threshold_s


def _pv_overlap_count(pv_lines, top_move, n_top=3):
    if not pv_lines or top_move not in pv_lines:
        return 0
    top_pv = pv_lines[top_move]
    if len(top_pv) < 2:
        return 0
    ref_next = top_pv[1]
    count = 0
    compared = 0
    for move, pv in pv_lines.items():
        if move == top_move:
            continue
        if compared >= n_top - 1:
            break
        if len(pv) >= 2 and pv[1] == ref_next:
            count += 1
        compared += 1
    return count


_RE_USI_MOVE_STRICT = re.compile(r"\d[a-z]\d[a-z]\+?|[A-Z]\*\d[a-z]")


def _multi_ponder_alt_reply(pv_lines, our_move, primary_reply):
    if not pv_lines or not our_move or not primary_reply:
        return None
    pv = pv_lines.get(our_move)
    if pv and len(pv) >= 2 and pv[1] and pv[1] != primary_reply:
        if _RE_USI_MOVE_STRICT.fullmatch(pv[1]):
            return pv[1]
    for _alt_mv, _alt_pv in pv_lines.items():
        if _alt_mv == our_move:
            continue
        if (_alt_pv and len(_alt_pv) >= 2 and _alt_pv[1]
                and _alt_pv[1] != primary_reply
                and _RE_USI_MOVE_STRICT.fullmatch(_alt_pv[1])):
            return _alt_pv[1]
    return None


def _override_ponder_core(final_move, pv_lines):
    if not final_move or final_move in ("resign", "win"):
        return None
    if not pv_lines:
        return None
    pv = pv_lines.get(final_move)
    if not pv or len(pv) < 2:
        return None
    cand = pv[1]
    if not isinstance(cand, str) or _RE_USI_MOVE_STRICT.fullmatch(cand) is None:
        return None
    return cand


_SFEN_HEADER_RE = re.compile(r"\bsfen\s+\S+\s+([bw])\s+\S+\s+(\d+)")

def _count_moves(position_cmd):
    head, sep, tail = position_cmd.partition(" moves ")
    n_moves = len(tail.split()) if sep else 0

    m = _SFEN_HEADER_RE.search(head)
    if not m:
        return n_moves
    stm, move_n = m.group(1), int(m.group(2))
    plies_anchor = (move_n - 1) + ((stm == "b") != ((move_n - 1) % 2 == 0))
    return plies_anchor + n_moves

def _position_after_move(position_cmd, move):
    if "moves" in position_cmd:
        return position_cmd + " " + move
    return position_cmd + " moves " + move

def _position_after_moves(position_cmd, moves):
    filtered = [mv for mv in moves if mv]
    if not filtered:
        return position_cmd
    suffix = " ".join(filtered)
    if "moves" in position_cmd:
        return position_cmd + " " + suffix
    return position_cmd + " moves " + suffix


class Prefetcher:
    def __init__(self):
        self._lock        = threading.Lock()
        self._pos         = None
        self._result      = None
        self._src         = None
        self._dl_2_results = {}
        self._dl_1_extra_results = {}
        self._generation  = 0
        self.dl_1_lock = threading.Lock()
        self._dl_1     = None
        self._dl_2_ref = None
        self._dl_3_result = None
        self._dl_3_ref    = None
        self._dl_3_shared_lock = None
        self._dl_3_lock   = threading.Lock()

    def start(self, dl_1, position_cmd, n, nodes, timeout=None,
              dl_2=None, dl_2_lock=None,
              dl_2_opponent_turn_pos=None, prefetch_top_n=1,
              dl_3=None, dl_3_lock=None):
        with self._lock:
            if self._pos == position_cmd:
                return
            self._pos       = position_cmd
            self._result    = None
            self._dl_2_results = {}
            self._dl_1_extra_results = {}
            self._dl_1   = dl_1
            self._dl_2_ref = dl_2 if (dl_2 is not None and dl_2_lock is not None) else None
            self._dl_3_result = None
            self._dl_3_ref    = dl_3 if (dl_3 is not None and dl_3._alive) else None
            self._dl_3_shared_lock = dl_3_lock
            self._generation += 1
            my_gen = self._generation
        _ptimeout = timeout if timeout is not None else (_tdg.dl_time_fallback_ms / 1000.0)

        _opponent_turn_pos = dl_2_opponent_turn_pos
        _top_n        = max(1, int(prefetch_top_n))

        def _run():
            _dlog(f"Prefetch started: {position_cmd[:80]}")
            with self.dl_1_lock:
                with self._lock:
                    if self._generation != my_gen:
                        return

                r = _dl1_fetch_repack(position_cmd, nodes, "prefetch_none_dl1")
                if r is None:
                    return
                policy = r[0]; mate = r[1]
            with self._lock:
                if self._generation == my_gen and self._pos == position_cmd:
                    self._result = r
                    self._src    = "prefetch"
                    _dlog(f"Prefetch done: moves={[mv for mv,_ in policy]} mate={mate} gap={_gap}")


            if _dl_prefetch_idp_nodes > nodes and policy:
                with self.dl_1_lock:
                    with self._lock:
                        if self._generation != my_gen:
                            return
                    r2 = _dl1_fetch_repack(position_cmd, _dl_prefetch_idp_nodes, "prefetch_none_idp")
                    if r2 is None:
                        return
                with self._lock:
                    if self._generation == my_gen and self._pos == position_cmd:
                        self._result = r2
                        self._src    = "prefetch"
                        _dlog(f"Prefetch IDP done: top={r2[0][0][0] if r2[0] else None} nodes={_dl_prefetch_idp_nodes}")

            if dl_2 is None or dl_2_lock is None:
                return
            with self._lock:
                if self._generation != my_gen:
                    return
            if not dl_2._alive:
                return

            dl_2_positions_ordered = [position_cmd]

            def _dl1_fetch_repack(pos, fetch_nodes, counter_key):
                raw = fetch_dl_policy(
                    dl_1, pos, n, fetch_nodes,
                    timeout=_ptimeout, gap_min=None
                )
                if raw is None:
                    _DLPONDER_STATE[counter_key] = int(_DLPONDER_STATE.get(counter_key, 0)) + 1
                    _flog(f"[ignored] prefetch _run: {counter_key} fetch returned None "
                          f"(cumulative={_DLPONDER_STATE[counter_key]})")
                    return None
                pol, mt, gp, _pv, dp, hs = raw
                return (pol, mt, gp, dp, hs)

            def _do_dl_2_prefetch(pos):
                with self._lock:
                    if self._generation != my_gen:
                        return False
                if not dl_2._alive:
                    return False
                _dlog(f"DL_2 prefetch started: {pos[:80]}")
                with self._lock:
                    if self._generation != my_gen:
                        return False
                with dl_2_lock:
                    with self._lock:
                        if self._generation != my_gen:
                            return False
                    _flush_timeout = min(_tdg.dl_2_time_max_ms / 1000.0 + 6.0, 30.0)
                    _drain_ok = dl_2.flush_with_stop(timeout=_flush_timeout)
                    if not _drain_ok:
                        _dlog("DL_2 prefetch: flush_until_ready timeout — skipping")
                        return False
                    with self._lock:
                        if self._generation != my_gen:
                            return False
                    _d2_raw = fetch_dl_policy(
                        dl_2, pos, 1,
                        _dl_2_node_budget(_time_aggression_dyn_ratio(
                            _tdg.time_aggression_dl_dyn, _time_aggression_base, hi=1.2)),
                        timeout=_ptimeout, gap_min=None
                    )
                    if _d2_raw is not None:
                        _d2_policy, _d2_mate, _d2_gap, _d2_pv, _d2_depth, _d2_hist = _d2_raw
                        r2_local = (_d2_policy, _d2_mate, _d2_gap, _d2_depth, _d2_hist)
                    else:
                        r2_local = None
                with self._lock:
                    if self._generation == my_gen:
                        self._dl_2_results[pos] = r2_local
                        _d2_top = (r2_local[0][0][0] if (r2_local and r2_local[0]) else None)
                        _dlog(f"DL_2 prefetch done: pos={pos[:60]} top={_d2_top}")
                        return True
                return False

            _ok_main = _do_dl_2_prefetch(position_cmd)
            if not _ok_main:
                return

            if _top_n <= 1 or _opponent_turn_pos is None:
                return

            with self._lock:
                if self._generation != my_gen:
                    return

            _mini_top_n_moves = []
            try:
                with self.dl_1_lock:
                    with self._lock:
                        if self._generation != my_gen:
                            return
                    _moves_scores, _, _, _, _mate2 = _run_dl_1_search(
                        dl_1, _opponent_turn_pos, _top_n, nodes,
                        timeout=_ptimeout, collect_extended=False,
                    )
                _ranked = sorted(_moves_scores.items(), key=lambda kv: -kv[1])
                _mini_top_n_moves = [mv for mv, _ in _ranked[:_top_n]]
                _dlog(f"[G] top-N derivation: {_mini_top_n_moves} (mate={_mate2})")
            except Exception as e:
                _dlog(f"[G] top-N derivation failed: {e} — keeping single-position prefetch")
                return

            for mv in _mini_top_n_moves:
                if len(dl_2_positions_ordered) >= _top_n:
                    break
                _candidate = _position_after_move(_opponent_turn_pos, mv)
                if _candidate in dl_2_positions_ordered:
                    continue
                dl_2_positions_ordered.append(_candidate)

            for extra_pos in dl_2_positions_ordered[1:]:
                with self._lock:
                    if self._generation != my_gen:
                        _dlog("[G] cancel() detected — aborting remaining extras")
                        return
                _ok_extra = _do_dl_2_prefetch(extra_pos)
                if not _ok_extra:
                    _dlog(f"[G] DL_2 prefetch for extra {extra_pos[:60]} skipped/failed")

                if _ok_extra and _dl_prefetch_idp_nodes > nodes:
                    with self.dl_1_lock:
                        with self._lock:
                            if self._generation != my_gen:
                                return
                        _j_r = _dl1_fetch_repack(extra_pos, _dl_prefetch_idp_nodes, "prefetch_none_jext")
                        if _j_r is None:
                            return
                    with self._lock:
                        if self._generation == my_gen:
                            self._dl_1_extra_results[extra_pos] = _j_r
                            _dlog(f"[J] DL_1 IDP extra done: pos={extra_pos[:60]} "
                                  f"top={_j_r[0][0][0] if _j_r[0] else None} nodes={_dl_prefetch_idp_nodes}")

            with self._lock:
                if self._generation != my_gen:
                    return
            try:
                if _ranked and len(_ranked) >= 2:
                    _voi_scores = [sc for _, sc in _ranked[:_top_n]]
                    _voi_norm = float(_cfg.get("Voi_Norm_Cp", 600)) or 600.0
                    _pf_max_voi = min(1.0, max(0.0, (max(_voi_scores) - min(_voi_scores)) / _voi_norm))
                else:
                    _pf_max_voi = 0.0
            except Exception:
                _pf_max_voi = 0.0
            _cfg_park_nodes = int(
                _params.get("POLICY_NODES", 2000)
            )
            _park_nodes = _root_park_budget_core(
                _cfg_park_nodes, _pf_max_voi,
                float(_cfg.get("Root_Park_VOI_Scale", 0.0)),
            )
            if _park_nodes != _cfg_park_nodes:
                _dlog(f"[PF-2] ROOT-PARK nodes adjusted: {_cfg_park_nodes} -> {_park_nodes} (voi={_pf_max_voi:.3f})")
            _ok_park = _do_dl_2_prefetch(_opponent_turn_pos)
            _dlog(f"[ROOT-PARK] DL_2 tree parked at opponent-turn root (ok={_ok_park})")

            if dl_3 is not None and dl_3._alive:
                def _dl_3_run():
                    with self._lock:
                        if self._generation != my_gen:
                            return
                    _t_dl3 = time.perf_counter()
                    _shared = self._dl_3_shared_lock
                    _shared_held = False
                    if _shared is not None:
                        _shared_held = _shared.acquire(timeout=5.0)
                        if not _shared_held:
                            _dlog("[DL_3] prefetch: dl_3_lock 取得タイムアウト — prefetch スキップ")
                            return
                    try:
                        try:
                            _prefetch_flush(dl_3, label="dl_3-prefetch-pre", eff_s=None)
                            _dl3_raw = fetch_dl_policy(
                                dl_3, position_cmd, 1, _dl_3_effective_nodes,
                                timeout=60.0, gap_min=0,
                                use_dl3=True,
                            )
                            _dl3_policy = _dl3_raw[0] if (_dl3_raw and _dl3_raw[0]) else None
                        except Exception as _e3:
                            _dlog(f"[DL_3] prefetch fetch error: {_e3}")
                            _dl3_policy = None
                    finally:
                        if _shared_held:
                            _shared.release()
                    _dl3_elapsed = int((time.perf_counter() - _t_dl3) * 1000)
                    with self._lock:
                        if self._generation == my_gen and self._pos == position_cmd:
                            self._dl_3_result = _dl3_policy
                            _dlog(
                                f"[DL_3] prefetch done: pos={position_cmd!r:.60s} "
                                f"policy={'ok' if _dl3_policy else 'empty'} "
                                f"elapsed={_dl3_elapsed}ms"
                            )
                        else:
                            _dlog(
                                f"[DL_3] prefetch STALE (gen mismatch): "
                                f"pos={position_cmd!r:.60s} elapsed={_dl3_elapsed}ms"
                            )
                threading.Thread(target=_dl_3_run, daemon=True, name="dl_3_prefetch").start()

        threading.Thread(target=_run, daemon=True).start()

    def get(self, position_cmd):
        with self._lock:
            r1, r2, r3, r1_src = None, None, None, None
            _pos_matched = (self._pos == position_cmd)
            if _pos_matched and self._result is not None:
                r1 = self._result
                r1_src = self._src
                self._pos    = None
                self._result = None
                self._src    = None
            if position_cmd in self._dl_2_results:
                r2 = self._dl_2_results.pop(position_cmd)
            if _pos_matched:
                r3 = self._dl_3_result
                self._dl_3_result = None
            return r1, r2, r3, r1_src

    def peek_dl_1(self, position_cmd):
        with self._lock:
            if self._pos == position_cmd and self._result is not None:
                return self._result
            return None

    def inject_dl_1(self, position_cmd, result):
        with self._lock:
            self._pos    = position_cmd
            self._result = result
            self._src    = "ponder"

    def inject_dl_2(self, position_cmd, result):
        with self._lock:
            self._dl_2_results[position_cmd] = result

    def get_dl_1_extra(self, position_cmd):
        with self._lock:
            return self._dl_1_extra_results.pop(position_cmd, None)

    def cancel(self):
        with self._lock:
            self._pos         = None
            self._result      = None
            self._src         = None
            self._dl_2_results = {}
            self._dl_1_extra_results = {}
            self._dl_3_result = None
            self._generation += 1
            fk  = self._dl_1
            f2k = self._dl_2_ref
            f3k = self._dl_3_ref
            self._dl_3_ref = None
        if fk is not None and fk._alive:
            fk.send("stop")
        if f2k is not None and f2k._alive:
            try:
                f2k.send("stop")
            except Exception as _fe:
                _flog(f"[ignored] {__file__}:4010: {_fe}")
        if f3k is not None and f3k._alive:
            try:
                f3k.send("stop")
            except Exception as _fe:
                _flog(f"[ignored] {__file__}:4019: {_fe}")
            def _dl3_async_flush(eng=f3k):
                try:
                    eng.flush_until_ready(timeout=3.0)
                except Exception as _fe:
                    _flog(f"[ignored] {__file__}:4024: {_fe}")
            threading.Thread(target=_dl3_async_flush, daemon=True,
                             name="dl3_cancel_flush").start()


_DUR_EMA_LOCK = threading.Lock()

class _DurationEma:
    __slots__ = ("_s", "_n", "_max_s", "_warmup")
    def __init__(self, max_elapsed=60.0, warmup=2):
        self._s, self._n = {}, {}
        self._max_s, self._warmup = max_elapsed, warmup
    def update(self, key, elapsed_s):
        if elapsed_s is None or elapsed_s <= 0 or elapsed_s > self._max_s:
            return
        with _DUR_EMA_LOCK:
            prev = self._s.get(key)
            self._s[key] = float(elapsed_s) if prev is None else 0.8 * prev + 0.2 * float(elapsed_s)
            self._n[key] = self._n.get(key, 0) + 1
    def get(self, key, fallback_s):
        with _DUR_EMA_LOCK:
            if self._n.get(key, 0) >= self._warmup:
                v = self._s.get(key)
                if v and v > 0:
                    return float(v)
        return float(fallback_s)

_dur_stop_rt    = _DurationEma(max_elapsed=30.0, warmup=3)
_dur_cold_start = _DurationEma(max_elapsed=60.0, warmup=2)
_dur_quit       = _DurationEma(max_elapsed=60.0, warmup=2)

def _dur_update_stop_rt(elapsed_s):  _dur_stop_rt.update(None, elapsed_s)
def _dur_get_stop_rt(fallback_s):    return _dur_stop_rt.get(None, fallback_s)
def _dur_update_cold_start(slot, elapsed_s): _dur_cold_start.update(slot, elapsed_s)
def _dur_get_cold_start(slot, fallback_s):   return _dur_cold_start.get(slot, fallback_s)
def _dur_update_quit(kind, elapsed_s): _dur_quit.update(kind, elapsed_s)


def _stop_drain_timeout_safe(ctx, eff_s_hint=None) -> float:
    _eff = float(eff_s_hint or 0.0)
    if _eff <= 0:
        try:
            _pc = ctx.ps.ponder_clock if ctx is not None and getattr(ctx, "ps", None) else None
            if _pc is not None and getattr(_pc, "eff_s", 0.0) and _pc.eff_s > 0:
                _eff = float(_pc.eff_s)
        except Exception:
            pass
    _ov = _move_overhead_s
    try:
        _emar = _dur_get_stop_rt(_ov)
    except Exception:
        _emar = _ov
    if _eff > 0:
        return min(3.0, max(_ov, _eff / 3.0, _emar))
    return min(3.0, max(_ov, _emar))


def _make_dl1_multipv_cb(ctx, pos):
    try:
        _pb = _board_for_position(pos) if pos else None
    except Exception:
        _pb = None
    _scores = {}
    _last_emit = [0.0]
    def _cb(ln, _ctx=ctx):
        if _ctx.current_position != pos:
            return
        if " pv " not in ln:
            return
        _pm = _RE_PV_FULL.search(ln)
        if not _pm:
            return
        _root = _pm.group(1).split()[0]
        if _pb is not None and not _bestmove_is_for_board(_root, _pb):
            return
        _sc = 0
        _sm = _RE_SCORE_CP.search(ln)
        if _sm:
            _sc = int(_sm.group(1))
        else:
            _mm = _RE_MATE.search(ln)
            if _mm:
                _sc = 30000 if int(_mm.group(1)) > 0 else -30000
        _dm = _RE_DEPTH.search(ln)
        _dep = int(_dm.group(1)) if _dm else 0
        _prev = _scores.get(_root)
        if _prev is None or _dep >= _prev[1]:
            _scores[_root] = (_sc, _dep)
        _pol = sorted(((mv, sd[0]) for mv, sd in _scores.items()), key=lambda t: -t[1])
        if _LIVE._ready():
            _LIVE.update_think_pv(policy=_pol, pos=pos)
        else:
            _now = time.monotonic()
            if _now - _last_emit[0] >= 0.25:
                _last_emit[0] = _now
                try:
                    print("info string dl_live_policy "
                          + json.dumps([(m, round(float(sc), 4))
                                        for m, sc in _pol[:10]]), flush=True)
                except Exception:
                    pass
    return _cb


def _endgame_dl3_display_fetch(ctx, eff_s):
    if not _cfg_bool("Endgame_DL3_MultiPV_Display", True):
        return
    if ctx.dl_3 is not None and ctx.dl_3._alive:
        _eng, _lock = ctx.dl_3, ctx.dl_3_lock
    elif (ctx.dl_2 is not None and ctx.dl_2._alive
            and ctx.dl_2_lock is not None):
        _eng, _lock = ctx.dl_2, ctx.dl_2_lock
    else:
        return
    _pos = ctx.current_position
    _eff = eff_s if (eff_s and eff_s > 0) else 2.0

    def _run():
        if not _lock.acquire(blocking=False):
            _dlog("[EG-DL3-MULTIPV] %s lock busy — display fetch skipped" % _eng.name)
            return
        try:
            _eng._live_info_cb = _make_dl1_multipv_cb(ctx, _pos)
            try:
                _n = max(2, int(_cfg.get("Endgame_DL3_MultiPV_N", 5)))
            except Exception:
                _n = 5
            _to = max(0.4, min(2.5, _eff * 0.35))
            _r = fetch_dl_policy(_eng, _pos, _n, _dl_3_effective_nodes,
                                 timeout=_to, eff_s=_eff, use_dl3=True)
            if _r and _r[0]:
                if _LIVE._ready() and ctx.current_position == _pos:
                    try:
                        _LIVE.update_think_pv(policy=_r[0], pos=_pos)
                    except Exception:
                        pass
                try:
                    print("info string dl_live_policy "
                          + json.dumps([(m, round(float(sc), 4))
                                        for m, sc in _r[0][:10]]), flush=True)
                except Exception:
                    pass
        except Exception as _e:
            _dlog(f"[EG-DL3-MULTIPV] display fetch failed: {_e!r}")
        finally:
            try:
                _eng._live_info_cb = None
            except Exception:
                pass
            _lock.release()

    threading.Thread(target=_run, daemon=True, name="eg-dl3-multipv").start()


def _make_live_think_cb(ctx, handler, position, *, mode=None,
                        game_phase=None, game_phase_delta=None):
    if not _LIVE._ready():
        return None
    _LIVE.set_think({"game_phase": game_phase, "game_phase_delta": game_phase_delta},
                    position, mode=mode, live=True)
    def _cb(score_cp, depth, pv):
        _LIVE.update_think_pv(pv=pv, score_cp=score_cp, pos=position)
    return _cb


def relay_until_bestmove(eng, timeout=120, intercept_bestmove=False,
                          partial_pv_holder=None, eff_s=None,
                          slow_mover_opts=None, full_pv_holder=None,
                          partial_pv_depth_holder=None, pv_head_event=None,
                          remaining_ms=None, floor_ms=None,
                          kill_on_empty=True, go_clock=None,
                          live_info_cb=None):
    if go_clock is not None:
        if eff_s is None:
            eff_s = go_clock.eff_s
        if remaining_ms is None:
            remaining_ms = go_clock.remaining_ms
        if floor_ms is None:
            floor_ms = go_clock.floor_ms
    _relay_binding_layer = None
    if eff_s is not None and eff_s > 0:
        _sm_opts = slow_mover_opts if slow_mover_opts is not None else _nnue_1_opts
        _slow_mover_val = float(_sm_opts.get("SlowMover", "146"))
        _relay_factor = min(1.25, max(1.05, _slow_mover_val / 200.0 * 1.25))
        _relay_cap = eff_s * _relay_factor
        _relay_binding_layer = "eff_s*factor"
        _relay_min_floor = max(_move_overhead_s, min(eff_s, 2.0 * _move_overhead_s))
        if _relay_cap < _relay_min_floor:
            _relay_cap = _relay_min_floor
            _relay_binding_layer = "MO_floor"
        _rem_ceiling = None
        if remaining_ms is not None and remaining_ms > 0:
            _rem_ceiling = max(1.0, remaining_ms / 1000.0 - _move_overhead_s)
            if _relay_cap > _rem_ceiling:
                _flog(
                    f"relay cap clamped by remaining: {_relay_cap:.2f}s -> "
                    f"{_rem_ceiling:.2f}s (remaining={remaining_ms}ms "
                    f"overhead={_move_overhead_ms}ms eff_s={eff_s:.2f})"
                )
                _relay_cap = _rem_ceiling
                _relay_binding_layer = "remaining_ms"
        if (remaining_ms is not None and remaining_ms == 0
                and floor_ms is not None and floor_ms > 0):
            _inc_ceiling = max(_move_overhead_s, floor_ms / 1000.0)
            if _relay_cap > _inc_ceiling:
                _flog(
                    f"relay cap clamped by inc (remaining=0): {_relay_cap:.2f}s -> "
                    f"{_inc_ceiling:.2f}s (floor_ms={floor_ms}ms eff_s={eff_s:.2f})"
                )
                _relay_cap = _inc_ceiling
                _relay_binding_layer = "floor_ms"
        if timeout < _relay_cap:
            _relay_binding_layer = "caller_timeout"
        timeout = min(timeout, _relay_cap)
        _dlog(f"relay cap: {timeout:.2f}s (binding={_relay_binding_layer} "
              f"eff_s={eff_s:.2f} factor={_relay_factor:.3f} "
              f"MO_floor={_relay_min_floor:.2f}"
              + (f" rem_ceil={_rem_ceiling:.2f}" if _rem_ceiling is not None else "")
              + ")")
    ponder_move = None
    nnue_info   = {"bestmove": "", "score_cp": 0, "depth": 0, "seldepth": 0,
                   "relay_binding_layer": _relay_binding_layer,
                   "scored_info_seen": False,
                   "book_info_seen": False,
                   "relay_elapsed_s": 0.0}
    _best_depth = -1
    _caller     = threading.current_thread().name
    _t_start    = time.perf_counter()
    _last_hb    = _t_start
    _HB_INTERVAL = 5.0
    _lines_read  = 0

    _deadline = time.perf_counter() + timeout

    def _ctx(extra=""):
        return (
            f"  caller={_caller}"
            f"  elapsed={time.perf_counter()-_t_start:.1f}s"
            f"  lines={_lines_read}"
            + extra
        )

    while True:
        _remaining = _deadline - time.perf_counter()
        if _remaining <= 0:
            _flog(
                f"relay_until_bestmove: TIMEOUT"
                + _ctx(
                    f"  intercept={intercept_bestmove}"
                    f"  alive={eng._alive}"
                    f"  q={eng._q.qsize() if hasattr(eng,'_q') else 'n/a'}"
                    f"  best_score={nnue_info.get('score_cp', 'n/a')}"
                    f"  best_depth={nnue_info.get('depth', 'n/a')}"
                )
            )
            if eng._alive:
                _flog(f"relay_until_bestmove: deadline reached — sending stop to {eng.name}")
                _t_stop_sent = time.perf_counter()
                try:
                    eng.send("stop")
                except Exception as _fe:
                    _flog(f"[ignored] {__file__}:4118: {_fe}")
                _stop_window = 5.0
                if remaining_ms is not None and remaining_ms > 0:
                    _elapsed_main_ms = (time.perf_counter() - _t_start) * 1000.0
                    _rem_after_main_s = (
                        remaining_ms - _elapsed_main_ms
                    ) / 1000.0 - _move_overhead_s
                    _stop_window = max(0.3, min(5.0, _rem_after_main_s))
                    if _stop_window < 5.0:
                        _flog(
                            f"relay_until_bestmove: stop window scaled by remaining: "
                            f"5.00s -> {_stop_window:.2f}s (remaining={remaining_ms}ms "
                            f"overhead={_move_overhead_ms}ms main_elapsed={_elapsed_main_ms:.0f}ms)"
                        )
                elif (remaining_ms is not None and remaining_ms == 0
                        and floor_ms is not None and floor_ms > 0):
                    _elapsed_main_ms = (time.perf_counter() - _t_start) * 1000.0
                    _rem_after_main_s = (floor_ms - _elapsed_main_ms) / 1000.0
                    _stop_window = max(0.3, min(5.0, _rem_after_main_s))
                    if _stop_window < 5.0:
                        _flog(
                            f"relay_until_bestmove: stop window scaled by inc (remaining=0): "
                            f"5.00s -> {_stop_window:.2f}s (floor_ms={floor_ms}ms "
                            f"main_elapsed={_elapsed_main_ms:.0f}ms)"
                        )
                _stop_deadline = time.perf_counter() + _stop_window
                while True:
                    _sr = _stop_deadline - time.perf_counter()
                    if _sr <= 0:
                        break
                    _stop_out = eng.readline(timeout=min(1.0, _sr))
                    if _stop_out is None:
                        break
                    if not _stop_out:
                        continue
                    _lines_read += 1
                    if _stop_out.startswith("info") and "depth" in _stop_out and "score" in _stop_out:
                        nnue_info["scored_info_seen"] = True
                        dm2 = _RE_DEPTH.search(_stop_out)
                        d2 = int(dm2.group(1)) if dm2 else 0
                        if d2 > _best_depth:
                            _best_depth = d2
                            sm2 = _RE_SCORE_CP.search(_stop_out)
                            if sm2:
                                nnue_info["score_cp"] = int(sm2.group(1))
                            else:
                                mm2 = _RE_MATE.search(_stop_out)
                                if mm2:
                                    nnue_info["score_cp"] = 30000 if int(mm2.group(1)) > 0 else -30000
                                    nnue_info["mate_ply"] = int(mm2.group(1))
                            nnue_info["depth"] = d2
                            if full_pv_holder is not None and " pv " in _stop_out:
                                _fpv2 = _RE_PV_FULL.search(_stop_out)
                                if _fpv2:
                                    _fpv2_str = _fpv2.group(1)
                                    _old_pv = full_pv_holder[0]
                                    if _old_pv is None or len(_fpv2_str) >= len(_old_pv):
                                        full_pv_holder[0] = _fpv2_str
                    if not intercept_bestmove and not _stop_out.startswith("bestmove"):
                        if not _suppress_info_print:
                            try:
                                print(_stop_out, flush=True)
                            except OSError:
                                pass
                    if _stop_out.startswith("bestmove"):
                        nnue_info["relay_elapsed_s"] = time.perf_counter() - _t_start
                        _dur_update_stop_rt(time.perf_counter() - _t_stop_sent)
                        parts = _stop_out.split()
                        if len(parts) >= 2:
                            nnue_info["bestmove"] = parts[1]
                        if len(parts) >= 4 and parts[2] == "ponder":
                            ponder_move = parts[3]
                            nnue_info["ponder"] = parts[3]
                        if not intercept_bestmove:
                            if not _suppress_info_print:
                                try:
                                    print(_stop_out, flush=True)
                                except OSError:
                                    pass
                        _flog(f"relay_until_bestmove: stop bestmove={parts[1] if len(parts)>=2 else '?'}")
                        eng._empty_relay_streak = 0
                        break
                else:
                    pass
                if nnue_info["bestmove"]:
                    break
                if not kill_on_empty and eng._alive:
                    _flog(f"relay_until_bestmove: no bestmove after stop — "
                          f"{eng.name} は生存。kill せず空で返す "
                          f"(SP ponderhit idle とみなし呼び出し側で再探索)")
                    break
                _probe_to = max(_move_overhead_s, min(2.0 * _move_overhead_s, _stop_window))
                if eng._alive and eng.flush_until_ready(timeout=_probe_to, max_stale_lines=200):
                    if timeout is not None and timeout >= 2.0:
                        eng._empty_relay_streak = getattr(eng, "_empty_relay_streak", 0) + 1
                    if getattr(eng, "_empty_relay_streak", 0) >= 2:
                        _flog(f"relay_until_bestmove: {eng.name} responsive-idle だが "
                              f"空 relay {eng._empty_relay_streak} 連続 — "
                              f"live-lock とみなし kill (次 go で再起動)")
                        try:
                            _terminate_proc_full(
                                eng.proc, job=getattr(eng, "_job", None),
                                via_shell=getattr(eng, "_via_shell", False),
                                bat_path=getattr(eng, "_bat_path", None),
                                wsl_tag=getattr(eng, "_wsl_tag", None),
                                name=eng.name)
                            eng.proc.wait(timeout=5)
                        except Exception as _ll_kill_e:
                            _flog(f"relay_until_bestmove: livelock kill failed "
                                  f"(non-fatal): {_ll_kill_e}")
                        eng._alive = False
                        eng._empty_relay_streak = 0
                        break
                    _flog(f"relay_until_bestmove: no bestmove after stop but "
                          f"{eng.name} is responsive (isready→readyok, probe={_probe_to:.2f}s) — "
                          f"idle とみなし kill せず温存 (呼び出し側で再探索, "
                          f"empty_streak={eng._empty_relay_streak})")
                    break
                _flog(f"relay_until_bestmove: no bestmove AND unresponsive "
                      f"(isready→readyok 失敗) — killing {eng.name}")
                try:
                    _terminate_proc_full(
                        eng.proc, job=getattr(eng, "_job", None),
                        via_shell=getattr(eng, "_via_shell", False),
                        bat_path=getattr(eng, "_bat_path", None),
                        wsl_tag=getattr(eng, "_wsl_tag", None),
                        name=eng.name)
                    eng.proc.wait(timeout=5)
                except Exception as _kill_e:
                    _flog(f"relay_until_bestmove: kill failed (non-fatal): {_kill_e}")
                eng._alive = False
                _flog(f"{eng.name} killed (unresponsive) — will auto-restart on next go/ponderhit")
            break
        if not eng._alive and eng._q.empty():
            _flog(f"relay_until_bestmove: {eng.name} dead — exit" + _ctx())
            break
        _now = time.perf_counter()
        if _now - _last_hb >= _HB_INTERVAL:
            _flog(
                f"relay_until_bestmove: waiting"
                + _ctx(
                    f"  remaining={_remaining:.1f}s"
                    f"  intercept={intercept_bestmove}"
                    f"  alive={eng._alive}"
                    f"  q={eng._q.qsize() if hasattr(eng,'_q') else 'n/a'}"
                )
            )
            _last_hb = _now
        _rl_timeout = min(5.0, _remaining)
        out = eng.readline(timeout=_rl_timeout)
        if out is None:
            _flog(f"relay_until_bestmove: {eng.name} readline=None (engine died)" + _ctx())
            break
        if not out:
            continue
        _lines_read += 1

        if out.startswith("info") and "depth" in out and "score" in out:
            nnue_info["scored_info_seen"] = True
            dm = _RE_DEPTH.search(out)
            d  = int(dm.group(1)) if dm else 0
            _cur_score = nnue_info["score_cp"]
            _cur_mate_ply = None
            sm = _RE_SCORE_CP.search(out)
            if sm:
                _cur_score = int(sm.group(1))
            else:
                mm = _RE_MATE.search(out)
                if mm:
                    _cur_mate_ply = int(mm.group(1))
                    _cur_score = 30000 if _cur_mate_ply > 0 else -30000
            if d > _best_depth:
                _best_depth = d
                nnue_info["score_cp"] = _cur_score
                if _cur_mate_ply is not None:
                    nnue_info["mate_ply"] = _cur_mate_ply
                nnue_info["depth"] = d
                sdm = _RE_SELDEPTH.search(out)
                if sdm:
                    nnue_info["seldepth"] = int(sdm.group(1))
                if full_pv_holder is not None and " pv " in out:
                    _fpv = _RE_PV_FULL.search(out)
                    if _fpv:
                        full_pv_holder[0] = _fpv.group(1)
            if live_info_cb is not None:
                _pv_for_cb = None
                if " pv " in out:
                    _fpv_cb = _RE_PV_FULL.search(out)
                    if _fpv_cb:
                        _pv_for_cb = _fpv_cb.group(1).split()
                try:
                    live_info_cb(_cur_score, d, _pv_for_cb)
                except Exception:
                    pass

        if out.startswith("info string"):
            _low_bk = out.lower()
            if ("book" in _low_bk
                    or "moves to" in _low_bk
                    or "bookeval" in _low_bk):
                nnue_info["book_info_seen"] = True

        if (partial_pv_holder is not None or partial_pv_depth_holder is not None) \
                and out.startswith("info") and " pv " in out:
            pv_match = _RE_PV_FIRST.search(out)
            if pv_match:
                _pv_head_move = pv_match.group(1)
                if partial_pv_holder is not None:
                    partial_pv_holder[0] = _pv_head_move
                if partial_pv_depth_holder is not None:
                    _dm = _RE_DEPTH.search(out)
                    partial_pv_depth_holder[0] = (
                        _pv_head_move,
                        int(_dm.group(1)) if _dm else 0,
                    )
                if pv_head_event is not None:
                    pv_head_event.set()

        if out.startswith("bestmove"):
            nnue_info["relay_elapsed_s"] = time.perf_counter() - _t_start
            bm = _RE_BESTMOVE.match(out)
            if bm:
                nnue_info["bestmove"] = bm.group(1)
            pm = _RE_BESTMOVE_PONDER.match(out)
            if pm:
                ponder_move = pm.group(1)
                nnue_info["ponder"] = pm.group(1)
            eng._empty_relay_streak = 0
            _flog(
                f"relay_until_bestmove: bestmove received"
                + _ctx(
                    f"  bestmove={nnue_info['bestmove']!r}"
                    f"  intercept={intercept_bestmove}"
                )
            )
            if not intercept_bestmove and not _suppress_info_print:
                try:
                    print(out, flush=True)
                except OSError:
                    pass
            break

        if not _suppress_info_print:
            try:
                print(out, flush=True)
            except OSError:
                pass

    return ponder_move, nnue_info





def _model_size_mb(engine_exe_path, model_relative="eval/model.onnx"):
    try:
        return round(os.path.getsize(
            os.path.join(os.path.dirname(os.path.abspath(engine_exe_path)), model_relative)
        ) / (1024 * 1024), 1)
    except Exception:
        return None



def _decided_thresholds(side):
    if side == "sente":
        return 150, 0
    return 0, -150


def _game_blunder_records_core(game_log, swing_floor_cp, score_cap=29000):
    if swing_floor_cp is None or swing_floor_cp <= 0 or not game_log:
        return []

    def _num(v):
        try:
            return int(v)
        except (TypeError, ValueError):
            return None

    def _clamp(v):
        return max(-score_cap, min(score_cap, v))

    def _verdict(ri):
        if ri.get("council_override"):
            return "override_regret", ri.get("nnue_bestmove")
        if ri.get("endgame_veto_applied"):
            return "veto_regret", ri.get("nnue_bestmove")
        if ri.get("dl_nnue_agree") is False:
            return "dissent_vindicated", ri.get("dl_top_move")
        if ri.get("dl_2_nnue_agree") is False:
            return "dissent_vindicated", ri.get("dl_2_top_move")
        if ri.get("stability_eff_s_boosted") is True:
            return "self_warned", None
        return "blind", None

    records = []
    for i in range(len(game_log) - 1):
        ri, rj = game_log[i], game_log[i + 1]
        if ri.get("decided"):
            continue
        sc_i, sc_j = _num(ri.get("nnue_score_cp")), _num(rj.get("nnue_score_cp"))
        p_i,  p_j  = _num(ri.get("ply")),           _num(rj.get("ply"))
        if sc_i is None or sc_j is None or p_i is None or p_j is None:
            continue
        if p_j - p_i != 2:
            continue
        our_side = _record_side(ri) or ("sente" if p_i % 2 == 0 else "gote")
        win_th, lose_th = _decided_thresholds(our_side)
        if not (lose_th <= sc_i <= win_th):
            continue
        loss = _clamp(sc_i) - _clamp(sc_j)
        if loss >= swing_floor_cp:
            verdict, alt = _verdict(ri)
            records.append({
                "kind": "own", "verdict": verdict, "side": our_side,
                "ply": p_i, "move": ri.get("council_winner"),
                "alt_move": alt,
                "override_source": ri.get("council_override_source"),
                "loss_cp": loss,
                "prev_score": sc_i, "next_score": sc_j, "index": i,
                "indices": {
                    "nnue_depth":          ri.get("nnue_depth"),
                    "eff_s":               ri.get("eff_s"),
                    "dl_stability_spread": ri.get("dl_stability_spread"),
                    "score_swing_nnue":    ri.get("score_swing_nnue"),
                    "score_swing_dl":      ri.get("score_swing_dl"),
                    "dl3_proxy_wr_leaf":   ri.get("dl3_proxy_wr_leaf"),
                    "council_wr_nnue":     ri.get("council_wr_nnue"),
                    "handover_game_phase":         ri.get("handover_game_phase"),
                },
            })
        elif loss <= -swing_floor_cp:
            records.append({
                "kind": "opponent",
                "side": "gote" if our_side == "sente" else "sente",
                "ply": p_i + 1, "move": None,
                "loss_cp": -loss,
                "prev_score": sc_i, "next_score": sc_j, "index": i,
            })
    return records


def _game_summary_counts_core(game_log):
    n_dl    = sum(1 for m in game_log if m.get("dl_used"))
    n_pre   = sum(1 for m in game_log if m.get("prefetch_hit"))
    n_pon   = sum(1 for m in game_log if m.get("dl_cache_src") == "ponder")
    n_agree = sum(1 for m in game_log if m.get("dl_nnue_agree"))
    n_dl_nz = sum(1 for m in game_log if m.get("dl_used") and m.get("dl_top_move"))
    prefetch_rate = round(n_pre / n_dl, 3) if n_dl else None
    ponder_rate   = round(n_pon / n_dl, 3) if n_dl else None
    agree_rate    = round(n_agree / n_dl_nz, 3) if n_dl_nz else None
    return {
        "n_dl": n_dl, "n_pre": n_pre, "n_pon": n_pon,
        "n_agree": n_agree, "n_dl_nz": n_dl_nz,
        "prefetch_rate": prefetch_rate, "ponder_rate": ponder_rate,
        "agree_rate": agree_rate,
    }


