def _handle_replay(ctx, line):
    toks = [t.strip('"') for t in re.findall(r'"[^"]*"|\S+', line)][1:]
    path, game_back, speed = _STATS_PATH, 1, 10.0
    for t in toks:
        if "=" in t:
            k, v = t.split("=", 1)
            try:
                if k == "game":
                    game_back = max(1, int(v))
                elif k == "speed":
                    speed = max(0.01, float(v))
            except ValueError:
                print(f"[replay] 引数を解釈できません: {t}", flush=True)
                return
        else:
            path = t
    try:
        raw = open(path, encoding="utf-8", errors="replace").read().splitlines()
    except OSError as e:
        print(f"[replay] stats を開けません: {e}", flush=True)
        return
    games, cur = [], []
    for ln in raw:
        if ln.startswith("#GAME "):
            games.append(cur)
            cur = []
        else:
            cur.append(ln)
    games.append(cur)
    games = [g for g in games if any(ln.lstrip().startswith("{") for ln in g)]
    if not games:
        print("[replay] 再生可能な対局が見つかりません", flush=True)
        return
    recs = []
    for ln in games[-min(game_back, len(games))]:
        try:
            r = json.loads(ln)
        except Exception:
            continue
        mv = r.get("bestmove") or r.get("move") or r.get("council_winner")
        if isinstance(mv, str) and re.match(r"^[1-9a-zA-Z*+]{4,5}$", mv):
            recs.append((r, mv))
    if not recs:
        print("[replay] 指し手レコードがありません (旧 stats は ts 無しでも再生可)",
              flush=True)
        return
    print(f"[replay] {len(recs)} 手を再生します (speed=x{speed:g})", flush=True)
    moves, prev_ts = [], None
    for r, mv in recs:
        ts = r.get("ts")
        _dt = ((ts - prev_ts) if (prev_ts is not None
                                  and isinstance(ts, (int, float))) else 1.0)
        if moves:
            time.sleep(min(5.0, max(0.05, _dt)) / speed)
        if isinstance(ts, (int, float)):
            prev_ts = ts
        moves.append(mv)
        try:
            bd = _board_for_position("position startpos moves " + " ".join(moves))
        except Exception as _be:
            print(f"[replay] 盤再構築に失敗 ({len(moves)}手目 {mv}: {_be!r}) — 中断",
                  flush=True)
            return
        wr = None
        for k in ("score_cp", "cp", "nnue_score_cp", "dl_score_cp"):
            v = r.get(k)
            if isinstance(v, (int, float)):
                wr = _cp_to_winrate(v, _SR_WR_SLOPE) * 100.0
                break
        _tstr = (time.strftime("%H:%M:%S", time.localtime(ts))
                 if isinstance(ts, (int, float)) else "")
        hdr = f"── {len(moves)}手目 {mv}" + (f"  [{_tstr}]" if _tstr else "")
        try:
            print(_sr_render_board(bd, winrate=wr, header=hdr), flush=True)
        except Exception as _re:
            print(f"[replay] 描画失敗 (継続): {_re!r}", flush=True)
    print("[replay] 終了", flush=True)



