def _is_pipe_lost_exc(exc) -> bool:
    return isinstance(exc, OSError) and (
        getattr(exc, "winerror", None) in (109, 232, 233)
        or isinstance(exc, BrokenPipeError))


def _excepthook_to_diagnosis(exc_type, exc_value, exc_tb):
    if _is_pipe_lost_exc(exc_value):
        try:
            _flog(f"[PIPE-LOST] stdio pipe closed by peer — exiting: {exc_value!r}")
        except Exception:
            pass
        return
    msg = _safe_format_exc(exc_type, exc_value, exc_tb)
    _flog("UNCAUGHT EXCEPTION — engine will exit:\n" + msg)
    try:
        print(msg, file=sys.stderr)
    except Exception:
        pass



