def _wdl_regress_endpoints_core(points, fit_offset: bool):
    pts = []
    for it in points:
        if len(it) >= 4:
            p, sl, a, w = float(it[0]), float(it[1]), float(it[2]), float(it[3])
        else:
            p, sl, a, w = float(it[0]), float(it[1]), float(it[2]), 1.0
        if w > 0.0:
            pts.append((p, sl, a, w))
    n = len(pts)
    if n == 0:
        return None
    if n == 1:
        p, sl, a, _w = pts[0]
        off = (a / p) if (fit_offset and p > 1e-9) else 0.0
        return max(1e-6, sl), max(1e-6, sl), off
    W = sum(w for _, _, _, w in pts)
    pbar = sum(w * p for p, _, _, w in pts) / W
    sbar = sum(w * sl for _, sl, _, w in pts) / W
    sxx = sum(w * (p - pbar) ** 2 for p, _, _, w in pts)
    sxy = sum(w * (p - pbar) * (sl - sbar) for p, sl, _, w in pts)
    if sxx < 1e-18:
        m, b = 0.0, sbar
    else:
        m = sxy / sxx
        b = sbar - m * pbar
    early = max(1e-6, b)
    late = max(1e-6, m + b)
    if fit_offset:
        denom = sum(w * p * p for p, _, _, w in pts)
        offset = (sum(w * p * a for p, _, a, w in pts) / denom
                  if denom > 1e-12 else 0.0)
    else:
        offset = 0.0
    return early, late, offset


def _wdl_fit_cli(args):
    kv = {}
    for a in args:
        if "=" in a:
            k, _, v = a.partition("=")
            kv[k.strip()] = v.strip()
    base = _get_base_dir()
    path = kv.get("stats") or os.path.join(base, "stats.txt")
    n_bands = max(2, int(kv.get("bands", "4")))
    game_phase_split = float(kv.get("game_phase_split", "0.5"))
    min_n = int(kv.get("min_n", "50"))
    fit_offset = str(kv.get("fit_offset", "1")).strip().lower() not in ("0", "false", "no")
    out = kv.get("out") or os.path.join(base, "wdl_fit.txt")

    _GAME_PHASE_MAX = 1.5

    def _band_index(game_phase):
        g = float(game_phase)
        if n_bands == 2:
            return (0 if g < game_phase_split else 1)
        idx = int(g / (_GAME_PHASE_MAX / n_bands))
        if idx < 0:
            idx = 0
        elif idx > n_bands - 1:
            idx = n_bands - 1
        return idx

    records, n_games, _vc = _tuner_load_records(path)
    _OUTCOME = {"win": 1.0, "lose": 0.0, "draw": 0.5, "rep_draw": 0.5,
                "sennichite": 0.5}
    _FAM = {"dl": "dl_top_score", "nnue": "nnue_score_cp"}
    _ANCHOR = {"dl": 0.0049, "nnue": 0.004}
    buckets = {}
    _prog_sum = {}
    _n_used = 0
    for rec in records:
        o = _OUTCOME.get(str(rec.get("_game_result", "")).strip().lower())
        if o is None:
            continue
        game_phase = rec.get("game_phase")
        if game_phase is None:
            continue
        bi = _band_index(game_phase)
        prog = float(game_phase)
        prog = 0.0 if prog < 0.0 else 1.0 if prog > 1.0 else prog
        _matched = False
        for fam, fld in _FAM.items():
            cp = rec.get(fld)
            if cp is None:
                continue
            buckets.setdefault((fam, bi), []).append((float(cp), o))
            _ps = _prog_sum.setdefault((fam, bi), [0.0, 0])
            _ps[0] += prog
            _ps[1] += 1
            _matched = True
        if _matched:
            _n_used += 1

    def _fit_wr(pairs, anchor):
        if len(pairs) < min_n:
            return None

        def _nll(s, a):
            t = 0.0
            for cp, o in pairs:
                z = s * (cp - a)
                if z > 60.0:
                    lp, l1 = 0.0, -z
                elif z < -60.0:
                    lp, l1 = z, 0.0
                else:
                    lp = -math.log1p(math.exp(-z))
                    l1 = -math.log1p(math.exp(z))
                t -= o * lp + (1.0 - o) * l1
            return t

        s = anchor
        a = 0.0
        cur = _nll(s, a)
        for _ in range(100):
            g_s = g_a = h_ss = h_aa = h_sa = 0.0
            for cp, o in pairs:
                z = s * (cp - a)
                if z > 60.0:
                    p = 1.0
                elif z < -60.0:
                    p = 0.0
                else:
                    p = 1.0 / (1.0 + math.exp(-z))
                r = o - p
                w = p * (1.0 - p)
                d = cp - a
                g_s += d * r
                h_ss += w * d * d
                if fit_offset:
                    g_a += (-s) * r
                    h_aa += w * s * s
                    h_sa += w * (-s) * d
            if not fit_offset:
                if h_ss < 1e-12:
                    break
                ds = g_s / (h_ss + 1e-12)
                da = 0.0
            else:
                h_ss_r = h_ss + 1e-9
                h_aa_r = h_aa + 1e-9
                det = h_ss_r * h_aa_r - h_sa * h_sa
                if abs(det) < 1e-18:
                    break
                ds = (h_aa_r * g_s - h_sa * g_a) / det
                da = (-h_sa * g_s + h_ss_r * g_a) / det
            t = 1.0
            improved = False
            for _bt in range(30):
                ns = s + t * ds
                na = a + t * da
                if ns < 1e-6:
                    ns = 1e-6
                if na > 2000.0:
                    na = 2000.0
                elif na < -2000.0:
                    na = -2000.0
                nv = _nll(ns, na)
                if nv <= cur + 1e-12:
                    s, a, cur = ns, na, nv
                    improved = True
                    break
                t *= 0.5
            if not improved:
                break
            if abs(t * ds) < 1e-10 and abs(t * da) < 1e-9:
                break
        return s, a

    def _regress_endpoints(points):
        return _wdl_regress_endpoints_core(points, fit_offset)

    print(f"[wdl fit] {path}: games={n_games} used_moves={_n_used} "
          f"bands={n_bands} min_n={min_n} fit_offset={int(fit_offset)}"
          + (f" game_phase_split={game_phase_split}" if n_bands == 2 else ""), flush=True)
    lines = []
    for fam, KEY in (("dl", "DL"), ("nnue", "NNUE")):
        pts = []
        for bi in range(n_bands):
            pairs = buckets.get((fam, bi), [])
            res = _fit_wr(pairs, _ANCHOR[fam])
            if res is None:
                print(f"  {fam:4s} band{bi}: n={len(pairs):6d} "
                      f"slope=n/a (sample不足 <{min_n})", flush=True)
                continue
            sl, a = res
            _ps = _prog_sum.get((fam, bi), [0.0, 0])
            prog = (_ps[0] / _ps[1]) if _ps[1] > 0 else 0.0
            pts.append((prog, sl, a, len(pairs)))
            print(f"  {fam:4s} band{bi}: n={len(pairs):6d} prog={prog:.3f} "
                  f"slope={round(sl, 6)} a={round(a, 1)}", flush=True)
        reg = _regress_endpoints(pts)
        if reg is None:
            print(f"  {fam:4s} → 端点回帰不能 (有効バンド 0)。", flush=True)
            continue
        early, late, offset = reg
        print(f"  {fam:4s} → Early={round(early, 6)} Late={round(late, 6)} "
              f"Offset={round(offset, 1)} (有効バンド {len(pts)})", flush=True)
        lines.append(f"Council_WR_Scale_{KEY}_Early {round(early, 6)}")
        lines.append(f"Council_WR_Scale_{KEY}_Late {round(late, 6)}")
        if fit_offset:
            lines.append(f"Council_WR_Offset_{KEY} {round(offset, 1)}")

    if lines:
        try:
            with open(out, "w", encoding="utf-8") as f:
                f.write("# [SF-WDL] wdl fit 結果 (cp→winrate の GP 依存 slope + 中心 offset)。\n")
                f.write("# setup_config.txt / config.txt に設定するか SPSA 起点に使う。\n")
                f.write("\n".join(lines) + "\n")
            print(f"[wdl fit] {len(lines)} 行を {out} へ出力。"
                  " setup_config.txt/config.txt へ反映 (または SPSA 起点に)。", flush=True)
        except OSError as e:
            print(f"[wdl fit] 出力失敗: {e}", flush=True)
    else:
        print("[wdl fit] 有効データ不足 — stats.txt に win/lose/draw 結果 + "
              "dl_top_score/nnue_score_cp/game_phase が必要。", flush=True)



_FLIP_PIECES = ["歩", "香", "桂", "銀", "金", "角", "飛", "玉",
                "と", "杏", "圭", "全", "馬", "龍"]
_FLIP_FONT_NAME = "PyfamateFlip"


def _flip_find_cjk_font():
    import glob
    cands = []
    if sys.platform.startswith("win"):
        d = os.path.join(os.environ.get("WINDIR", r"C:\Windows"), "Fonts")
        cands = [os.path.join(d, n) for n in
                 ("meiryo.ttc", "YuGothM.ttc", "YuGothR.ttc", "msgothic.ttc",
                  "BIZ-UDGothicR.ttc", "msmincho.ttc")]
    else:
        import subprocess
        r = subprocess.run(["fc-match", "-f", "%{file}", ":lang=ja"],
                           capture_output=True, text=True, timeout=5)
        if r.returncode == 0 and r.stdout.strip():
            cands.append(r.stdout.strip())
        _names = ("NotoSansCJK", "NotoSerifCJK", "NotoSansJP", "SourceHanSans",
                  "SourceHanSerif", "ipag", "ipaexg", "ipam", "ipaexm",
                  "TakaoGothic", "VL-Gothic", "DroidSansJapanese", "Hiragino")
        for base in ("/usr/share/fonts", "/usr/local/share/fonts",
                     os.path.expanduser("~/.local/share/fonts"), os.path.expanduser("~/.fonts"),
                     "/Library/Fonts", "/System/Library/Fonts"):
            if not os.path.isdir(base):
                continue
            for ext in ("ttf", "ttc", "otf"):
                for p in glob.glob(os.path.join(base, "**", "*." + ext), recursive=True):
                    if any(nm.lower() in os.path.basename(p).lower() for nm in _names):
                        cands.append(p)
    from fontTools.ttLib import TTFont
    for p in cands:
        if not os.path.exists(p):
            continue
        for idx in range(4):
            try:
                cm = TTFont(p, fontNumber=idx).getBestCmap()
            except Exception:
                break
            if all(ord(ch) in cm for ch in _FLIP_PIECES):
                return (p, idx)
    return None


def _flip_build_font(out_path, mode="plain", ks_path=None):
    import math
    from fontTools.ttLib import TTFont
    from fontTools.fontBuilder import FontBuilder
    from fontTools.pens.ttGlyphPen import TTGlyphPen
    from fontTools.pens.transformPen import TransformPen
    from fontTools.pens.recordingPen import DecomposingRecordingPen
    from fontTools.pens.boundsPen import BoundsPen
    from fontTools.misc.transform import Transform

    found = _flip_find_cjk_font()
    if not found:
        raise RuntimeError("システム CJK フォント未検出 (漢数字/な/し の反転生成に必要)")
    sysf = TTFont(found[0], fontNumber=found[1])
    sgs = sysf.getGlyphSet(); scmap = sysf.getBestCmap(); smtx = sysf["hmtx"].metrics
    upm = sysf["head"].unitsPerEm; asc = sysf["hhea"].ascent; desc = sysf["hhea"].descent
    glyphs = {".notdef": TTGlyphPen(None).glyph()}
    order = [".notdef"]; metrics = {".notdef": (upm, 0)}; charmap = {}

    def _bb(fn):
        bp = BoundsPen(None); fn(bp); return bp.bounds or (0, 0, 0, 0)

    def _emit(name, cp, gs_src, glyphname, adv, rotate, scale=1.0):
        rec = DecomposingRecordingPen(gs_src); gs_src[glyphname].draw(rec)
        base = Transform().scale(scale)
        sb = _bb(lambda p: rec.replay(TransformPen(p, base)))
        if rotate:
            cx, cy = (sb[0] + sb[2]) / 2.0, (sb[1] + sb[3]) / 2.0
            t = Transform().translate(cx, cy).rotate(math.pi).translate(-cx, -cy).scale(scale)
        else:
            t = base
        pen = TTGlyphPen(None); rec.replay(TransformPen(pen, t))
        lsb = int(_bb(lambda p: rec.replay(TransformPen(p, t)))[0])
        glyphs[name] = pen.glyph(); order.append(name)
        metrics[name] = (int(round(adv * scale)), lsb); charmap[cp] = name

    if mode == "ks":
        if not ks_path:
            raise ValueError("ks モードは ks_path (KsShogiPieces.ttf) が必要")
        ksf = TTFont(ks_path); kgs = ksf.getGlyphSet(); kcmap = ksf.getBestCmap(); kmtx = ksf["hmtx"].metrics
        ksc = upm / float(ksf["head"].unitsPerEm)
        gl = ['i', 'h', 'g', 'f', 'e', 'd', 'c', 'a', 'y', 'x', 'w', 'v', 't', 's']
        gu = ['I', 'H', 'G', 'F', 'E', 'D', 'C', 'A', 'Y', 'X', 'W', 'V', 'T', 'S']
        for i in range(14):
            if ord(gl[i]) not in kcmap:
                raise ValueError("指定フォントに K's の駒グリフが無い — 正しい KsShogiPieces.ttf を")
            gn = kcmap[ord(gl[i])]; un = kcmap[ord(gu[i])]
            _emit("g%02d" % i, 0xE000 + i, kgs, gn, kmtx[gn][0], False, ksc)
            _emit("s%02d" % i, 0xE010 + i, kgs, un, kmtx[un][0], False, ksc)
    else:
        for i, ch in enumerate(_FLIP_PIECES):
            gn = scmap[ord(ch)]; adv = smtx[gn][0]
            _emit("g%02d" % i, 0xE000 + i, sgs, gn, adv, True)
            _emit("s%02d" % i, 0xE010 + i, sgs, gn, adv, False)
    for i, ch in enumerate(_FLIP_EXTRA):
        if ord(ch) not in scmap:
            continue
        gn = scmap[ord(ch)]
        _emit("x%02d" % i, 0xE020 + i, sgs, gn, smtx[gn][0], True)

    fb = FontBuilder(upm, isTTF=True)
    fb.setupGlyphOrder(order)
    fb.setupCharacterMap(charmap)
    fb.setupGlyf(glyphs)
    fb.setupHorizontalMetrics(metrics)
    fb.setupHorizontalHeader(ascent=asc, descent=desc)
    fb.setupNameTable({"familyName": _FLIP_FONT_NAME, "styleName": "Regular"})
    fb.setupOS2(sTypoAscender=asc, sTypoDescender=desc, usWinAscent=asc, usWinDescent=-desc)
    fb.setupPost()
    fb.save(out_path)


def _flip_install_font(ttf_path):
    import shutil
    fname = os.path.basename(ttf_path)
    if sys.platform.startswith("win"):
        _la = os.environ.get("LOCALAPPDATA", "")
        if not _la:
            return ("LOCALAPPDATA 未設定 — フォント自動インストール不可。"
                    "%s を手動で Fonts に配置してください。" % ttf_path)
        dest_dir = os.path.join(_la, "Microsoft", "Windows", "Fonts")
        os.makedirs(dest_dir, exist_ok=True)
        dest = os.path.join(dest_dir, fname)
        shutil.copyfile(ttf_path, dest)
        try:
            import winreg
            k = winreg.CreateKey(winreg.HKEY_CURRENT_USER,
                                 r"SOFTWARE\Microsoft\Windows NT\CurrentVersion\Fonts")
            winreg.SetValueEx(k, "%s (TrueType)" % _FLIP_FONT_NAME, 0, winreg.REG_SZ, dest)
            winreg.CloseKey(k)
        except Exception as e:
            return "コピー済 (%s) だがレジストリ登録失敗: %s — 手動インストールを。" % (dest, e)
        return "ユーザー単位インストール済: %s (フォント名 %s)" % (dest, _FLIP_FONT_NAME)
    dest_dir = os.path.join(os.path.expanduser("~"), ".local", "share", "fonts")
    if sys.platform == "darwin":
        dest_dir = os.path.join(os.path.expanduser("~"), "Library", "Fonts")
    os.makedirs(dest_dir, exist_ok=True)
    dest = os.path.join(dest_dir, fname)
    shutil.copyfile(ttf_path, dest)
    import subprocess
    subprocess.run(["fc-cache", "-f", dest_dir], capture_output=True, timeout=30)
    if sys.platform == "darwin":
        return ("インストール済: %s — 端末のフォントを %s に手動設定してください "
                "(mac は自動適用不可)。" % (dest, _FLIP_FONT_NAME))
    return "インストール済: %s / %s" % (dest, _flip_setup_fontconfig_fallback())


_FLIP_FC_CONF_NAME = "99-pyfamate-flip.conf"


def _flip_setup_fontconfig_fallback():
    conf_dir = os.path.join(
        os.environ.get("XDG_CONFIG_HOME") or os.path.expanduser("~/.config"),
        "fontconfig", "conf.d")
    conf = os.path.join(conf_dir, _FLIP_FC_CONF_NAME)
    xml = (
        '<?xml version="1.0"?>\n'
        '<!DOCTYPE fontconfig SYSTEM "fonts.dtd">\n'
        '<!-- Pyfamate flip-font: PUA (U+E000..) 反転駒グリフのフォールバック。\n'
        '     このファイルを削除すれば完全に無効化されます。 -->\n'
        '<fontconfig>\n'
        '  <match target="pattern">\n'
        '    <edit name="family" mode="append_last" binding="weak">\n'
        '      <string>%s</string>\n'
        '    </edit>\n'
        '  </match>\n'
        '</fontconfig>\n' % _FLIP_FONT_NAME)
    try:
        if os.path.exists(conf) and open(conf, encoding="utf-8").read() == xml:
            return "fontconfig フォールバック登録済 (%s) — 端末フォント変更不要。" % conf
        os.makedirs(conf_dir, exist_ok=True)
        open(conf, "w", encoding="utf-8").write(xml)
        import subprocess
        subprocess.run(["fc-cache", "-f"], capture_output=True, timeout=30)
        return ("fontconfig フォールバック登録: %s "
                "(端末フォント変更不要・新しい端末ウィンドウから反映)。" % conf)
    except Exception as e:
        return ("fontconfig 登録失敗 (非致命): %s — 端末フォントを %s に手動設定を。"
                % (e, _FLIP_FONT_NAME))


def _flip_set_user_env_live_flip_font():
    if os.name != "nt":
        return
    import winreg
    k = winreg.OpenKey(winreg.HKEY_CURRENT_USER, "Environment", 0, winreg.KEY_SET_VALUE)
    try:
        winreg.SetValueEx(k, "LIVE_FLIP_FONT", 0, winreg.REG_SZ, "1")
    finally:
        winreg.CloseKey(k)
    import ctypes
    from ctypes import wintypes
    HWND_BROADCAST = 0xFFFF
    WM_SETTINGCHANGE = 0x001A
    SMTO_ABORTIFHUNG = 0x0002
    res = wintypes.DWORD()
    ctypes.windll.user32.SendMessageTimeoutW(
        HWND_BROADCAST, WM_SETTINGCHANGE, 0,
        ctypes.c_wchar_p("Environment"),
        SMTO_ABORTIFHUNG, 1000, ctypes.byref(res))


def _flip_register_console_face():
    if os.name != "nt":
        return
    import winreg
    for _title in ("engine.py", "engine.exe", "Pyfamate"):
        _path = r"Console\%s" % _title
        try:
            k = winreg.CreateKey(winreg.HKEY_CURRENT_USER, _path)
        except Exception:
            continue
        try:
            winreg.SetValueEx(k, "FaceName", 0, winreg.REG_SZ, _FLIP_FONT_NAME)
            winreg.SetValueEx(k, "FontFamily", 0, winreg.REG_DWORD, 54)
            winreg.SetValueEx(k, "FontWeight", 0, winreg.REG_DWORD, 400)
        finally:
            winreg.CloseKey(k)
    import ctypes
    ctypes.windll.kernel32.SetConsoleTitleW("engine.py")


def _flip_strip_jsonc(text):
    out = []
    i, n = 0, len(text)
    in_str = False
    escape = False
    while i < n:
        c = text[i]
        if in_str:
            out.append(c)
            if escape:
                escape = False
            elif c == "\\":
                escape = True
            elif c == '"':
                in_str = False
            i += 1
            continue
        if c == '"':
            in_str = True
            out.append(c)
            i += 1
            continue
        if c == "/" and i + 1 < n and text[i + 1] == "/":
            j = text.find("\n", i)
            i = n if j == -1 else j
            continue
        if c == "/" and i + 1 < n and text[i + 1] == "*":
            j = text.find("*/", i + 2)
            i = n if j == -1 else j + 2
            continue
        out.append(c)
        i += 1
    cleaned = "".join(out)
    cleaned = re.sub(r",(\s*[}\]])", r"\1", cleaned)
    return cleaned


def _flip_setup_windows_terminal(engine_dir):
    import json, re

    _preserve_comments = os.environ.get(
        "PYFAMATE_WT_PRESERVE_COMMENTS", "").strip().lower() in ("1", "true", "yes")

    la = os.environ.get("LOCALAPPDATA", "")
    cands = [os.path.join(la, r"Packages\Microsoft.WindowsTerminal_8wekyb3d8bbwe\LocalState\settings.json"),
             os.path.join(la, r"Packages\Microsoft.WindowsTerminalPreview_8wekyb3d8bbwe\LocalState\settings.json"),
             os.path.join(la, r"Microsoft\Windows Terminal\settings.json")]
    path = next((p for p in cands if os.path.exists(p)), None)
    if not path:
        path = next((p for p in cands if os.path.isdir(os.path.dirname(p))),
                     os.path.join(la, r"Microsoft\Windows Terminal\settings.json"))
        os.makedirs(os.path.dirname(path), exist_ok=True)
        _seed = {"$schema": "https://aka.ms/terminal-profiles-schema",
                 "profiles": {"defaults": {"font": {"face": _FLIP_FONT_NAME}}, "list": []}}
        open(path, "w", encoding="utf-8").write(json.dumps(_seed, ensure_ascii=False, indent=4))
        raw = open(path, encoding="utf-8").read()
        _sentinel = os.path.join(os.path.dirname(os.path.abspath(__file__)),
                                 "_fontcheck", "wt_defaults_patched")
        os.makedirs(os.path.dirname(_sentinel), exist_ok=True)
        open(_sentinel, "w", encoding="utf-8").write("done\n")
        _msgs = ["WT settings.json 新規作成 (font.face=%s): %s" % (_FLIP_FONT_NAME, path)]
    elif _preserve_comments:
        return ("WT settings.json は既存 (PYFAMATE_WT_PRESERVE_COMMENTS=1 のため"
                "コメント消失を避けて書き換えをスキップしました。手動で "
                'profiles.defaults.font.face="%s" を設定してください: %s'
                % (_FLIP_FONT_NAME, path))
    else:
        raw = open(path, encoding="utf-8-sig").read()
        _msgs = []

    _sentinel = os.path.join(os.path.dirname(os.path.abspath(__file__)),
                             "_fontcheck", "wt_defaults_patched")
    _defaults_ok = False
    if '"profiles"' in raw:
        try:
            _ck_clean = _flip_strip_jsonc(raw)
            _ck_doc = json.loads(_ck_clean)
            _ck_prof = _ck_doc.get("profiles", {})
            if isinstance(_ck_prof, dict):
                _ck_face = _ck_prof.get("defaults", {}).get("font", {}).get("face")
                _defaults_ok = (_ck_face == _FLIP_FONT_NAME)
        except Exception:
            pass
    if not _defaults_ok and ('"profiles"' in raw):
        _clean = ""
        try:
            _clean = _flip_strip_jsonc(raw)
            doc = json.loads(_clean)
            prof = doc.setdefault("profiles", {})
            if isinstance(prof, dict):
                dflt = prof.setdefault("defaults", {})
                font = dflt.setdefault("font", {})
                if font.get("face") != _FLIP_FONT_NAME:
                    font["face"] = _FLIP_FONT_NAME
                    new_text = json.dumps(doc, ensure_ascii=False, indent=4)
                    open(path + ".pyfamate.defaults.bak", "w", encoding="utf-8").write(raw)
                    open(path, "w", encoding="utf-8").write(new_text)
                    raw = new_text
                    os.makedirs(os.path.dirname(_sentinel), exist_ok=True)
                    open(_sentinel, "w", encoding="utf-8").write("done\n")
                    _msgs.append("WT profiles.defaults.font.face=%s 上書き完了 "
                                 "(backup: settings.json.pyfamate.defaults.bak)" % _FLIP_FONT_NAME)
        except json.JSONDecodeError as e:
            _ctx_lo = max(0, e.pos - 40)
            _ctx_hi = min(len(_clean), e.pos + 40)
            _flog(f"[flip-auto] WT defaults JSON parse 失敗詳細: {e} "
                  f"周辺テキスト={_clean[_ctx_lo:_ctx_hi]!r}")
            _msgs.append("WT defaults 上書き失敗 (非致命): %s" % e)
        except Exception as e:
            _msgs.append("WT defaults 上書き失敗 (非致命): %s" % e)

    if "Pyfamate (flip)" in raw:
        _msgs.append("WT プロファイル「Pyfamate (flip)」既存 (スキップ)")
    else:
        _clean2 = ""
        try:
            _clean2 = _flip_strip_jsonc(raw)
            doc2 = json.loads(_clean2)
            prof2 = doc2.setdefault("profiles", {})
            if isinstance(prof2, dict):
                lst = prof2.setdefault("list", [])
                if isinstance(lst, list):
                    prof_obj = {
                        "name": "Pyfamate (flip)",
                        "guid": "{e1d2c3b4-a5f6-4789-9abc-def012345678}",
                        "font": {"face": _FLIP_FONT_NAME},
                        "startingDirectory": engine_dir,
                        "commandline": 'powershell.exe -NoExit -Command '
                                       '"$env:LIVE_FLIP_FONT=1"',
                    }
                    lst.insert(0, prof_obj)
                    new_text = json.dumps(doc2, ensure_ascii=False, indent=4)
                    open(path + ".pyfamate.bak", "w", encoding="utf-8").write(raw)
                    open(path, "w", encoding="utf-8").write(new_text)
                    raw = new_text
                    _msgs.append("WT プロファイル「Pyfamate (flip)」追加")
                else:
                    _msgs.append("profiles.list が配列でないため追加スキップ")
            else:
                _msgs.append("profiles が想定外の型のため追加スキップ")
        except json.JSONDecodeError as e:
            _ctx_lo = max(0, e.pos - 40)
            _ctx_hi = min(len(_clean2), e.pos + 40)
            _flog(f"[flip-auto] WT プロファイル追加 JSON parse 失敗詳細: {e} "
                  f"周辺テキスト={_clean2[_ctx_lo:_ctx_hi]!r}")
            _msgs.append("WT プロファイル追加で JSON 検証失敗 (変更せず): %s" % e)
        except Exception as e:
            _msgs.append("WT プロファイル追加で JSON 検証失敗 (変更せず): %s" % e)

    return " / ".join(_msgs) if _msgs else "WT 変更なし"


def _flip_setup_cli(args):
    kv = {}; flags = set(); it = iter(args)
    for a in it:
        if a.startswith("--"):
            k = a[2:]
            if k in ("no-install", "no-terminal", "check"):
                flags.add(k)
            else:
                kv[k] = next(it, "")
    if "check" in flags:
        _sr_configure_render(force=True)
        _w = {(hex(ord(c)) if ord(c) >= 0xE000 else c): v
              for c, v in _SR_MEASURED_W.items()}
        print("[check] 実測幅: %s" % (_w or "(測定不能: 非TTY か DSR 未対応端末)"), flush=True)
        print("[check] flip=%s %s" % (_sr_flip_font_active(), _SR_PROBE_NOTE or "OK"),
              flush=True)
        print("0123456789" * 3, flush=True)
        print("".join(_sr_cell(p) for p in ("p", "l", "n", "s", "g", "b", "r", "k")),
              flush=True)
        print("".join(_sr_cell(p) for p in ("P", "L", "N", "S", "G", "B", "R", "K")),
              flush=True)
        print("▲▽■□──  ← 各行が定規と桁一致し、駒が上下反転して見えれば正常", flush=True)
        return
    mode = kv.get("mode", "plain")
    engine_dir = os.path.dirname(os.path.abspath(__file__))
    out = kv.get("out") or os.path.join(engine_dir, "_fontcheck", _FLIP_FONT_NAME + ".ttf")
    os.makedirs(os.path.dirname(out) or ".", exist_ok=True)
    try:
        import fontTools
    except ImportError:
        print("[flip] fontTools が必要です: pip install fonttools", flush=True); return
    if mode == "ks":
        ks = kv.get("ks-font", "")
        if not ks or not os.path.exists(ks):
            print("[flip] --ks-font に KsShogiPieces.ttf のパスを指定してください "
                  "(K's は再配布不可・各自入手 https://ksbookshelf.com/FD/KsShogiPieces.zip)", flush=True); return
        _flip_build_font(out, mode="ks", ks_path=ks)
        print("[flip] K's タイル版を生成: %s" % out, flush=True)
    else:
        found = _flip_find_cjk_font()
        if not found:
            print("[flip] システムの CJK フォントが見つかりません "
                  "(Noto Sans CJK / IPAGothic 等を入れてください)。", flush=True); return
        base, idx = found
        print("[flip] base CJK font: %s (index %d)" % (base, idx), flush=True)
        _flip_build_font(out, mode="plain")
        print("[flip] 素の漢字反転版を生成: %s" % out, flush=True)
    if "no-install" not in flags:
        print("[flip] " + _flip_install_font(out), flush=True)
    if sys.platform.startswith("win") and "no-terminal" not in flags:
        print("[flip] " + _flip_setup_windows_terminal(engine_dir), flush=True)
    print("[flip] 完了 (先手=正立/後手=反転)。Windows は WT/conhost へ、Linux は "
          "fontconfig フォールバックで自動適用 (新しい端末ウィンドウから)。mac のみ端末"
          "フォントを %s に手動設定。反映確認は `flip-font --check`。有効/無効は起動時の"
          "端末実測で自動判定 (LIVE_FLIP_FONT=0 で強制OFF / LIVE_FLIP_FONT_FORCE=1 で"
          "強制ON)。" % _FLIP_FONT_NAME, flush=True)


